/* RECIPES — the canonical authored recipe collection (window.RECIPES). Compact one-line
   JSON-ish records; kept dense by design. Pretty-printed files live alongside as siblings. */
window.RECIPES=[{"slug": "risotto-milanese-saffron", "t": "Risotto Milanese with Saffron", "tier": "signature", "cui": "Italian \u00b7 Lombardy", "occ": ["date"], "time": "25 min", "method": "Stovetop \u00b7 rice starch emulsion", "diff": "Medium", "blurb": "The golden rice of Milan, transformed by saffron into one of Italy's most luxurious dishes.", "prov": {"popular_in": "Milan and Lombardy region, Italy", "famous_for": "The signature saffron-infused rice dish of Milanese cuisine", "consists_of": "Rice slowly cooked in broth with saffron, finished with butter and Parmigiano-Reggiano", "name_origin": "Risotto alla Milanese dates to the 14th century; legend says it was created for a stained-glass window installation at Milan Cathedral in 1574, when a painter added saffron to the rice", "why_loved": "The allure of saffron \u2014 earthy, honeyed, metallic \u2014 turns simple rice into something opulent, each grain suspended in a creamy, daffodil-yellow sauce that gently collapses under its own weight", "method_detail": "Stovetop \u2014 rice toasted in oil, then cooked with broth infused with saffron threads, stirred to release starch for creaminess"}, "brief": {"lead": "This is risotto as the Milanese intend: not stand-and-stir for twenty minutes, but a smarter method that rinses rice with stock to capture its starch, then toasts it for nuttiness before a gentle simmer. Saffron threads \u2014 just two generous pinches \u2014 bloom in the hot broth, tinting the rice daffodil-yellow and infusing it with that singular earthy, honeyed aroma. Finished with butter and Parmigiano-Reggiano off the heat, the grains should be tender but al dente at the core, swimming in a creamy sauce that flows like lava.", "expect": [["Intense saffron aroma.", "The kitchen fills with saffron's earthy, honeyed scent as it blooms."], ["Creamy emulsion.", "Rice starch creates a velvety sauce that clings to each grain."], ["Al dente texture.", "Grains are tender with a faint bite at the center."], ["Rich finish.", "Butter and Parmigiano-Reggiano enrich the risotto into something luxurious."]], "stats": [["25", "min", "Active"], ["20", "min", "Simmer"], ["2", "", "Serves 2"], ["Tender", "", "Doneness"]], "kit": ["Heavy-based saut\u00e9 pan", "Fine-mesh strainer", "Wooden spoon", "Chef's knife"]}, "ing": [["The rice", [["linear", 400, "g", "Carnaroli or Vialone Nano rice"], ["linear", 950, "ml", "Chicken or vegetable stock"], ["linear", 45, "ml", "Extra-virgin olive oil"]]], ["Aromatics & saffron", [["countN", 1, "", "Small yellow onion, minced"], ["linear", 225, "ml", "Dry white wine"], ["taper", 2, "pinches", "Saffron threads"], ["taper", 1, "tsp", "Flaky sea salt"]]], ["The finish", [["linear", 40, "g", "Unsalted butter"], ["linear", 50, "g", "Parmigiano-Reggiano, finely grated"], ["static", "", "Extra Parmigiano-Reggiano, for serving"]]]], "tl": [["T\u221205:00", "Rinse rice", "Combine rice and stock in a bowl, agitate to release starch, then drain well, reserving the starchy stock", 300], ["T+00:00", "Toast rice", "Heat oil in a heavy 30cm saut\u00e9 pan over medium-high heat. Add drained rice and cook, stirring, until sizzling and aromatic, about 5 minutes", null], ["T+05:00", "Add aromatics", "Add onion and cook 1 minute until softened. Add wine and cook until evaporated, about 3 minutes", null], ["T+08:00", "Add saffron stock", "Stir reserved stock (reserving 240ml) and saffron into rice. Bring to simmer, cover, reduce heat to lowest setting", 30], ["T+18:00", "Simmer", "Cook undisturbed 10 minutes. Stir once, redistribute rice, cover and cook 5 more minutes until liquid absorbed and rice tender", 600], ["T+23:00", "Finish risotto", "Stir in reserved 240ml stock. Increase heat to high, add butter, stir until melted and creamy. Off heat, add cheese, stir rapidly to emulsify. Season with salt. Serve immediately", 120]], "steps": [["Rinse the rice", "Combine the rice and stock in a large bowl. Agitate vigorously with your fingers to release surface starch into the liquid. Strain through a fine-mesh strainer set over a 2-quart liquid measure, shaking the rice to drain well. Save that starchy stock \u2014 it's the foundation of your creamy sauce.", "Surface starch thickens risotto. Rinsing rice with stock captures starch that would be lost during toasting; this starch is what creates the velvety emulsion that suspends each grain.", 300], ["Toast the rice", "Heat the olive oil in a heavy 30cm saut\u00e9 pan over medium-high heat until shimmering (not smoking). Add the drained rice and cook, stirring and tossing frequently, until all liquid has evaporated and the rice sizzles and takes on a nutty aroma, about 5 minutes. The grains will look like ice cubes \u2014 cloudy in the centre, translucent at the edges.", "Toasting matters. This develops flavour and firms the exterior of each grain, preventing it from disintegrating during cooking.", null], ["Saut\u00e9 the aromatics", "Add the minced onion to the rice and continue cooking, stirring frequently, until aromatic and softened, about 1 minute. Add the white wine and cook, stirring occasionally, until the pan is nearly dry, about 3 minutes. The wine drops the pan's temperature and adds acidity.", "Wine first. Alcohol carries flavour better than water, and its acidity balances the richness of the final dish.", null], ["Add the saffron stock", "Give the reserved starchy stock a vigorous stir to redistribute any settled starch. Pour all but 240ml of the stock over the rice. Add the saffron threads and a large pinch of salt. Increase heat to high and bring to a simmer. Stir once to ensure no grains cling above the liquid. Cover the pan and reduce heat to the lowest possible setting. Keep the stock at a gentle, barely-visible simmer throughout.", "Saffron blooms in hot liquid and why cover on low heat. The heat extracts saffron's colour and flavour compounds, infusing the entire dish. Covering at the lowest setting prevents evaporation and allows the rice to cook evenly without excessive starch release.", 30], ["Simmer gently", "Cook the rice covered and undisturbed for 10 minutes. Uncover, stir once, and shake the pan gently to redistribute the rice evenly. Cover again and continue cooking until the liquid is mostly absorbed and the rice is tender with just a faint bite at the centre, about 5 minutes longer.", "Minimal stirring. Unlike traditional risotto, this method requires almost no stirring because we've already extracted the starch into the cooking liquid.", 600], ["Finish to creaminess", "Stir the remaining 240ml of stock thoroughly to redistribute any settled starch, then stir it into the rice. Increase heat to high and add the butter. Cook, stirring and shaking the pan constantly, until the butter has melted and the risotto is thick and creamy. Add more stock or water if the risotto becomes too dry. Remove from heat, add the grated Parmigiano-Reggiano, and stir rapidly to thoroughly incorporate and emulsify. Season with salt. Serve immediately on hot plates, passing extra cheese at the table.", "Finish off the heat. Adding cheese to hot rice can cause proteins to clump; off heat allows the cheese and starch to emulsify smoothly into a creamy sauce. Stir rapidly so residual heat melts the cheese evenly.", 120]], "pair": [["With the risotto", "Barolo", "Piedmont, Italy \u00b7 Nebbiolo", "The wine's firm tannins and notes of rose and tar cut through the risotto's richness, while its acidity balances the buttery finish"], ["Starter", "Buricca", "Lombardy, Italy \u00b7 cured pork belly", "Thinly sliced, its salinity and fat echo the Parmigiano and butter, setting up the richness to come"]], "image": "https://images.unsplash.com/photo-1537147127881-1c4b0e6b87e8?w=500&q=80", "imageAlt": "Risotto Milanese with saffron"}, {"slug": "thai-green-curry", "t": "Thai Green Curry", "tier": "signature", "cui": "Thai", "occ": ["solo", "date"], "time": "35 min", "method": "Stovetop \u00b7 coconut curry emulsion", "diff": "Medium", "blurb": "The most popular curry in Thailand: coconut milk spiked with green chillies, aromatic with basil and lime leaves.", "prov": {"popular_in": "Throughout Thailand, from home cooking to street food to fine dining", "famous_for": "Being the most popular curry in Thailand, served with jasmine rice, rice noodles, and even roti", "consists_of": "Chicken or other protein braised in coconut milk with green curry paste, seasoned with fish sauce and palm sugar, finished with Thai basil and makrut lime leaves", "name_origin": "Gaeng kiew waan (\u0e41\u0e01\u0e07\u0e40\u0e02\u0e35\u0e22\u0e27\u0e2b\u0e27\u0e32\u0e19) literally means 'sweet green curry' in Thai, though the dish isn't particularly sweet \u2014 the 'sweet' refers to the soft pastel green colour from fresh green chillies", "why_loved": "Green curry hits every note: creamy richness from coconut, fresh heat from green chillies, salinity from fish sauce, sweetness from palm sugar, and the bright perfume of makrut lime and Thai basil", "method_detail": "Stovetop \u2014 curry paste fried in coconut milk until oil separates, then protein added with remaining coconut milk and stock, simmered until tender, finished with Thai basil"}, "brief": {"lead": "Green curry is Thailand's most loved curry for good reason: it hits every note \u2014 creamy, spicy, salty, sweet, aromatic. The key is cooking the curry paste in a portion of coconut milk until the oil separates, a traditional technique that concentrates flavour. Chicken thighs stay tender during the simmer, while Thai aubergine absorbs the sauce. Finished with torn makrut lime leaves and fresh Thai basil, the curry should be vibrant green, fragrant, and perfectly balanced. Serve over jasmine rice for the authentic experience.", "expect": [["Vibrant green colour.", "The curry paste tints the coconut milk a soft pastel green."], ["Coconut oil separation.", "Cooking the paste until oil beads to the surface concentrates flavour."], ["Tender chicken.", "Thighs braise gently without becoming tough or dry."], ["Aromatic finish.", "Thai basil and makrut lime leaves perfume the dish at the end."]], "stats": [["35", "min", "Active"], ["15", "min", "Simmer"], ["2", "", "Serves 2"], ["Tender", "", "Doneness"]], "kit": ["Heavy-bottomed pot or wok", "Mortar and pestle (optional)", "Tongs", "Chef's knife"]}, "ing": [["The curry base", [["linear", 420, "ml", "Full-fat coconut milk, divided"], ["linear", 240, "ml", "Unsaled chicken stock"], ["linear", 50, "g", "Green curry paste (about 3\u00bd tbsp)"]]], ["The protein & veg", [["countX", 450, "g", "Boneless skinless chicken thighs, 2.5cm pieces"], ["linear", 225, "g", "Thai aubergine, quartered (or 1 \u00d7 540g can bamboo shoots)"], ["countN", 1, "\u00bc", "Red capsicum, julienned"]]], ["Seasoning & finish", [["linear", 30, "g", "Palm sugar, finely chopped"], ["linear", 30, "ml", "Fish sauce"], ["countN", 5, "", "Fresh makrut lime leaves, torn"], ["linear", 15, "g", "Fresh Thai basil leaves"], ["static", "", "Jasmine rice, for serving"]]]], "tl": [["T\u221200:00", "Prep ingredients", "Cut chicken into 2.5cm pieces. If using Thai aubergine, quarter and keep submerged in water. Julienne red capsicum. Tear makrut lime leaves", 300], ["T+00:00", "Fry curry paste", "Bring 180ml coconut milk to a full boil in a heavy pot over medium heat. Add curry paste and fry, stirring frequently, until coconut oil starts to separate, 3-5 minutes", null], ["T+05:00", "Add chicken", "Add chicken pieces and stir to coat with paste. Add remaining coconut milk, chicken stock, half the palm sugar, and half the fish sauce. Stir to combine", 60], ["T+06:00", "Simmer", "Add torn makrut lime leaves. Bring to a gentle simmer and cook for 10-15 minutes until chicken is fork-tender", 900], ["T+21:00", "Add vegetables", "Add Thai aubergine (or bamboo shoots) and red capsicum. Simmer 1 minute until aubergine can be pierced with slight resistance. Do not overcook aubergine", 60], ["T+22:00", "Finish & serve", "Turn off heat. Stir in Thai basil until just wilted. Taste and adjust with more fish sauce and palm sugar. Serve over jasmine rice", 60]], "steps": [["Prepare the ingredients", "Cut the chicken thighs into 2.5cm pieces. If using fresh Thai aubergine, quarter them and keep submerged in water to prevent browning until ready to use. If using canned bamboo shoots, drain and rinse well. Julienne the red capsicum into thin strips. Tear the makrut lime leaves into pieces, discarding the tough centre stems if desired.", "Prep matters. Having everything ready before you start is crucial \u2014 curry paste can burn quickly, and once you add the coconut milk, the process moves fast.", 300], ["Fry the curry paste", "Heat a splash of oil in a large pan over medium-high heat. Add the curry paste and toast it in the oil for 1\u20132 minutes, stirring constantly, until it becomes fragrant and deepens in color. This blooming releases the paste's essential oils and builds flavor.", "Bloom curry paste. Raw paste tastes harsh; blooming in hot oil mellows the spices, releases their aromatics, and creates a flavor foundation that deepens throughout the cook.", null], ["Add the chicken", "Add the chicken pieces to the pot and stir to coat thoroughly with the curry paste. Pour in the remaining coconut milk and chicken stock. Add half the palm sugar and half the fish sauce. Stir well to combine everything. The chicken should be submerged in the liquid. Use warm or room-temperature coconut milk; boiling coconut milk can break the emulsion and create a grainy texture.", "Temperature matters with coconut. Boiling disrupts the emulsion of fat and water in coconut milk, resulting in separation and a grainy sauce instead of creamy.", 60], ["Simmer gently", "Add the torn makrut lime leaves to the pot. Bring everything to a gentle simmer, then reduce heat to maintain a slow bubble. Cook for 10-15 minutes, stirring occasionally, until the chicken is fork-tender and cooked through. The sauce should thicken slightly as it simmers.", "Gentle simmering. A gentle bubble prevents the coconut milk from separating too much while allowing flavours to meld and the chicken to cook evenly.", 900], ["Add the vegetables", "Add the Thai aubergine quarters (or drained bamboo shoots) and julienned red capsicum. Simmer for 1 minute, stirring continuously to push the aubergine into the sauce \u2014 if left floating on top, they'll oxidise and turn brown. Cook until the aubergine can be pierced with a fork with slight resistance. Do not overcook, or they'll disintegrate. If using bamboo shoots, they just need 1 minute to heat through.", "Add veg last. Thai aubergine and capsicums cook quickly and overcooking ruins their texture. Adding them at the end preserves their structure and colour.", 60], ["Finish and serve", "Turn off the heat. Add the fresh Thai basil leaves and stir just until wilted \u2014 this should take only seconds. Taste the sauce and adjust the seasoning with more fish sauce and palm sugar as needed. Serve immediately over jasmine rice, with extra fish sauce on the table for guests to adjust to their taste.", "Finish off the heat. Thai basil wilts instantly and loses its perfume if overcooked. Adding it off the heat preserves its vibrant green colour and fresh aroma.", 60]], "pair": [["With the curry", "Jasmine rice", "Thailand \u00b7 fragrant long-grain", "The floral aroma and sticky texture perfectly complement the creamy sauce, while its mild flavour lets the curry shine"], ["Drink", "Thai iced tea", "Thailand \u00b7 Ceylon tea with condensed milk", "Sweet, creamy, and strongly spiced with star anise \u2014 it cools the palate and complements the curry's richness"]], "image": "https://images.unsplash.com/photo-1455619452474-d2be8b1e4e31?w=500&q=80", "imageAlt": "Thai green curry in bowl"}, {"slug": "carnitas-tacos", "t": "Carnitas Tacos Michoac\u00e1n", "tier": "signature", "cui": "Mexican \u00b7 Michoac\u00e1n", "occ": ["host", "date"], "time": "4.5 hrs", "method": "Confit \u00b7 lard slow-braise", "diff": "Hard", "blurb": "The authentic Michoac\u00e1n way: pork slow-cooked in lard until fork-tender, then crisped and tucked into warm corn tortillas.", "prov": {"popular_in": "Michoac\u00e1n, Mexico \u2014 recognized as the true home of carnitas", "famous_for": "Being the definitive Mexican pork slow-cooked in lard, closer to French confit than braise", "consists_of": "Various cuts of pork slowly cooked in lard with aromatics until falling-apart tender, then crisped before serving in corn tortillas with salsa and garnishes", "name_origin": "Carnitas Michoacanas \u2014 literally 'little meats' from Michoac\u00e1n, the Mexican state universally recognized as the true home of this dish", "why_loved": "Confit in lard creates incomparable texture \u2014 meltingly tender interior with crispy, browned edges. The variety of pork cuts yields different colours, flavours, and textures in every bite", "method_detail": "Confit \u2014 pork submerged in lard and cooked at 91\u00b0C until tender, then briefly fried at high heat to crisp the exterior before serving"}, "brief": {"lead": "Real carnitas \u2014 the kind from Michoac\u00e1n, birthplace of the technique \u2014 aren't braised. They're confit: pork slowly submerged in lard and cooked at 91\u00b0C until fork-tender. The lard, flavoured with orange peel, bay leaves, garlic, and onion, becomes a cooking medium rather than an ingredient. When the meat is tender, it's removed, pulled, and briefly seared in hot lard until crispy edges form. Tucked into warm corn tortillas with salsa, white onion, and coriander, this is the carnitas Mexicans know.", "expect": [["Variety of textures.", "Different cuts yield crispy skin, melting fat, and tender meat in every bite."], ["Lard confit.", "Slow-cooking in lard at 91\u00b0C yields meat that's falling-apart tender, never dry."], ["Crispy edges.", "A quick high-heat sear before serving creates browned, crunchy exterior bits."], ["Traditional garnishes.", "Corn tortillas, salsa verde, white onion, and coriander are the classic accompaniments."]], "stats": [["30", "min", "Active"], ["4", "hrs", "Confit"], ["4", "", "Serves 4"], ["Fork-tender", "", "Doneness"]], "kit": ["Heavy pot or Dutch oven", "Tongs", "Slotted spoon", "Cutting board", "Chef's knife"]}, "ing": [["The pork", [["countX", 2.3, "kg", "Mixed pork cuts (see brief): shoulder, skin, belly, ribs, hocks"], ["taper", 3, "tbsp", "Flaky sea salt"]]], ["The confit medium", [["linear", 2.8, "L", "Fresh rendered pork lard"], ["countN", 3, "", "Oranges, zest only, pith removed"], ["countN", 5, "", "Bay leaves"], ["countN", 1, "", "White onion, quartered"], ["countN", 1, "", "Head of garlic, halved horizontally"]]], ["For serving", [["countX", 12, "", "Small corn tortillas"], ["linear", 120, "ml", "Salsa verde or salsa de arbol"], ["countN", 1, "", "White onion, finely diced"], ["linear", 30, "g", "Fresh coriander leaves"]]]], "tl": [["T\u221204:30", "Prep pork", "Cut pork into large chunks, leaving bone-in pieces intact. Salt generously with flaky salt. Let sit at room temperature while lard heats", 600], ["T+00:00", "Heat lard", "Fill pot with lard and heat to 93\u00b0C. Add orange zest, bay leaves, onion, and garlic to infuse the fat", null], ["T+00:15", "Add pork gradually", "When lard reaches 93\u00b0C, add longest-cooking cuts first (hocks, feet, if using). Wait 30 minutes before adding next tier (shoulder, ribs). Continue adding cuts in order of cooking time", null], ["T+00:45", "Maintain temperature", "Keep lard at 91\u00b0C and cook gently until all pork is fork-tender, about 3-4 hours total", 14400], ["T+04:45", "Remove & pull pork", "Remove pork from lard and let cool slightly. Pull meat into large chunks, slicing across the grain. Discard bones", 900], ["T+05:00", "Crisp & serve", "Heat 240ml reserved lard in a large pan over high heat until smoking. Sear pork pieces in batches until crispy edges form, about 2-3 minutes per batch. Serve immediately in warm tortillas with garnishes", 720]], "steps": [["Cut and salt the pork", "Cut the pork into large chunks, leaving bone-in pieces intact. Different cuts cook at different rates, so keeping them large makes timing easier. Salt all the meat generously with flaky sea salt, coating every surface. Let the pork sit at room temperature while you heat the lard \u2014 this helps it cook evenly.", "Salt before confit. Salting early flavours the meat throughout and helps retain moisture during the long cook.", 600], ["Heat the lard with aromatics", "Fill your heavy pot with the lard and heat it to 93\u00b0C. Add the orange zest (with bitter white pith removed), bay leaves, quartered white onion, and halved garlic head to the fat. These aromatics will infuse the lard with subtle flavour as the pork cooks.", "Aromatics in the fat. Infusing the cooking medium distributes flavour more evenly than adding aromatics directly to the meat.", null], ["Add pork gradually", "When the lard reaches 93\u00b0C, start adding the pork. Different cuts cook at different rates, so add the longest-cooking pieces first \u2014 hocks, feet, tongue (if using) \u2014 then wait 30 minutes before adding the next tier (shoulder, ribs). Continue adding cuts in order of cooking time. Even relatively quick-cooking cuts like loin will need about 1 hour total.", "Stagger the addition. Adding cuts at different times ensures everything finishes tender at the same moment, preventing some from drying out while others cook.", null], ["Maintain gentle heat", "Maintain the lard temperature at 91\u00b0C and cook gently until all the various pork pieces are soft and tender. Normally this takes about 4 hours, but could be more with very large pieces. The pork should be falling-apart tender, offering no resistance when prodded.", "Low temperature. Cooking at 91\u00b0C \u2014 barely above simmering \u2014 slowly breaks down connective tissue without rendering all the fat, creating meltingly tender meat.", 14400], ["Remove and pull the pork", "When the meat is starting to fall off the bone, remove it from the lard and let it cool slightly. Carefully pull the meat apart with your hands or a knife, working across the grain into large chunks. Don't shred it into strings \u2014 you want identifiable pieces. Discard bones, but keep any crispy skin bits.", "Pull, don't shred. Large chunks have better texture and let guests distinguish between cuts. Shredding turns everything into a uniform mash.", 900], ["Crisp before serving", "For serving, heat about 240ml of the reserved lard in a large pan over high heat until smoking. Working in batches, add the pulled pork and sear until crispy edges form, about 2-3 minutes per batch. Remove with a slotted spoon and drain briefly. Serve immediately in warm corn tortillas with salsa verde, diced white onion, and fresh coriander.", "Crisp at the end. The quick high-heat sear creates browned, crunchy exterior bits that contrast with the meltingly tender interior.", 720]], "pair": [["With the tacos", "Salsa verde", "Mexico \u00b7 tomatillo and green chilli salsa", "Tomatillos' acidity and green chillies' heat cut through the rich pork, while the salsa's freshness balances the confit's heaviness"], ["Drink", "Negro Modelo", "Mexico \u00b7 dark lager beer", "The malt sweetness complements the pork's caramelised edges, while the beer's carbonation and slight bitterness refresh the palate between rich bites"]], "image": "https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=500&q=80", "imageAlt": "Carnitas tacos with tortillas"}, {"slug": "mussels-white-wine-garlic", "t": "Moules Marini\u00e8res", "tier": "signature", "cui": "Belgian \u00b7 French", "occ": ["date"], "time": "18 min", "method": "Steam \u00b7 shellfish rapid-cook", "diff": "Easy", "blurb": "The classic sailor-style mussels: steamed open in white wine with garlic, shallots, and butter \u2014 the taste of Brittany and Belgium.", "prov": {"popular_in": "Belgium and northern France, especially Brittany and Normandy", "famous_for": "Being the quintessential Belgian mussel dish, typically served with frites", "consists_of": "Fresh mussels steamed open in white wine with shallots, garlic, and butter, finished with parsley and served with crusty bread", "name_origin": "Moules marini\u00e8res means 'sailor-style mussels' in French, referring to the simple preparation traditionally made by sailors with their catch", "why_loved": "Moules marini\u00e8res capture the essence of the sea: sweet, briny mussels steamed in aromatic white wine, enriched with butter, and meant to be eaten with your hands and plenty of bread for dipping", "method_detail": "Steam \u2014 mussels cooked in a tightly covered pan with white wine, shallots, garlic, and butter until they open, then finished with herbs"}, "brief": {"lead": "Moules marini\u00e8res are the simplest, purest way to eat mussels: steamed open in white wine with shallots, garlic, and butter. The key is starting with live mussels \u2014 discard any that won't close when tapped. Sweat shallots and garlic in butter, add white wine, then the mussels, and cover tightly. In 5 minutes they'll steam open. Finish with more butter and chopped parsley. Serve in the cooking pot with crusty bread to mop up the aromatic juices \u2014 it's finger food at its finest.", "expect": [["Aromatic steam.", "The kitchen fills with the scent of white wine, garlic, and cooking shellfish."], ["Rapid cooking.", "Mussels steam open in just 5 minutes under high heat."], ["Briny-sweet sauce.", "The cooking liquid is intensely flavoured \u2014 wine, garlic, butter, and mussel juices."], ["Communal eating.", "Serve the mussels in the cooking pot and let guests help themselves, discarding shells as they go."]], "stats": [["18", "min", "Active"], ["5", "min", "Steam"], ["2", "", "Serves 2"], ["Open", "", "Doneness"]], "kit": ["Large pot with tight-fitting lid", "Colander", "Tongs", "Crusty bread"]}, "ing": [["The mussels", [["countX", 2, "kg", "Live mussels in the shell"]]], ["The cooking liquid", [["linear", 60, "ml", "Dry white wine"], ["linear", 30, "g", "Unsalted butter, divided"], ["countN", 2, "", "Large shallots, finely minced"], ["countN", 2, "", "Garlic cloves, finely minced"]]], ["The finish", [["countN", 20, "g", "Fresh parsley leaves, finely chopped"], ["static", "", "Crusty baguette or sourdough, for serving"]]]], "tl": [["T\u221215:00", "Clean mussels", "Scrub mussels under cold running water. Pull off any beards. Discard any with cracked shells or that won't close when tapped firmly", 600], ["T+00:00", "Sweat aromatics", "Melt 15g butter in a large pot over medium heat. Add shallots and cook, stirring, until softened and translucent but not browned, about 3 minutes. Add garlic and cook until fragrant, 1 minute", null], ["T+04:00", "Add wine & mussels", "Add white wine and bring to a simmer. Add mussels all at once and immediately cover with tight-fitting lid. Increase heat to high", 30], ["T+04:30", "Steam", "Cook mussels, covered, shaking the pot occasionally, until they have opened, 4-5 minutes. Do not overcook", 300], ["T+09:30", "Finish & serve", "Remove from heat. Add remaining 15g butter and chopped parsley. Stir until butter melts. Discard any unopened mussels. Serve immediately in the cooking pot with crusty bread", 60]], "steps": [["Clean and sort the mussels", "Scrub the mussels thoroughly under cold running water, using a stiff brush to remove any grit or barnacles from the shells. Pull off the fibrous 'beards' that protrude from the shells \u2014 give them a firm tug toward the hinge end. Discard any mussels with cracked shells. Tap any open mussels firmly on the counter \u2014 if they don't close within a minute, discard them. Keep only live mussels that close tightly.", "Check for life. Dead mussels spoil quickly and can make you sick. Live mussels close when tapped \u2014 it's their natural defence mechanism.", 600], ["Sweat the aromatics", "Melt 15g of the butter in a large pot (one with a tight-fitting lid) over medium heat. Add the minced shallots and cook, stirring occasionally, until softened and translucent but not browned, about 3 minutes. Add the minced garlic and cook until fragrant, about 1 minute.", "Soften, don't brown. Browned shallots would dominate the delicate flavour of the mussels. We want sweetness, not caramelisation.", null], ["Add wine and bring to simmer", "Pour in the white wine and bring to a simmer. Let it cook for 30 seconds to reduce slightly and cook off some of the alcohol.", "Reduce the wine. Brief simmering concentrates flavour and milder alcohol heat while preserving the wine's acidity, which balances the richness of the butter and mussels.", 30], ["Add mussels and cover", "Add all the cleaned mussels to the pot at once and immediately cover with the tight-fitting lid. Increase the heat to high. The trapped steam will quickly build pressure and cook the mussels evenly.", "Add all at once. Adding mussels in batches means some will overcook while others steam open. They should all go in together to finish at the same time.", null], ["Steam until opened", "Cook the mussels, covered, for 4-5 minutes. Shake the pot occasionally to redistribute the mussels. Check after 4 minutes \u2014 they should have opened. Do not overcook or they'll become tough and rubbery.", "Shake, don't stir. Shaking redistributes the mussels without losing the steam that builds up in the pot. Stirring would release too much heat and moisture.", 300], ["Finish and serve", "Remove the pot from the heat. Add the remaining 15g butter and the chopped parsley. Stir gently until the butter has melted and coated the mussels. Discard any mussels that haven't opened \u2014 they were dead to begin with and shouldn't be eaten. Serve immediately in the cooking pot with crusty bread for dipping in the aromatic juices.", "Finish with butter. The final butter enriches and slightly thickens the cooking liquid, creating a luxurious sauce that clings to the mussels and bread.", 60]], "pair": [["With the mussels", "Muscadet", "Loire Valley, France \u00b7 Melon de Bourgogne", "High acidity and salinity complement the briny mussels, while its lean structure won't overpower the delicate shellfish"], ["Starter", "Celery r\u00e9moulade", "France \u00b7 celery root in mustard mayonnaise", "Crunchy, sharply dressed celery root cuts through the richness of the mussels and butter, preparing the palate for the shellfish to come"]], "image": "https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=500&q=80", "imageAlt": "Moules marini\u00e8res seafood"}, {"slug": "cacio-e-pepe", "t": "Cacio e Pepe", "tier": "signature", "cui": "Italian \u00b7 Roman", "occ": ["solo", "date"], "time": "15 min", "method": "Stovetop \u00b7 cheese emulsion", "diff": "Medium", "blurb": "Rome's minimalist masterpiece: spaghetti tossed with Pecorino Romano and black pepper into a creamy emulsion.", "prov": {"popular_in": "Rome and Lazio region, Italy", "famous_for": "Being one of Rome's four classic pasta dishes, alongside carbonara, amatriciana, and gricia", "consists_of": "Spaghetti tossed with Pecorino Romano cheese and black pepper in a creamy emulsion made with pasta water", "name_origin": "Cacio e pepe literally means 'cheese and pepper' in Roman dialect, referring to the dish's two primary ingredients beyond pasta", "why_loved": "The brilliance of cacio e pepe is how two ingredients \u2014 Pecorino Romano and black pepper \u2014 transform into something luxurious: a creamy, aromatic sauce that coats each strand of spaghetti", "method_detail": "Stovetop \u2014 pepper toasted in oil, pasta cooked in minimal water, then cheese emulsified with hot pasta water to create a smooth sauce"}, "brief": {"lead": "Cacio e pepe is Rome's answer to the question: how much can you do with how little? The answer: plenty. Finely grated Pecorino Romano, toasted black pepper, and pasta water emulsify into a creamy sauce that coats each strand of spaghetti. The trick is a two-pan method: toast pepper in oil in one pan while cooking pasta in a small amount of water in another, then combine. The starch-heavy pasta water helps the cheese melt smoothly instead of clumping. The result: a silky, peppery, salty masterpiece that's greater than the sum of its parts. Work quickly; if the sauce sits, the emulsion breaks. Serve immediately.", "expect": [["Toasted pepper aroma.", "Black pepper toasted in oil becomes sweeter and more mellow, not harsh."], ["Cheese emulsion.", "Pecorino Romano and pasta water create a smooth, creamy sauce that clings to the pasta."], ["Al dente spaghetti.", "Pasta retains a firm bite while being coated in sauce."], ["Minimalist perfection.", "Only four ingredients \u2014 pasta, cheese, pepper, oil \u2014 but deeply flavoured."]], "stats": [["15", "min", "Active"], ["10", "min", "Cook pasta"], ["2", "", "Serves 2"], ["Al dente", "", "Doneness"]], "kit": ["Two skillets (one 30cm)", "Tongs", "Microplane or fine grater", "Fork"]}, "ing": [["The pasta", [["countX", 225, "g", "Spaghetti"], ["static", "", "Salt, for pasta water"]]], ["The sauce", [["linear", 45, "ml", "Extra-virgin olive oil, divided"], ["taper", 1, "tsp", "Coarsely ground black pepper, plus more for serving"], ["linear", 30, "g", "Unsalted butter"]]], ["The cheese", [["linear", 55, "g", "Pecorino Romano, very finely grated (about 250 ml), plus more for serving"]]]], "tl": [["T\u221212:00", "Toast pepper", "Heat 45ml olive oil and pepper in a medium skillet over medium-low heat until fragrant and barely starting to sizzle, about 1 minute. Set aside to cool", 60], ["T+00:00", "Cook pasta", "Place spaghetti in a large 30cm skillet and cover with water. Add a small pinch of salt. Bring to boil over high heat, prodding occasionally to prevent clumping", null], ["T+08:00", "Prepare emulsion", "When pasta is al dente (1 minute less than package), transfer 45-60ml pasta water to the cooled oil/pepper skillet. Stir in butter", 60], ["T+10:00", "Combine", "Using tongs, lift spaghetti directly from water to the oil/butter mixture. Add half the cheese and toss vigorously, adding more pasta water as needed", null], ["T+12:00", "Finish", "Add remaining cheese and remaining 15ml oil. Stir with fork until cheese completely melts and sauce is creamy. Season with salt and more pepper. Serve immediately", 180]], "steps": [["Toast the black pepper", "Heat 45ml of the olive oil and about a teaspoon of coarsely ground black pepper in a medium skillet over medium-low heat. Cook until the ingredients are fragrant and the pepper is barely starting to sizzle, about 1 minute. Remove from the heat and set aside to cool \u2014 the pan needs to be cool enough that it won't overheat the cheese when we add it later.", "Toast pepper in oil. Heat changes black pepper's flavour from harsh and sharp to sweet and mellow, while the oil carries its flavour more evenly through the dish.", 60], ["Cook the pasta", "Place the spaghetti in a large 30cm skillet and add enough water to just cover the pasta. Season with a small pinch of salt \u2014 go light here, as both the cheese and pasta cooking water will contribute salinity. Bring to a boil over high heat, prodding the spaghetti occasionally with a fork to prevent it from clumping together.", "Cook in minimal water. Using less water than traditional pasta cooking concentrates the starch in the cooking liquid, which is crucial for creating a smooth cheese emulsion.", null], ["Prepare the emulsion base", "When the spaghetti is al dente (typically about 1 minute less than the package instructions), transfer 2-3 tablespoons of the pasta cooking water to the skillet with the olive oil and pepper mixture. Stir in the butter. The mixture should be glossy and fragrant.", "Reserve pasta water. The starchy pasta water is what allows the hard Pecorino to melt into a smooth sauce rather than clumping into sticky masses.", 60], ["Combine pasta and sauce", "Using tongs, lift the spaghetti directly from the water and transfer it to the oil/butter mixture. Don't drain \u2014 the water clinging to the noodles is all the liquid we need. Add half the finely grated Pecorino Romano cheese and toss vigorously. Hold your fork almost horizontally and swirl the spaghetti around to distribute the cheese evenly. Add a few more tablespoons of pasta water if the mixture seems dry Use COLD cheese straight from the fridge; cold cheese melts smoothly into the creamy emulsion. If the sauce becomes clumpy or grainy, add a splash of pasta water and stir constantly to re-emulsify.", "Add cheese in stages. Adding cheese in two additions prevents the proteins from clumping and ensures smooth emulsification.", null], ["Finish the dish", "Add the remaining cheese and the remaining 15ml of olive oil. Stir with a fork until the cheese is completely melted and the sauce is creamy and coats each strand of spaghetti. The sauce should be loose and flowing, not clumpy. Season to taste with salt (remembering the cheese is salty) and more freshly ground black pepper. Serve immediately, passing extra grated cheese and black pepper at the table.", "Finish off the heat. Residual heat from the pasta melts the final cheese without risking overheating, which can cause cheese proteins to seize and clump.", 180]], "pair": [["With the pasta", "Frascati", "Lazio, Italy \u00b7 Malvasia di Frascati", "The wine's gentle bitterness and citrus notes complement the pepper's heat, while its crisp acidity cuts through the richness of the cheese and oil"], ["Starter", "Cicoria ripassata", "Lazio, Italy \u00b7 rebraised chicory", "Bitter greens saut\u00e9ed with garlic and chilli provide the perfect counterpoint to the rich, salty pasta, cleansing the palate between bites"]], "image": "https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=500&q=80", "imageAlt": "Cacio e pepe pasta dish"}, {"slug": "shakshuka-crusty-bread", "t": "Shakshuka with Crusty Bread", "tier": "signature", "cui": "Middle Eastern \u00b7 North African", "occ": ["solo", "date"], "time": "35 min", "method": "Braise \u00b7 egg poach in tomato sauce", "diff": "Easy", "blurb": "Eggs gently poached in a spiced tomato sauce \u2014 a North African breakfast now loved across the Middle East.", "prov": {"popular_in": "North Africa and the Middle East, especially Tunisia, Israel, and Egypt", "famous_for": "Being a popular breakfast dish across the Middle East and North Africa, often served with pita bread", "consists_of": "Eggs poached in a chunky tomato and capsicum sauce seasoned with cumin, paprika, and coriander", "name_origin": "The word shakshuka comes from Arabic for 'all mixed up' or 'shaken', referring to the dish's jumbled appearance of eggs nestled in tomato sauce", "why_loved": "Shakshuka hits every note: sweet tomatoes, fragrant spices, rich runny yolks, and the satisfaction of dipping crusty bread into the sauce", "method_detail": "Braise \u2014 tomatoes, peppers, onions, and spices simmered into a thick sauce, then eggs cracked into wells and poached until whites are set but yolks remain runny"}, "brief": {"lead": "Shakshuka is comfort food across North Africa and the Middle East: eggs poached in a thick, fragrant tomato sauce. The sauce starts with onions, green peppers, and garlic softened in olive oil, then seasoned with cumin, paprika, coriander, and a pinch of red pepper flakes. Fresh tomatoes (or canned in winter) simmer into a chunky sauce. You make wells in the sauce, crack in the eggs, cover, and cook until the whites are set but yolks remain gloriously runny. Serve with plenty of crusty bread for dipping \u2014 runny yolks and spicy tomato-soked bread are the whole point.", "expect": [["Chunky tomato sauce.", "Fresh tomatoes break down into a thick, flavourful base punctuated with soft peppers."], ["Aromatic spices.", "Cumin, paprika, and coriander bloom in the oil, perfuming the entire dish."], ["Runny yolks.", "Eggs are poached to perfection \u2014 whites set, yolks liquid and rich."], ["Dipping bread.", "Crusty bread or pita is essential for soaking up the spiced tomato sauce and runny yolks."]], "stats": [["25", "min", "Active"], ["20", "min", "Simmer"], ["2", "", "Serves 2"], ["Runny yolks", "", "Doneness"]], "kit": ["Large cast iron skillet or heavy pan with lid", "Wooden spoon", "Ladle"]}, "ing": [["The base", [["linear", 45, "ml", "Extra-virgin olive oil"], ["countN", 1, "", "Large yellow onion, chopped"], ["countN", 2, "", "Green capsicums, chopped"], ["countN", 2, "", "Garlic cloves, minced"]]], ["The spices", [["taper", 1, "tsp", "Ground coriander"], ["taper", 1, "tsp", "Sweet paprika"], ["taper", 0.5, "tsp", "Ground cumin"], ["taper", 0.25, "tsp", "Red pepper flakes"]]], ["The tomatoes & eggs", [["countN", 6, "", "Medium tomatoes, chopped (about 900g)"], ["linear", 120, "ml", "Tomato sauce"], ["countX", 6, "", "Large eggs"], ["taper", 1, "tsp", "Flaky sea salt", "plus more"]]], ["The finish", [["linear", 15, "g", "Fresh parsley leaves, chopped"], ["linear", 15, "g", "Fresh mint leaves, chopped"], ["static", "", "Crusty bread or pita, for serving"]]]], "tl": [["T\u221225:00", "Prep ingredients", "Chop onions, peppers, garlic, and tomatoes. Have spices measured. Crack eggs into individual bowls if you're nervous about them", 300], ["T+00:00", "Cook sofrito", "Heat olive oil in a large cast iron skillet. Add onions, peppers, garlic, spices, and salt. Cook, stirring, until vegetables have softened, about 5 minutes", 300], ["T+05:00", "Add tomatoes", "Add chopped tomatoes and tomato sauce. Cover and simmer for about 15 minutes, then uncover and cook until sauce has thickened. Taste and adjust seasoning", 900], ["T+20:00", "Make wells & add eggs", "Using the back of a spoon, make 6 indentations in the tomato mixture. Gently crack an egg into each well", 60], ["T+21:00", "Poach eggs", "Reduce heat to low, cover skillet, and cook until egg whites are set but yolks are still runny, about 5-8 minutes", 480], ["T+29:00", "Garnish & serve", "Uncover and add fresh parsley and mint. Add more salt or red pepper flakes if desired. Serve immediately directly from the skillet with crusty bread", 60]], "steps": [["Prepare the ingredients", "Chop the onions, green peppers, garlic, and tomatoes. If you're using fresh tomatoes, they should be soft and almost overripe for best results. Measure out your spices and set them near the stove. If you're nervous about cracking eggs directly into the hot sauce, crack each one into a small bowl first \u2014 this makes it easier to add them to the wells without breaking yolks.", "Prep matters. Once you start cooking the sauce, everything happens quickly. Having everything ready prevents scrambling around while your sofrito burns.", 300], ["Cook the sofrito", "Heat the olive oil in a large cast iron skillet (or any heavy pan with a lid) over medium heat. Add the chopped onions, green peppers, minced garlic, ground coriander, sweet paprika, ground cumin, red pepper flakes, and a teaspoon of flaky sea salt. Cook, stirring occasionally, until the vegetables have softened and are fragrant, about 5 minutes.", "Build flavour base. This sofrito of vegetables and spices forms the aromatic foundation of the dish. Cooking them together allows their flavours to meld and develop.", 300], ["Add the tomatoes and simmer", "Add the chopped fresh tomatoes and tomato sauce to the skillet. Stir well to combine everything. Cover the skillet and let it simmer for about 15 minutes, then uncover and continue cooking for a few more minutes until the mixture has reduced and thickened into a chunky sauce. Taste and adjust the seasoning to your liking \u2014 you may want more salt or a pinch more red pepper flakes.", "Simmer covered first. Covering initially allows the vegetables to steam and break down evenly. Uncovering later reduces the liquid and concentrates flavours.", 900], ["Create wells for the eggs", "Using the back of a wooden spoon, make 6 indentations, or 'wells,' in the tomato mixture. Space them out evenly so each egg has room. Gently crack an egg into each indentation, being careful not to break the yolks. If you pre-cracked the eggs into bowls, gently slide them from the bowls into the wells.", "Make wells first. Creating wells before adding the eggs helps contain them and prevents them from spreading too thinly across the sauce.", 60], ["Poach the eggs", "Reduce the heat to low, cover the skillet, and cook until the egg whites are completely set but the yolks are still runny, about 5-8 minutes. The steam trapped in the covered skillet gently cooks the eggs from above while the sauce heats them from below.", "Cover to poach. Covering traps steam and ensures even cooking. The whites should be opaque and set, but when you jiggle the pan, the yolks should still wobble liquidly.", 480], ["Garnish and serve", "Uncover the skillet and add the fresh chopped parsley and mint. The residual heat will slightly wilt the herbs, releasing their aroma. You can add more flaky sea salt or red pepper flakes if you like. Serve immediately in the skillet with warm pita, challah, or crusty bread for dipping into the sauce and runny yolks.", "Add herbs at the end. Fresh herbs lose their vibrant flavour and colour if cooked. Adding them raw preserves their freshness and adds a bright note to the rich sauce.", 60]], "pair": [["With shakshuka", "Israeli salad", "Israel \u00b7 chopped cucumber and tomato salad", "The salad's crisp vegetables and bright lemon-dressing cut through the rich eggs and spicy sauce, refreshing the palate"], ["Drink", "Mint tea", "Morocco \u00b7 green tea with fresh mint", "Sweet, minty tea cools the palate and complements the dish's Middle Eastern and North African origins, while sugar balances the spice heat"]], "image": "https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=500&q=80", "imageAlt": "Shakshuka with bread"}, {"slug": "molten-chocolate-fondant", "t": "Molten Chocolate Fondant", "tier": "signature", "cui": "French", "occ": ["date"], "time": "30 min", "method": "Bake \u00b7 individual chocolate cakes", "diff": "Medium", "blurb": "The ultimate dinner party dessert: individual chocolate cakes with molten centres, ready in 12 minutes from the oven.", "prov": {"popular_in": "France and fine dining restaurants worldwide", "famous_for": "Being a showstopping dinner party dessert with a surprise molten centre", "consists_of": "Individual chocolate cakes baked until just set, with a molten, gooey centre that flows when cut", "name_origin": "Known as fondant au chocolat in French, this dessert became popular in French restaurants in the 1990s and has since become a dinner party classic", "why_loved": "The contrast between the slightly set exterior and the molten, flowing centre creates drama and delight \u2014 it's chocolate in two textures at once", "method_detail": "Bake \u2014 chocolate and butter melted, then mixed with eggs, sugar, and flour, baked at 200\u00b0C for 10-12 minutes until edges are set but centre remains molten"}, "brief": {"lead": "Molten chocolate fondant is the dessert that makes dinner guests gasp: individual chocolate cakes with a secret. The batter \u2014 melted chocolate and butter whisked with eggs, sugar, and flour \u2014 bakes at 200\u00b0C for just 10-12 minutes. The edges set into a tender cake, but the centre stays molten. When you cut into it, warm chocolate flows onto the plate. The key is precise timing \u2014 underbake and they're too liquid, overbake and they're brownies. Get it right and you've got the ultimate chocolate dessert.", "expect": [["Glossy dark batter.", "Melted chocolate and butter create a smooth, glossy base."], ["Rapid bake.", "200\u00b0C heat sets the edges quickly while preserving the molten centre."], ["Dramatic presentation.", "Cutting into the cake releases warm molten chocolate onto the plate."], ["Temperature contrast.", "Serve warm from the oven with vanilla ice cream for hot-cold contrast."]], "stats": [["20", "min", "Active"], ["12", "min", "Bake"], ["4", "", "Serves 4"], ["Molten centre", "", "Doneness"]], "kit": ["6 \u00d7 150ml ramekins or dariole moulds", "Mixing bowls", "Whisk", "Saucepan"]}, "ing": [["For the moulds", [["linear", 50, "g", "Butter, melted, for brushing"], ["static", "", "Cocoa powder, for dusting"]]], ["The cake", [["linear", 200, "g", "Good-quality dark chocolate (70%), chopped"], ["linear", 200, "g", "Butter, chopped"], ["linear", 200, "g", "Golden caster sugar"], ["countN", 4, "", "Large eggs"], ["countN", 4, "", "Large egg yolks"], ["linear", 200, "g", "Plain flour"]]], ["To serve", [["static", "", "Caramel sauce (optional)"], ["static", "", "Vanilla ice cream or orange sorbet"]]]], "tl": [["T\u221230:00", "Prepare moulds", "Brush 4 ramekins with melted butter using upward strokes. Chill in fridge 10 minutes. Brush again with butter, then dust with cocoa powder, tapping out excess", 600], ["T\u221220:00", "Melt chocolate & butter", "Place chocolate and butter in a bowl over a pan of barely simmering water. Stir until melted and smooth. Leave to cool about 10 minutes", null], ["T\u221210:00", "Whisk eggs & sugar", "In a separate bowl, whisk eggs and yolks with sugar until thick, pale, and whisk leaves a trail (use electric whisk if desired)", 300], ["T\u221205:00", "Combine batter", "Sift flour into egg mixture, beat together. Pour melted chocolate into egg mixture in thirds, beating well between each addition until completely combined", 300], ["T+00:00", "Fill & chill", "Pour batter into prepared ramekins. Chill at least 20 minutes or up to overnight (can be frozen at this point for up to 1 month)", 1200], ["T+12:00", "Bake", "Heat oven to 200\u00b0C fan. Place ramekins on baking tray. Bake 10-12 minutes until tops have formed a crust and starting to come away from sides. Let sit 1 minute before turning out", 720]], "steps": [["Prepare the moulds", "First get your moulds ready. Using upward strokes, heavily brush melted butter all over the inside of the pudding moulds. Place the moulds in the fridge or freezer to chill the butter. Brush more melted butter over the chilled butter, then add a good spoonful of cocoa powder into each mould. Tip the mould so the powder completely coats the butter. Tap any excess cocoa back into the jar, then repeat with the next mould.", "Double-coat the moulds. The double layer of butter and cocoa ensures the fondants release easily while maintaining a clean shape. The cocoa powder adds a subtle chocolate crust.", 600], ["Melt chocolate and butter", "Place a bowl over a pan of barely simmering water, then slowly melt 200g good-quality dark chocolate and 200g butter, both chopped into small pieces, together. Remove the bowl from the heat and stir until smooth. Leave to cool for about 10 minutes.", "Melt gently. Using a double boiler prevents the chocolate from seizing or scorching, which can happen if melted over direct heat. Cooling slightly prevents the eggs from cooking when we combine them.", null], ["Whisk eggs and sugar", "In a separate bowl whisk 4 eggs and 4 egg yolks together with 200g golden caster sugar until thick and pale and the whisk leaves a trail; use an electric whisk if you want. The mixture should nearly double in volume and become ribbon-like.", "Whisk until thick. This aerates the eggs and sugar, creating structure that will support the cake while allowing the centre to stay molten.", 300], ["Combine flour and chocolate", "Sift 200g plain flour into the eggs, then beat together. Pour the melted chocolate into the egg mixture in thirds, beating well between each addition, until all the chocolate is added and the mixture is completely combined to a loose cake batter.", "Add chocolate in stages. Adding the warm chocolate gradually prevents it from cooking the eggs, which would cause the batter to seize and lose its aeration.", 300], ["Fill and chill the moulds", "Tip the fondant batter into a jug, then evenly divide between the moulds. The fondants can now be frozen for up to a month and cooked from frozen. Chill for at least 20 minutes or up to the night before. To bake from frozen, simply carry on as stated, adding 5 minutes more to the cooking time.", "Chill before baking. Chilling the batter allows it to set slightly, which helps the fondants hold their shape during baking and creates a more defined molten centre.", 1200], ["Bake to perfection", "Heat oven to 200\u00b0C fan. Place the fondants on a baking tray, then cook for 10-12 minutes until the tops have formed a crust and they are starting to come away from the sides of their moulds. Remove from the oven, then leave to sit for 1 minute before turning out.", "Look for the signs. The crust forming and edges pulling away indicate the outside is set while the centre remains molten. That 1-minute rest allows the centre to set slightly so it doesn't flow out immediately when unmoulded.", 720]], "pair": [["With the fondant", "Sauternes", "Bordeaux, France \u00b7 Semillon", "The wine's honeyed sweetness and apricot notes complement the dark chocolate, while its acidity cuts through the richness"], ["Accompaniment", "Cr\u00e8me fra\u00eeche", "France \u00b7 cultured cream", "Tangy, cool cr\u00e8me fra\u00eeche balances the molten chocolate's sweetness and richness, while its creamy texture echoes the fondant's interior"]], "image": "https://images.unsplash.com/photo-1578985545062-69928b1d9587?w=500&q=80", "imageAlt": "Molten chocolate dessert"}, {"slug": "smash-burgers-special-sauce", "t": "Smash Burgers with Special Sauce", "tier": "signature", "cui": "American", "occ": ["solo", "date"], "time": "20 min", "method": "Griddle \u00b7 Maillard crust maximisation", "diff": "Medium", "blurb": "The burger technique that changed everything: thin patties smashed onto a screaming-hot griddle for maximum crispy crust.", "prov": {"popular_in": "Across the United States, popularised by Shake Shack and copied nationwide", "famous_for": "Creating burgers with double the crispy crust through the smashing technique", "consists_of": "Thin beef patties smashed onto a hot griddle to maximise crust, stacked with cheese and served on toasted buns with special sauce", "name_origin": "Smash burgers get their name from the technique of smashing balls of beef onto a hot griddle, popularised by Shake Shack in the early 2000s", "why_loved": "The Maillard reaction \u2014 browning \u2014 creates incomparably flavoured crispy edges. Double thin patties mean double the crust, while a centre layer of cheese keeps things moist", "method_detail": "Griddle \u2014 beef balls smashed onto hot unoiled surface, seasoned, scraped and flipped, cheese added and stacked, all in under 1 minute"}, "brief": {"lead": "Smash burgers changed the burger game by maximising the Maillard reaction \u2014 the browning that creates flavour. Form 110g beef into two balls. Heat a stainless steel pan until smoking. Add the balls and smash them hard with a spatula, creating ultra-thin patties with maximum surface contact. Season generously. After 45 seconds, scrape up the patties, flip, add cheese to one, stack the other on top. Build on a toasted bun: special sauce, shredded lettuce, sliced onions, pickles. The result: maximum crispy crust, juicy interior, gooey cheese centre. It's burger perfection.", "expect": [["Screaming-hot pan.", "Preheating for 2 minutes creates the intense heat needed for rapid crust formation."], ["Violent smash.", "Pressing beef balls flat creates maximum surface contact for browning."], ["Scraped crust.", "A stiff spatula lifts every bit of browned flavour from the pan."], ["Fast cooking.", "From hitting the pan to the bun: under 60 seconds."]], "stats": [["15", "min", "Active"], ["1", "min", "Cook per burger"], ["2", "", "Serves 2"], ["Medium", "", "Doneness"]], "kit": ["Stainless steel or cast iron skillet", "Stiff metal spatula", "Bench scraper", "Tongs"]}, "ing": [["The burgers", [["countX", 220, "g", "Freshly beef mince chuck (80/20 fat ratio), divided into 2 \u00d7 55g balls"], ["taper", 1, "tsp", "Flaky sea salt, plus more"], ["taper", 1, "tsp", "Freshly ground black pepper"]]], ["The cheese", [["countX", 2, "", "Slices good melting cheese (American or cheddar)"]]], ["The buns & sauce", [["countX", 2, "", "Soft hamburger rolls, buttered and toasted"], ["linear", 45, "ml", "Special sauce (mayo-ketchup-mustard mix)"]]], ["Toppings", [["countN", 4, "", "Pickle slices"], ["countN", 4, "", "Thin onion slices"], ["linear", 30, "g", "Shredded lettuce"]]]], "tl": [["T\u221205:00", "Prep", "Form beef into 55g balls. Toast buns in butter. Prepare toppings. Have sauce ready. Everything must be prepped before cooking begins", 300], ["T+00:00", "Preheat pan", "Heat a large stainless steel skillet over high heat for 2 minutes until smoking hot. No oil \u2014 you want the meat to stick", null], ["T+02:00", "Smash & season", "Place beef balls in pan. Smash down hard with stiff spatula, using a second spatula to apply pressure. Season generously with salt and pepper", 30], ["T+02:30", "Develop crust", "Cook until patties are well browned and tops are turning pale pink/gray, about 45 seconds", 45], ["T+03:15", "Scrape, flip, cheese, stack", "Using bench scraper or spatula, carefully scrape patties from pan. Flip immediately. Place cheese slice on one patty, stack second on top. Remove from pan", 15], ["T+03:30", "Assemble & serve", "Place stacked patties on toasted bun with sauce, lettuce, onion, pickles. Serve immediately", 30]], "steps": [["Prepare everything in advance", "Form the beef mince into 55g balls \u2014 working the meat gently to help it bind. Toast the hamburger buns in butter until golden. Prepare your toppings: shred the lettuce, slice the onions, arrange the pickles. Make the special sauce by mixing mayonnaise, ketchup, and mustard. Have everything ready at your station before you heat the pan.", "Mise en place matters. Smash burgers cook in under a minute. You won't have time to prep toppings while the patties cook. Everything must be ready to assemble the moment the patties come off the heat.", 300], ["Preheat the pan", "Preheat a large stainless steel saut\u00e9 pan or skillet over high heat for 2 minutes. Do not add oil \u2014 you want the surface to be dry and unoiled. The pan should be smoking hot, reaching 316-371\u00b0C (315-370\u00b0C).", "Cook on dry, unoiled surface. You want the meat to stick to the pan so maximum contact points develop browned crust. Oil would prevent this crucial contact.", null], ["Smash the patties", "Place the balls of beef in the hot pan and immediately smash them down hard with a stiff metal spatula, using a second spatula to apply downward pressure. Smash the balls until they're thin discs, slightly wider than your burger buns.", "Smash for maximum crust. Pressing the meat flat increases surface contact with the hot pan, which maximises the Maillard reaction \u2014 the chemical reaction that creates browned flavour.", 30], ["Season and develop crust", "Season the patties generously with salt and freshly ground black pepper. Allow them to cook undisturbed until they're well browned and the tops are beginning to turn pale pink or gray in spots, about 45 seconds. Do not try to move them or flip them early \u2014 they need that full 45 seconds to develop a proper crust.", "Don't move the patties. The meat needs continuous contact with the hot surface to develop maximum browning. Moving them interrupts the Maillard reaction.", 45], ["Scrape, flip, cheese, stack", "Using a bench scraper or the back of a stiff metal spatula, carefully scrape the patties from the pan, making sure to get all the browned bits \u2014 they're pure flavour. Flip the patties immediately and place a slice of cheese on one patty. Stack the second patty directly on top of the cheese. Remove from the pan.", "Scrape, don't flip. Scraping lifts every bit of browned crust from the pan. Flipping would leave those flavourful bits behind. The centre layer of cheese melts from both sides, keeping the patties moist.", 15], ["Assemble and serve", "Place the stacked patties on the toasted bun bottom. Add special sauce, shredded lettuce, sliced onions, and pickles. Crown with the bun top. Serve immediately. Smash burgers are best eaten hot, while the cheese is still molten and the crust is still crisp.", "Assemble and eat immediately. These burgers cook so quickly that they're meant to be eaten immediately. The contrast between hot crispy crust, warm melted cheese, and cool fresh toppings is fleeting \u2014 enjoy it now.", 30]], "pair": [["With the burgers", "Craft IPA", "California \u00b7 American IPA", "The beer's bitterness and citrus notes complement the beef's richness, while its carbonation cuts through the cheese and sauce"], ["Side", "Onion rings", "American \u00b7 beer-battered fried onion rings", "Crispy, salty onion rings add crunch and sweetness that balance the burger's savoury flavours, while the fried preparation echoes the crispy burger edges"]], "image": "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=500&q=80", "imageAlt": "Smash burger with sauce"}, {"slug": "beef-rendang", "t": "Beef Rendang", "tier": "premium", "cui": "Indonesian \u00b7 Minang", "occ": ["date", "host"], "time": "4 hr", "method": "Stovetop \u00b7 slow braise", "diff": "Hard", "blurb": "Rich, caramelised beef slow-cooked in coconut milk until the sauce intensifies into a dark, fragrant coating.", "prov": {"popular_in": "West Sumatra, Indonesia; Padang restaurants worldwide", "famous_for": "CNN's World's Best Foods #1 (2011, 2017); culinary icon of Minangkabau cuisine", "consists_of": "Beef braised in spiced coconut milk until liquid evaporates and spices caramelize into dark coating", "name_origin": "Minangkabau language; 'rendang' refers to the slow-cooking process", "why_loved": "Deep complexity from slow reduction; tender beef with intense coconut-spice caramelisation", "method_detail": "Stovetop \u2014 constant stirring over low heat until coconut milk reduces and caramelises"}, "brief": {"lead": "Beef rendang is Indonesia's most celebrated dish \u2014 tender chunks of beef slow-braised in coconut milk with aromatics until the sauce reduces to a dark, caramelised coating. The dish evolves through distinct stages: gulai (soupy curry), kalio (thick curry), and finally dry rendang where the liquid has nearly evaporated and the meat turns rich brown.", "expect": [["Tender beef coated in dark caramelised spice paste.", "The long reduction creates impossibly tender meat with concentrated flavour."], ["Coconut milk reduction intensifies flavours.", "Four hours of gentle cooking transforms the liquid into a rich, fragrant coating."], ["Aromatic spice base with galangal, lemongrass, and makrut lime.", "Traditional Minang aromatics provide the distinctive Indonesian flavour profile."], ["Served with steamed rice.", "The intense, rich flavour needs plain rice to balance it."]], "stats": [["240", "min", "Active"], ["0", "min", "Passive"], ["4", "", "Serves"], ["160\u00b0", "", "Temp"]], "kit": ["Large heavy-based pan or wok", "Blender or food processor", "Wooden spoon", "Sharp knife"]}, "ing": [["Marinade & Spice Base", [["linear", 1000, "g", "beef top round or topside, cut into 4 cm pieces"], ["linear", 250, "g", "large red chillies, chopped"], ["countX", 10, "", "shallots, peeled"], ["countX", 5, "", "garlic cloves, peeled"], ["linear", 4, "cm", "fresh galangal, peeled"], ["linear", 4, "cm", "fresh ginger, peeled"], ["taper", 1, "tsp", "tamarind paste"], ["linear", 1.5, "L", "fresh thick coconut milk"], ["countN", 2, "", "lemongrass stalks, bruised and knotted"], ["countN", 4, "", "makrut lime leaves"], ["countN", 2, "", "fresh turmeric leaves (optional)"], ["taper", "", "to taste", "flaky sea salt"]]]], "tl": [["T+00:00", "Prepare ingredients", "Blend spice paste, assemble cooking components", 0], ["T+00:20", "Start initial braise", "Combine beef with spice paste and coconut milk, bring to boil", 1200], ["T+02:00", "Continue slow reduction", "Maintain gentle simmer, stir frequently until liquid reduces", 5400], ["T+03:30", "Final caramelisation", "Continue stirring as mixture darkens and coating forms", 1800], ["T+04:00", "Rest & serve", "Allow flavours to settle before serving over steamed rice", 600]], "steps": [["Prepare the spice paste", "Blend chillies, shallots, garlic, galangal, and ginger into a smooth paste. Bruise lemongrass stalks and knot them. Set aside.", "Creating a smooth aromatic paste ensures even flavour distribution and proper caramelisation during cooking.", 900], ["Start the braising process", "In a large non-stick pan, combine beef pieces with the spice paste. Add tamarind, salt, lemongrass, makrut lime leaves, and turmeric leaves if using. Pour in the coconut milk and mix everything together.", "Combining all components at the start allows the beef to absorb flavours as the coconut milk slowly reduces.", 600], ["Initial simmer", "Stir constantly over medium heat until the mixture comes to a boil. Reduce heat to low and continue cooking, maintaining gentle simmer.", "Constant stirring during the first hour prevents sticking and ensures even cooking of the beef.", 3600], ["Slow reduction phase", "Continue cooking over low heat, stirring occasionally. The coconut milk will gradually reduce, and the sauce will thicken and darken.", "This lengthy reduction phase is where the complex flavours develop and intensify.", 7200], ["Final caramelisation", "Increase stirring frequency as the liquid evaporates. Continue until the beef is tender and coated in a moist, dark brown paste.", "The final stage creates the signature rendang coating \u2014 caramelised spices clinging to tender beef.", 1800], ["Rest and serve", "Remove from heat and allow to rest for 10 minutes. Transfer to a serving dish and serve with steamed rice.", "Resting allows flavours to settle and the coating to set slightly for better texture.", 600]], "pair": [["With the dish", "Steamed jasmine rice", "Indonesia \u00b7 plain white", "Neutral rice balances the intense, rich flavours of rendang"], ["Aperitif", "Teh botol", "Indonesian sweet jasmine tea", "Sweet tea provides refreshing contrast to the rich, spiced beef"]], "image": "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=500&q=80", "imageAlt": "Beef rendang curry"}, {"slug": "bobotie", "t": "Bobotie", "tier": "premium", "cui": "South African \u00b7 Cape Malay", "occ": ["host", "date"], "time": "1 hr 45 min", "method": "Oven \u00b7 bake", "diff": "Medium", "blurb": "Spiced beef mince baked with a golden egg custard topping \u2014 South Africa's national dish with Cape Malay heritage.", "prov": {"popular_in": "South Africa, especially Cape Town; national dish", "famous_for": "South Africa's national dish; Cape Malay culinary heritage", "consists_of": "Curried spiced beef mince baked with egg custard and bay leaves until golden", "name_origin": "Derived from Indonesian 'bobotok'; brought by Cape Malay slaves in 17th century", "why_loved": "Perfect balance of sweet and savoury; gentle spices with comforting textures", "method_detail": "Oven bake \u2014 spiced mince topped with egg custard, baked until golden brown"}, "brief": {"lead": "Bobotie is South Africa's most famous traditional dish \u2014 gently spiced beef mince baked with a golden egg custard topping. The flavour profile balances mild curry spices with fruit sweetness, while the custard adds a silky texture that permeates the meat. Traditionally served with geelrys (yellow rice), this Cape Malay classic represents the beautiful fusion of European and Indonesian influences in South African cuisine.", "expect": [["Golden-topped spiced beef with fluffy custard.", "The baked custard creates a silky layer that complements the spiced meat."], ["Balanced sweet and savoury flavours.", "Apricot chutney and raisins provide gentle sweetness against mild curry spices."], ["Tender mince with aromatic depth.", "Slow-cooked onions and ginger-garlic base create rich foundation."], ["Served with yellow rice.", "Turmeric-stained rice is the traditional accompaniment."]], "stats": [["75", "min", "Active"], ["35", "min", "Passive"], ["4", "", "Serves"], ["180\u00b0", "", "Temp"]], "kit": ["Large frying pan", "Ceramic baking dish", "Whisk", "Sharp knife"]}, "ing": [["Spiced Mince Base", [["linear", 750, "g", "beef mince, 15-20% fat"], ["linear", 250, "g", "onion, finely chopped"], ["linear", 30, "g", "garlic-ginger paste"], ["linear", 50, "g", "butter"], ["countN", 2, "tbsp", "sultanas, soaked"], ["countN", 2, "tbsp", "raisins, soaked"], ["linear", 150, "g", "apricot chutney"], ["linear", 50, "ml", "Worcestershire sauce"], ["linear", 50, "g", "tomato paste"], ["linear", 30, "g", "brown sugar"], ["linear", 12, "g", "ground ginger"], ["linear", 12, "g", "mild curry powder (Madras style)"], ["linear", 2, "g", "turmeric powder"], ["taper", 8, "g", "flaky sea salt"]]], ["Egg Custard Topping", [["linear", 350, "ml", "whole milk"], ["countX", 2, "", "large eggs"], ["countN", 4, "", "bay leaves (optional decoration)"]]], ["Yellow Rice (Sides)", [["linear", 200, "g", "basmati rice"], ["linear", 300, "ml", "water"], ["taper", 4, "g", "flaky sea salt"], ["linear", 25, "g", "butter"], ["linear", 1, "g", "turmeric powder"]]]], "tl": [["T+00:00", "Prep & brown mince", "Soak raisins, chop onions, brown mince in batches", 900], ["T+00:15", "Build flavour base", "Fry aromatics, add spices, incorporate chutney and mince", 900], ["T+00:30", "Assemble & bake", "Transfer to dish, top with custard, bake at 180\u00b0C", 2100], ["T+01:05", "Cook yellow rice", "Prepare and cook turmeric rice while bobotie bakes", 1200], ["T+01:35", "Rest & serve", "Allow bobotie to settle, serve with yellow rice", 600]], "steps": [["Prepare and brown the mince", "Soak raisins and sultanas in warm water. Finely chop onions. Heat a large pan on high and fry mince in batches until well browned. Drain through a sieve to remove excess fat.", "Browning in batches prevents the mince from stewing in its own juices, ensuring better texture and flavour.", 900], ["Build the flavour base", "In the same pan, fry onions with garlic-ginger paste in butter over medium-low heat until softened. Add curry powder, turmeric, and soaked raisins. Cook briefly to combine, then add tomato paste and chutney. Cook for 1 minute until tomato paste loses rawness.", "Cooking the tomato paste removes its raw taste and creates depth; gentle heat prevents onions from caramelising and becoming too sweet.", 600], ["Combine and season", "Add ginger powder, browned mince, salt, and Worcestershire sauce. Mix well and cook on low heat for 5 minutes until everything comes together. Adjust seasoning if needed.", "The final gentle cook allows flavours to meld and the mince to absorb the aromatic base.", 600], ["Prepare for baking", "Preheat oven to 180\u00b0C. Transfer bobotie mix to a ceramic baking dish, spreading evenly without pressing down too firmly. Whisk together eggs and milk until combined. Pour over the meat mixture. Decorate with bay leaves if desired (brush with water to prevent burning).", "Not pressing the mince allows the custard to penetrate through the meat rather than sitting on top.", 600], ["Bake the bobotie", "Place the dish in an oven tray filled with boiling water to create a bain-marie (optional but recommended). Bake for 35-40 minutes until the custard is set and golden brown.", "The bain-marie prevents edges from overcooking while the gentle heat sets the custard evenly.", 2400], ["Make yellow rice", "While bobotie bakes, wash rice until water runs clear. Combine rice, water, salt, butter, and turmeric in a pot. Bring to boil, cover tightly, reduce to minimum heat, and cook for 15 minutes. Remove from heat and rest covered for 3 minutes.", "The resting period allows rice to finish steaming through evenly for perfect texture.", 1200], ["Rest and serve", "Remove bobotie from oven and let rest for 5-10 minutes. Serve with yellow rice and additional sides like creamed spinach or mashed potatoes.", "Resting allows the custard to set slightly for cleaner serving and better texture.", 600]], "pair": [["With the dish", "Yellow rice (geelrys)", "South Africa \u00b7 turmeric-stained", "Traditional accompaniment with buttery turmeric flavour"], ["Aperitif", "Chenin Blanc", "South Africa \u00b7 Stellenbosch", "Crisp white wine with good acidity balances the sweet-spiced mince"]], "image": "https://images.unsplash.com/photo-1593617957657-1f45e0d32e4d?w=500&q=80", "imageAlt": "Bobotie South African dish"}, {"slug": "beef-bourguignon", "t": "Beef Bourguignon", "tier": "premium", "cui": "French \u00b7 Burgundy", "occ": ["host", "date"], "time": "3 hr 15 min", "method": "Oven \u00b7 slow braise", "diff": "Hard", "blurb": "Tender beef braised slowly in Burgundy wine with pearl onions, mushrooms, and bacon \u2014 French comfort at its finest.", "prov": {"popular_in": "Burgundy region, France; worldwide French classic", "famous_for": "Iconic French beef stew; culinary school staple; Julia Child favourite", "consists_of": "Beef chuck braised in red wine with bacon, pearl onions, mushrooms, and herbs", "name_origin": "Bourguignon means 'from Burgundy'; wine is essential to the dish", "why_loved": "Deep red wine flavour with impossibly tender beef and silky vegetables", "method_detail": "Oven braise \u2014 seared beef slow-cooked in wine until falling-apart tender"}, "brief": {"lead": "Beef bourguignon is France's most celebrated beef stew \u2014 chunks of beef chuck slow-braised in full-bodied red wine with bacon, pearl onions, mushrooms, and herbs. The lengthy cooking time transforms tough beef into impossibly tender meat, while the wine reduces into a velvety sauce. This is the dish that defined French country cooking and remains the ultimate expression of Burgundy's culinary heritage.", "expect": [["Meltingly tender beef in rich wine sauce.", "Hours of gentle braising break down connective tissue into silk."], ["Deep red wine flavour with savoury depth.", "A full bottle of Burgundy wine reduces into a velvety, complex sauce."], ["Bacon, pearl onions, and mushrooms throughout.", "Classic garnishes add sweetness and earthiness to the dish."], ["Served with crusty bread or potatoes.", "The rich sauce needs something to soak it up."]], "stats": [["90", "min", "Active"], ["120", "min", "Passive"], ["4", "", "Serves"], ["175\u00b0", "", "Temp"]], "kit": ["Dutch oven or heavy oven-safe pot", "Large skillet", "Sharp knife", "Cutting board"]}, "ing": [["Meat & Base", [["countX", 1, "", "large yellow onion, diced"], ["countX", 1, "", "medium carrot, cut into 1cm rounds"], ["countX", 3, "", "garlic cloves, minced"], ["linear", 225, "g", "thick-cut bacon, cut into 1cm pieces"], ["linear", 1360, "g", "boneless beef chuck roast (approx. 1.4kg), cut into 5cm cubes"], ["taper", 2, "tsp", "flaky sea salt, divided"], ["taper", 0.75, "tsp", "black pepper, divided"], ["linear", 15, "ml", "tomato paste"], ["linear", 45, "ml", "all-purpose flour"]]]], "tl": [["T+00:00", "Prep & sear bacon", "Render bacon fat, prepare vegetables and beef", 1200], ["T+00:20", "Sear beef", "Brown beef in bacon fat, set aside with bacon", 900], ["T+00:35", "Build flavour base", "Cook vegetables, tomato paste, and wine", 900], ["T+00:50", "Start oven braise", "Combine everything, cover and transfer to oven", 7200], ["T+02:30", "Add final vegetables", "Sear pearl onions and mushrooms, add to pot", 1800], ["T+03:00", "Final cook & rest", "Finish cooking, season, and rest before serving", 900]], "steps": [["Prepare and render bacon", "Preheat oven to 175\u00b0C. Dice onion, cut carrot into rounds, mince garlic. Cut bacon into 1cm pieces. Place in Dutch oven over medium heat and cook, stirring occasionally, until fat is rendered and bacon is crisp (10-12 minutes).", "Rendering bacon slowly provides the fat needed for searing the beef and adds smoky depth to the dish.", 900], ["Sear the beef", "While bacon renders, trim excess fat from beef chuck and cut into 5cm cubes. Pat dry and season with 2 teaspoons salt and \u00bd teaspoon pepper. Remove bacon with slotted spoon and set aside. Add half the beef to pot in a single layer. Cook until browned on all sides (2-3 minutes per side). Transfer to bowl with bacon. Repeat with remaining beef.", "Searing in batches prevents overcrowding, ensuring proper browning for flavour development.", 900], ["Build the flavour base", "Add onion and carrot to pot. Cook, stirring occasionally, until onion is softened (about 3 minutes). Add garlic and cook until fragrant (30 seconds). Add tomato paste and stir to coat vegetables. Cook until darkened (1-2 minutes). Sprinkle with flour and stir to coat. Cook for 1 minute to remove floury taste.", "Cooking tomato paste concentrates its flavour and creates depth; flour provides gentle thickening for the sauce.", 600], ["Deglaze and assemble", "Add entire bottle of dry red wine to pot. Scrape up browned bits from bottom. Add beef broth, thyme sprigs, bay leaves, and remaining \u00bd teaspoon salt. Return beef, bacon, and any juices to pot. Increase heat to medium-high and bring to simmer.", "Wine deglazes the pot, incorporating all the flavourful browned bits into the sauce.", 600], ["Oven braise", "Cover pot and transfer to oven. Cook until beef is very tender (about 2 hours). About 30 minutes before beef is ready, trim and peel pearl onions if needed, and quarter mushrooms.", "The gentle, even heat of the oven breaks down connective tissue without risk of burning.", 7200], ["Prepare and add vegetables", "Melt butter in large skillet over medium heat. Add pearl onions, mushrooms, remaining \u00bd teaspoon salt, and remaining \u00bc teaspoon pepper. Cook, stirring occasionally, until tender and lightly browned (12-15 minutes). Add to pot and stir to combine. Remove and discard bay leaves and thyme stems.", "Searing vegetables separately ensures they're properly cooked and coloured before joining the stew.", 1800], ["Final seasoning and service", "Taste and adjust seasoning with more salt and pepper as needed. Remove from oven and let rest for 5-10 minutes. Garnish with chopped fresh parsley if desired. Serve with crusty bread, boiled potatoes, or over mashed potatoes.", "Resting allows flavours to settle and the sauce to thicken slightly for better texture.", 600]], "pair": [["With the dish", "Crusty baguette", "France \u00b7 traditional", "To soak up the rich, wine-infused sauce"], ["With the dish", "Pinot Noir", "Burgundy \u00b7 red wine", "Same wine variety used in cooking creates perfect harmony"]], "image": "https://images.unsplash.com/photo-1599599810694-b308ca884f3d?w=500&q=80", "imageAlt": "Beef bourguignon in wine"}, {"slug": "peking-duck", "t": "Peking Duck", "tier": "premium", "cui": "Chinese \u00b7 Beijing", "occ": ["host", "date"], "time": "25 hr", "method": "Oven \u00b7 roast", "diff": "Hard", "blurb": "Crispy-skinned roast duck served with thin pancakes, spring onions, and hoisin sauce \u2014 Beijing's imperial masterpiece.", "prov": {"popular_in": "Beijing, China; Chinese restaurants worldwide", "famous_for": "Imperial Chinese dish; crispy skin prized above all; UNESCO intangible heritage", "consists_of": "Whole duck air-dried then roasted until skin is paper-thin and crisp", "name_origin": "Peking (old name for Beijing); imperial court dish dating to Ming Dynasty", "why_loved": "Extraordinarily crispy skin contrasted with juicy, succulent meat", "method_detail": "Oven roast \u2014 air-dried duck roasted at high heat then low heat for crispy skin"}, "brief": {"lead": "Peking duck is Beijing's most celebrated dish \u2014 a whole duck air-dried for 24 hours, then roasted until the skin becomes impossibly crisp and thin. The duck is carved tableside and served with delicate pancakes, fresh spring onions, cucumber, and sweet bean sauce. Each diner assembles their own wraps, balancing the rich duck with refreshing vegetables. This is imperial Chinese dining at its finest.", "expect": [["Paper-thin, impossibly crispy skin.", "The lengthy air-drying process allows the skin to crisp dramatically during roasting."], ["Juicy, succulent meat underneath.", "Protected by the skin, the meat stays moist while roasting."], ["Interactive assembly with pancakes and vegetables.", "Each person creates their own perfect balance of duck, vegetables, and sauce."], ["Sweet-savoury flavour profile.", "Hoisin or sweet bean sauce provides traditional Chinese sweetness."]], "stats": [["30", "min", "Active"], ["1440", "min", "Passive"], ["4", "", "Serves"], ["180\u00b0", "", "Temp"]], "kit": ["Sharp knife", "Kitchen shears", "Roasting rack", "Baking tray", "Brush"]}, "ing": [["Duck Preparation", [["countX", 1, "", "whole duck (approx. 2kg), cleaned and lean"], ["linear", 5, "ml", "white vinegar"], ["linear", 30, "ml", "oyster sauce"], ["linear", 15, "ml", "Chinese cooking wine"], ["linear", 5, "g", "Chinese five-spice powder"], ["linear", 30, "ml", "maltose or honey"], ["linear", 30, "ml", "hot water"], ["linear", 2.5, "ml", "white vinegar"]]]], "tl": [["T-24:00", "Air dry duck (Day Before)", "Soak, hang, and begin air-drying process with maltose glaze", 900], ["T+00:00", "Continue drying", "Hang duck for at least 24 hours (up to 5 days in winter)", 86400], ["T+24:00", "Roast duck", "Initial roast at 180\u00b0C, then finish at 120\u00b0C", 3900], ["T+24:65", "Crisp skin (Optional)", "Final high-heat crisping or hot oil treatment", 600], ["T+24:75", "Rest & carve", "Rest duck, carve into thin slices", 600], ["T+24:85", "Assemble & serve", "Warm pancakes, prepare vegetables, assemble wraps", 900]], "steps": [["Prepare the duck for air-drying", "Choose a lean, clean duck around 2kg. Soak in water with 1 teaspoon white vinegar for 1 hour. Using kitchen twine, tie the duck from the neck for hanging. In a small bowl, mix oyster sauce, Chinese cooking wine, and five-spice powder. Spread the mixture evenly on the inside of the duck.", "The vinegar soak removes any gamey flavour; the internal seasoning adds depth to the meat.", 900], ["Glaze for drying", "In another small bowl, mix maltose (or honey) with hot water and \u00bd teaspoon white vinegar. The liquid should be warm for the first brushing. Brush the mixture evenly over the duck skin. Wait 30 minutes, then brush again. Hang the duck in a cool, well-ventilated area for at least 24 hours (up to 5 days in winter).", "The maltose glaze promotes crisping; air-drying removes moisture from the skin for better texture.", 86400], ["Prepare for roasting", "Preheat oven to 180\u00b0C. Seal the bottom of the duck by tucking the neck skin under or securing with toothpicks. Place duck on a roasting rack set over a lined baking tray to catch drips.", "Sealing the bottom prevents juices from escaping during roasting, keeping the meat moist.", 600], ["Initial roast", "Place duck in oven and roast for 20 minutes. Carefully turn duck over and roast other side for 15 minutes.", "The initial high heat begins the crisping process and renders some of the fat.", 2100], ["Slow-roast for tenderness", "Reduce oven temperature to 120\u00b0C. Continue roasting for 30 minutes (extend by 10 minutes for each additional 500g of duck weight).", "The lower, gentler heat cooks the meat through without drying it out while continuing fat rendering.", 1800], ["Crisp the skin (choose one method)", "Option 1: Heat oil until very hot. Holding duck by the neck, carefully pour hot oil over the skin. Option 2: Increase oven temperature back to 180\u00b0C and roast for 6-10 minutes, watching carefully to prevent burning.", "The final high heat creates the signature paper-thin crispy skin characteristic of Peking duck.", 600], ["Rest and carve", "Remove duck from oven and rest for several minutes. Carve by first cutting around the breast, then dividing in half. Slice breast meat thinly with skin attached. Shred remaining meat from bones.", "Resting allows juices to redistribute; slicing thinly creates the traditional presentation.", 600], ["Prepare and serve", "Make or warm Peking duck pancakes. Cut cucumber into thin strips. Slice spring onions into similar strips. Mix sweet bean sauce (2 tablespoons) with sesame oil (1 tablespoon). To assemble: brush sauce on pancake, add duck slices, cucumber strips, and spring onion strips. Roll up and enjoy.", "The fresh vegetables provide crunch and contrast to the rich, crispy duck.", 900]], "pair": [["With the dish", "Peking duck pancakes", "China \u00b7 wheat wrappers", "Traditional vehicle for duck, vegetables, and sauce"], ["Aperitif", "Tsingtao Beer", "China \u00b7 lager", "Light lager balances the rich duck and refreshes between bites"]], "image": "https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?w=500&q=80", "imageAlt": "Peking duck Chinese"}, {"slug": "slow-roast-lamb-kleftiko", "t": "Slow Roast Lamb Kleftiko", "tier": "premium", "cui": "Greek \u00b7 Islands", "occ": ["host"], "time": "16 hr 30 min", "method": "Oven \u00b7 slow roast", "diff": "Hard", "blurb": "Leg of lamb slow-roasted in parchment with garlic, lemon, and herbs until falling-off-the-bone tender.", "prov": {popular_in:'Greece and the Greek islands — the dish named for thieves, cooked in paper, eaten in celebration',famous_for:'The lamb sealed in parchment with garlic, lemon, oregano and potato, slow-roasted until the meat falls from the bone and the paper holds a pocket of fragrant steam',consists_of:'Lamb (shoulder or leg), rubbed with garlic, oregano, lemon, olive oil and flaky salt, sealed in parchment parcels with potato and onion, slow-roasted at low heat for 3-4 hours until spoon-tender',name_origin:'Kleftiko — \'of the klephts\', the mountain guerrillas who stole sheep and slow-cooked them in sealed pits to hide the smoke. The parchment wrap echoes the original sealed-in-the-ground method',why_loved:'Falls apart at the touch of a fork, the garlic and lemon soaked deep into the meat, and opening the parcel at the table releases a cloud of oregano and lamb fat that is its own appetiser',method_detail:'Oven — seal each portion in parchment (or foil) with the aromatics and potato; roast at 150°C for 3-4 hours; rest in the parcel 10 minutes; serve still wrapped so each diner opens their own'}, "brief": {"lead": "Lamb kleftiko is Greece's most celebrated lamb dish \u2014 a whole leg of lamb slow-roasted in a sealed parchment parcel with potatoes, olives, cheese, and aromatics until the meat falls from the bone. The parchment creates a self-braising environment where the lamb cooks in its own aromatic juices. The name means 'stolen meat,' referring to Greek rebels who would secretly cook stolen lamb in underground pits to avoid detection during Ottoman occupation.", "expect": [["Falling-off-the-bone tender lamb.", "Four hours at low temperature in parchment creates extraordinary tenderness."], ["Aromatic potatoes with olives and cheese.", "Vegetables cook in the lamb's juices, absorbing incredible flavour."], ["Lemon, garlic, and cinnamon perfume.", "The traditional Greek marinade creates bright, aromatic depth."], ["Impressive presentation at table.", "Opening the parchment parcel releases a cloud of aromatic steam."]], "stats": [["45", "min", "Active"], ["960", "min", "Passive"], ["4", "", "Serves"], ["160\u00b0", "", "Temp"]], "kit": ["Large roasting pan", "Parchment paper", "Sharp knife", "Food processor"]}, "ing": [["Marinade", [["countX", 1, "", "leg of lamb, bone-in (approx. 2kg)"], ["countX", 6, "", "garlic cloves"], ["taper", 0.5, "tsp", "ground cinnamon"], ["linear", 45, "ml", "extra virgin olive oil, divided"], ["countX", 3, "tbsp", "fresh herb leaves (oregano, rosemary, or thyme)"], ["countX", 1, "", "lemon, zested and juiced"], ["taper", "", "to taste", "flaky sea salt"], ["taper", "", "to taste", "black pepper"]]], ["Parcel Ingredients", [["linear", 900, "g", "Yukon Gold potatoes, cut into chunks"], ["linear", 250, "g", "cherry tomatoes"], ["linear", 225, "g", "kefalotiri cheese, cut into 2cm cubes"], ["linear", 250, "ml", "Greek olives, pitted"], ["linear", 15, "ml", "extra virgin olive oil"], ["countX", 5, "", "fresh herb sprigs (rosemary, oregano, thyme)"], ["countX", 1, "", "lemon, juiced"], ["taper", 1, "tsp", "dried oregano"]]]], "tl": [["T-24:00", "Marinate lamb (Day Before)", "Prepare marinade, score and coat lamb, refrigerate overnight", 43200], ["T+00:00", "Prepare parchment parcel", "Cut vegetables, arrange in parchment with lamb", 900], ["T+00:15", "Seal and slow-roast", "Fold parchment, roast at 160\u00b0C for 3.5 hours", 12600], ["T+03:30", "Open and finish", "Open parchment, roast 30 minutes more for colour", 1800], ["T+04:00", "Rest and carve", "Rest 30 minutes, carve and serve", 1800]], "steps": [["Prepare the marinade", "In a food processor, pulse garlic cloves, 1 teaspoon sea salt, fresh herbs, lemon zest, lemon juice, cinnamon, black pepper, and 2-3 tablespoons olive oil until combined into a paste.", "Creating a marinade paste ensures even coverage and better penetration into the meat.", 600], ["Marinate the lamb", "Using a sharp knife, create many small holes all over the lamb. Rub the marinade paste over the lamb, pushing it into the holes. Transfer to a large pan or ziplock bag. Marinate overnight or at least 3-4 hours.", "Scoring allows the marinade to penetrate deep into the meat for maximum flavour.", 43200], ["Prepare the parchment parcel", "Preheat oven to 160\u00b0C. Cut potatoes into chunks. Arrange two long pieces of parchment paper in a large roasting pan in a cross pattern. Place lamb in the center. Surround with potatoes. Add tomatoes, cheese, and olives. Tuck fresh herb sprigs around. Drizzle with lemon juice, remaining olive oil, dried oregano, salt, and pepper.", "The parchment cross ensures enough paper to completely seal the parcel for proper braising.", 900], ["Seal and begin roasting", "Fold parchment paper over lamb and ingredients. Tuck edges tightly to seal completely. Roast for 3.5 hours.", "A tight seal creates a self-braising environment where the lamb cooks in its own aromatic juices.", 12600], ["Open and finish", "Carefully open the parchment parcel. Return to oven for 30 minutes to brown the lamb and caramelize the vegetables.", "Opening the parchment allows the exterior to brown while the interior remains moist.", 1800], ["Rest and serve", "Remove from oven and let rest for 30 minutes. Transfer to a serving platter with vegetables. Serve warm.", "Resting allows juices to redistribute for more tender, juicy meat.", 1800]], "pair": [["With the dish", "Greek village salad", "Greece \u00b7 horiatiki", "Crisp, acidic salad balances the rich, slow-roasted lamb"], ["With the dish", "Agiorgitiko", "Greece \u00b7 Nemea red wine", "Medium-bodied Greek red with dark fruit complements lamb"]], "image": "https://images.unsplash.com/photo-1599043513300-2f1b3d81e53d?w=500&q=80", "imageAlt": "Slow roast lamb Mediterranean"}, {"slug": "grilled-crayfish-garlic-butter", "t": "Grilled Crayfish with Garlic Butter", "tier": "premium", "cui": "South African \u00b7 Coastal", "occ": ["date", "host"], "time": "40 min", "method": "Braai \u00b7 grill", "diff": "Medium", "blurb": "Fresh crayfish grilled over coals with garlicky butter baste \u2014 South Africa's luxury braai centerpiece.", "prov": {popular_in:'South African West Coast and the coastal braai — the dish that turns a catch into an occasion',famous_for:'The whole crayfish split lengthways, grilled shell-down over coals while garlic butter melts and bastes the tail meat — sweet, smoky, lavish',consists_of:'A whole crayfish (West Coast rock lobster), split in half lengthways, basted with garlic, lemon and melted butter, grilled shell-down over moderate coals until the meat just turns opaque',name_origin:'Crayfish — South African for rock lobster (Jasus lalandii); the West Coast is famous for them. Grilled, not boiled, is the braai way — and the only way that adds smoke',why_loved:'Sweet, rich meat with a smoky char and garlic butter running into the shell — the kind of plate that justifies the price and the effort. Bread to mop is mandatory',method_detail:'Open flame — split the crayfish alive (humane ice first), grill shell-down over moderate coals, baste with garlic butter, cook only until the tail meat is just opaque — overcook it and it turns rubbery'}, "brief": {"lead": "Grilled crayfish with garlic butter is South Africa's ultimate braai luxury \u2014 fresh crayfish lightly boiled, then grilled over hot coals while being basted with garlicky butter. The crayfish's sweet, delicate meat needs nothing more than simple preparation, making it perfect for the braai. The smoke from the butter dripping onto the coals infuses the crayfish with subtle flavour that defines authentic South African coastal cooking.", "expect": [["Sweet, succulent crayfish meat.", "Fresh crayfish has naturally sweet, delicate flesh that needs minimal enhancement."], ["Smoky aroma from coals.", "Butter dripping onto coals creates fragrant smoke that flavours the crayfish."], ["Garlic and chilli butter baste.", "Simple, aromatic butter enhances without overwhelming the delicate seafood."], ["Hands-on, social eating.", "Eating crayfish with your fingers is part of the experience."]], "stats": [["25", "min", "Active"], ["15", "min", "Passive"], ["2", "", "Serves"], ["200\u00b0", "", "Temp"]], "kit": ["Large pot", "Sharp kitchen shears", "Braai grid", "Small saucepan", "Brush"]}, "ing": [["Crayfish", [["countX", 2, "", "whole crayfish (approx. 500g each)"], ["taper", "", "to taste", "flaky sea salt"]]], ["Garlic Butter Baste", [["linear", 100, "g", "butter, melted"], ["countX", 6, "", "garlic cloves, minced"], ["taper", 1, "tsp", "chilli flakes"], ["taper", "", "to taste", "black pepper"]]]], "tl": [["T+00:00", "Boil crayfish", "Bring water to boil, add crayfish, steam for 15 minutes", 900], ["T+00:15", "Cool and prepare", "Ice bath, halve crayfish, remove veins, rinse", 600], ["T+00:25", "Prepare baste & fire", "Melt garlic butter, prepare coals", 600], ["T+00:35", "Grill over coals", "Place crayfish shell-side down, baste with garlic butter", 300], ["T+00:40", "Turn and finish", "Flip meat-side down briefly, finish cooking", 600]], "steps": [["Prepare and boil crayfish", "Break off feelers from crayfish. Add 2-3cm boiling water and pinch of salt to large pot. Add crayfish, cover, and steam on high heat for approximately 15 minutes until bright red.", "Steaming in minimal water preserves the sweet flavour and prevents waterlogging.", 900], ["Cool and prepare", "Transfer cooked crayfish to cold water to stop cooking. Using sharp kitchen shears, cut crayfish in half lengthwise. Remove and discard the digestive tract (vein). Rinse interior clean.", "Removing the vein prevents any bitterness and ensures clean, sweet flavour.", 600], ["Prepare garlic butter baste", "In a small saucepan over medium heat, melt butter with minced garlic, chilli flakes, and black pepper. Simmer for 2-3 minutes, then reduce to low heat for at least 10 minutes to infuse flavours.", "Simmering garlic removes its raw harshness and mellows the flavour.", 600], ["Prepare the braai", "Prepare nice hot coals for the braai. The fire should be medium-hot \u2014 you want steady heat, not flames.", "Steady, even coals provide consistent cooking without scorching the delicate meat.", 300], ["Grill shell-side down", "Place crayfish halves on braai grid, shell side down. Generously baste with garlic butter mixture. Cook until just warmed through and beginning to brown, basting frequently.", "Shell-side down protects the delicate meat while the shell helps retain the butter baste.", 600], ["Turn and finish", "Turn crayfish over, meat side down, for approximately 30 seconds. The butter will drip onto coals, creating smoke that flavours the crayfish.", "The brief meat-side down cooking adds smoky flavour while keeping the meat moist.", 300], ["Serve immediately", "Serve hot with mayonnaise and lemon wedges. Eat with fingers \u2014 this is hands-on dining.", "Crayfish is best enjoyed immediately while still hot and the butter is fresh.", 0]], "pair": [["With the dish", "Lemon wedges & mayonnaise", "South Africa \u00b7 classic", "Acidic lemon and creamy mayonnaise balance the rich butter"], ["With the dish", "Sauvignon Blanc", "South Africa \u00b7 coastal", "Crisp white wine with good acidity complements sweet crayfish"]], "image": "https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=500&q=80", "imageAlt": "Grilled seafood crayfish"}, {"slug": "osso-buco-gremolata", "t": "Osso Buco with Gremolata", "tier": "premium", "cui": "Italian \u00b7 Milanese", "occ": ["host", "date"], "time": "2 hr 30 min", "method": "Stovetop \u00b7 braise", "diff": "Hard", "blurb": "Veal shanks slowly braised in white wine until falling-off-the-bone, finished with bright gremolata.", "prov": {"popular_in": "Milan, Italy; Northern Italy; Italian restaurants worldwide", "famous_for": "Milan's signature dish; traditionally served with risotto alla milanese", "consists_of": "Cross-cut veal shanks braised in white wine with vegetables, finished with gremolata", "name_origin": "Italian for 'bone with a hole'; refers to the marrow bone visible in the cross-section", "why_loved": "Uniquely tender veal with rich marrow, brightened by fresh gremolata", "method_detail": "Stovetop braise \u2014 veal shanks slowly cooked in wine and broth until tender"}, "brief": {"lead": "Osso buco is Milan's most celebrated dish \u2014 cross-cut veal shanks slowly braised in white wine and broth with vegetables until the meat falls from the bone. The marrow in the centre of each shank melts into the sauce, creating incredible richness. The dish is finished with gremolata \u2014 a bright mixture of lemon zest, parsley, and garlic sprinkled over just before serving. This classic of Lombard cuisine represents elegant comfort food at its finest.", "expect": [["Falling-off-the-bone tender veal.", "Slow braising breaks down connective tissue into meltingly tender meat."], ["Rich, marrow-infused sauce.", "The marrow from the bones melts into the cooking liquid for extraordinary depth."], ["Bright gremolata finish.", "Fresh lemon, parsley, and garlic cut through the richness."], ["Served with risotto or polenta.", "Creamy Italian starches are the traditional accompaniment."]], "stats": [["60", "min", "Active"], ["90", "min", "Passive"], ["4", "", "Serves"], ["170\u00b0", "", "Temp"]], "kit": ["Dutch oven or heavy pan", "Sharp knife", "Cutting board", "Microplane or zester"]}, "ing": [["Osso Buco", [["countX", 4, "", "veal shanks (approx. 300g each, 4cm thick)"], ["countX", 0.5, "", "medium white onion, finely chopped"], ["countX", 1, "", "medium carrot, finely chopped"], ["countX", 1, "", "medium celery stalk, finely chopped"], ["linear", 60, "g", "butter, divided"], ["linear", 15, "ml", "all-purpose flour"], ["linear", 475, "ml", "dry white wine"], ["linear", 240, "ml", "beef broth"], ["taper", "", "to taste", "flaky sea salt"], ["taper", "", "to taste", "black pepper"]]], ["Gremolata", [["countX", 0.5, "", "garlic clove, minced"], ["linear", 15, "g", "fresh parsley, chopped"], ["countX", 1, "", "small lemon, zested (yellow part only)"]]]], "tl": [["T+00:00", "Prep & brown vegetables", "Finely chop mirepoix vegetables, brown in butter", 1200], ["T+00:20", "Sear veal shanks", "Lightly flour and brown veal in same pan", 900], ["T+00:35", "Deglaze & assemble", "Add wine, reduce, then add broth and cover", 900], ["T+00:50", "Slow braise", "Simmer gently for 1.5 hours until very tender", 5400], ["T+02:20", "Make gremolata & finish", "Prepare gremolata, sprinkle over, serve immediately", 600]], "steps": [["Prepare and brown vegetables", "Finely chop onion, carrot, and celery (mirepoix). In a Dutch oven or heavy pan, melt \u00bc stick butter over medium heat. Add vegetables and brown until lightly coloured (about 10 minutes). Remove vegetables and set aside.", "Browning vegetables develops sweetness and depth that forms the flavour foundation of the dish.", 900], ["Prepare and sear veal shanks", "Lightly flour veal shanks and season with salt. Return pan to medium-high heat. Add veal shanks and brown on both sides (2-3 minutes per side). Take care not to burn the vegetables remaining in pan.", "Flour helps with browning and provides gentle thickening for the sauce.", 900], ["Add wine and reduce", "Add white wine to pan. Let it evaporate for 7-8 minutes until reduced by about half. Add pepper and beef broth.", "Reducing wine concentrates its flavour and removes alcohol for sweeter, more aromatic sauce.", 600], ["Braise until tender", "Lower heat, cover pan, and cook for about 1.5 hours. Turn meat occasionally. If necessary, add more broth to keep meat moist. Cook until veal is tender enough to fall off the bone.", "Gentle braising breaks down collagen and connective tissue into gelatin for melting texture.", 5400], ["Make gremolata", "While veal braises, combine minced garlic, chopped parsley, and grated lemon zest (yellow part only). Mix well with mortar and pestle or press with spoon to release oils.", "The mortar releases essential oils from garlic and lemon for brighter flavour.", 300], ["Finish and serve", "When meat is finished cooking, ensure gremolata is well mixed. Sprinkle over cooked veal. Let meat and gremolata blend for one more minute. Serve warm, traditionally with risotto alla milanese.", "The brief blending allows gremolata to release oils without losing its bright, fresh character.", 600]], "pair": [["With the dish", "Risotto alla milanese", "Italy \u00b7 saffron rice", "Traditional accompaniment; creamy rice balances the rich veal"], ["With the dish", "Barolo", "Italy \u00b7 Piedmont red wine", "Powerful Nebbiolo-based wine stands up to the rich, marrow-infused sauce"]], "image": "https://images.unsplash.com/photo-1579631541616-8d1251ad1e13?w=500&q=80", "imageAlt": "Osso buco Italian braised"}, {"slug": "paella-mixta", "t": "Paella Mixta", "tier": "premium", "cui": "Spanish \u00b7 Coastal", "occ": ["host"], "time": "1 hr 15 min", "method": "Stovetop \u00b7 simmer", "diff": "Medium", "blurb": "Saffron-infused rice loaded with chicken, chorizo, and seafood \u2014 Spain's most famous festive dish.", "prov": {popular_in:'Valencia and the Spanish Mediterranean coast — the rice dish cooked in the wide, shallow pan that gives it its name',famous_for:'The saffron-gold rice spread thin in a wide pan, topped with mussels, prawns, chorizo and chicken, with the prized socarrat — the crisp, almost-burnt crust of rice at the base',consists_of:'Bomba or Calasparra short-grain rice, saffron, smoked paprika, tomato sofrito, stock, chicken, rabbit or chorizo, prawns, mussels and peas; cooked open in a wide paella pan so the rice forms a single thin layer',name_origin:'Paella — from the Latin \'patella\' (small pan); the Valencian name for the pan became the name of the dish. The authentic Valencian version is rabbit and bean; the mixta (mixed seafood and meat) is the global favourite',why_loved:'One pan feeds a table, the socarrat is the prize at the bottom, and the saffron turns the rice the colour of a Mediterranean sunset. Never stir once the stock goes in — that is the rule',method_detail:'Stovetop — fry the meats, build the sofrito, add the rice and toast it, pour in the stock and saffron, spread thin, simmer without stirring until the rice drinks the stock and the base crusts; rest 5 minutes covered'}, "brief": {"lead": "Paella is Spain's most celebrated dish \u2014 short-grain rice cooked in a wide shallow pan with saffron, chicken, chorizo, and seafood. The rice absorbs incredible flavour from the proteins and forms a crispy bottom layer called socarrat. Paella mixta (mixed paella) combines meat and seafood, though purists note this is a modern variation. This is festive, communal dining meant to be relaxed and fun \u2014 perfect for bringing people together around the pan.", "expect": [["Tender, saffron-stained rice grains.", "Bomba rice absorbs liquid without becoming mushy, maintaining distinct grains."], ["Crispy socarrat bottom layer.", "The prized crispy bottom forms from rice cooked without stirring."], ["Variety of proteins throughout.", "Chicken, chorizo, prawns, and mussels create diverse flavours and textures."], ["No-stirring cooking method.", "Unlike risotto, paella is cooked uncovered without stirring for proper texture."]], "stats": [["45", "min", "Active"], ["30", "min", "Passive"], ["4", "", "Serves"], ["Medium", "", "Temp"]], "kit": ["30cm paella pan or large skillet", "Spatula", "Sharp knife", "Tongs"]}, "ing": [["Proteins", [["linear", 200, "g", "chorizo, sliced \u00bdcm thick"], ["linear", 200, "g", "squid/calamari, cut into 7mm rings"], ["countX", 1, "", "onion, diced"], ["countX", 3, "", "garlic cloves, minced"], ["countX", 1, "", "red capsicum/capsicum, diced"], ["linear", 200, "g", "chicken thigh fillets, cut into 3.5cm pieces"], ["countX", 12, "", "medium/large prawns, whole"], ["countX", 12, "", "large mussels, cleaned"]]]], "tl": [["T+00:00", "Prep & sear proteins", "Cut all ingredients, sear chorizo and squid", 600], ["T+00:10", "Build flavour base", "Saut\u00e9 aromatics, brown chicken, add rice and liquids", 900], ["T+00:25", "Initial rice simmer", "Cook rice uncovered for 10 minutes without stirring", 600], ["T+00:35", "Add seafood & finish", "Squidge in prawns and mussels, cook 8 minutes more", 480], ["T+00:43", "Rest & serve", "Cover and rest 5 minutes, then serve with lemon", 300]], "steps": [["Prepare ingredients and sear chorizo", "Slice chorizo \u00bdcm thick. Cut squid into 7mm rings. Dice onion, mince garlic, dice capsicum. Cut chicken into 3.5cm pieces. Heat 1 tablespoon oil in a 30cm paella pan or large skillet over high heat. Add chorizo and cook until browned on each side (about 3 minutes). Remove with slotted spoon and set aside.", "Browning chorizo first renders its flavorful fat which will be used to cook other ingredients.", 300], ["Sear squid quickly", "Add squid rings to hot pan. Cook for 45 seconds on each side, then remove and set aside.", "Squid cooks very quickly and becomes rubbery if overcooked \u2014 just 90 seconds total is perfect.", 180], ["Build flavour base", "Add remaining oil if needed. Add garlic and onion, cook for 2 minutes. Add capsicum, cook for 1 minute. Add chicken pieces. Cook for 2 minutes until lightly browned but still raw inside.", "Building layers of flavour gradually creates the aromatic base that makes paella exceptional.", 300], ["Add rice and liquids", "Add paella rice and mix until grains are coated in oil. Add most of the chorizo (reserve \u00bc for garnish), chicken stock, tomato, and saffron. Stir to combine.", "Coating rice in oil helps grains remain separate during cooking for perfect texture.", 300], ["Initial rice simmer", "Bring to a simmer, then adjust heat to maintain gentle simmer (not rapid). Simmer for 10 minutes \u2014 no stirring. At this stage, some rice should be visible through the liquid but there should still be plenty of liquid.", "No stirring is crucial \u2014 unlike risotto, paella should not be creamy; we want distinct grains.", 600], ["Add seafood and finish", "Scatter frozen peas over rice. Squidge prawns and mussels into rice (partial submerge is fine). Cook for 8 minutes or until prawns are opaque, mussels are open, and most liquid is absorbed. Discard any mussels that do not open.", "Adding seafood partway through prevents overcooking while their juices flavour the rice.", 480], ["Check and rest", "Taste test rice \u2014 it should be firm but cooked through. If too firm, add splash of hot water and continue cooking. Remove from stove. Scatter over squid and reserved chorizo. Cover with lid and rest for 5 minutes.", "Resting allows rice to absorb remaining liquid for perfect texture \u2014 juicy, not stodgy.", 300], ["Serve", "Garnish with chopped fresh parsley and lemon wedges. Take to table as is, then mix up rice with seafood before serving. The mix at the table is part of the paella ritual.", "Mixing at the table distributes flavours and allows guests to customize their portions.", 0]], "pair": [["With the dish", "Albari\u00f1o", "Spain \u00b7 R\u00edas Baixas white wine", "Crisp Spanish white with good acidity complements saffron and seafood"], ["Aperitif", "Gazpacho", "Spain \u00b7 cold soup", "Refreshing cold soup provides light start before rich paella"]], "image": "https://images.unsplash.com/photo-1476124369162-f4978fcf69ba?w=500&q=80", "imageAlt": "Paella Spanish seafood"}, {"slug": "butter-chicken", "t": "Butter Chicken", "tier": "global", "cui": "Indian \u00b7 North Indian", "occ": ["solo", "date"], "time": "45 min", "method": "Stovetop \u00b7 simmer", "diff": "Medium", "blurb": "Tender chicken in a creamy, mildly spiced tomato butter sauce.", "prov": {popular_in:'Delhi and Punjab — the dish that introduced India to the world; now the most-ordered curry on earth',famous_for:'The silken tomato-and-cream gravy, perfumed with fenugreek, that cloaks tandoor-charred chicken in something halfway between sauce and velvet',consists_of:'Chicken marinated in yogurt and spice, roasted in a tandoor or oven, folded into a gravy of tomato, butter, cream, ginger, garlic and dried fenugreek leaves — kasuri methi',name_origin:'Murgh makhani — \'butter chicken\'; created in 1947 at Delhi\'s Moti Mahal by reusing leftover tandoori juices in a tomato gravy. A restaurant invention that became a national icon',why_loved:'Mild, rich, crowd-pleasing — the curry for people who think they don\'t like curry. The fenugreek is the secret: savoury, hay-like, unmistakable once you know it',method_detail:'Stovetop — marinate and char the chicken; build the gravy separately, then fold together and finish with cream and butter off the heat'}, "brief": {"lead": "Butter chicken (murgh makhani) is Delhi's gift to the world\u2014a mild, creamy tomato curry that makes first-time curry eaters feel welcome. Chicken thighs marinate briefly in yogurt and spices, get grilled for char, then simmer gently in a velvety sauce of tomatoes, butter, cream, and fenugreek. It's the Friday night takeout favourite that actually works at home.", "expect": [["Rich but not heavy.", "The sauce is luxurious but balanced by bright tomato and gentle spices."], ["Mild warmth.", "Chili powder provides gentle heat\u2014not a fiery dish."], ["Tender chicken.", "Boneless thigh meat stays juicy through grilling and simmering."], ["Restaurant authenticity.", "Kasuri methi (dried fenugreek leaves) is the signature finish."]], "stats": [["20", "min", "Active"], ["25", "min", "Passive"], ["4", "", "Serves"], ["45", "min", "Total"]], "kit": ["Grill or oven grill", "Heavy-based saucepan or Dutch oven", "Tongs", "Cutting board"]}, "ing": [["Chicken & Marinade", [["linear", 700, "g", "boneless chicken thighs"], ["linear", 60, "g", "Greek yogurt or full-fat plain yogurt"], ["taper", 2, "tsp", "ginger-garlic paste"], ["taper", 1, "tsp", "ground turmeric"], ["taper", 1, "tsp", "chili powder or Kashmiri chili powder"], ["taper", 1, "tsp", "ground cumin"], ["taper", 0.5, "tsp", "garam masala"], ["taper", 1, "tsp", "salt"]]], ["Sauce Base", [["linear", 3, "tbsp", "unsalted butter"], ["linear", 2, "tbsp", "oil"], ["linear", 2, "tbsp", "ginger-garlic paste"], ["linear", 400, "g", "crushed tomatoes or tomato pur\u00e9e"], ["linear", 1, "tbsp", "tomato paste"], ["taper", 1, "tsp", "ground cumin"], ["taper", 0.5, "tsp", "chili powder"], ["taper", 0.5, "tsp", "garam masala"], ["taper", 0.5, "tsp", "salt"]]], ["Finish", [["linear", 60, "ml", "double cream"], ["linear", 1, "tbsp", "kasuri methi (dried fenugreek leaves), crushed"], ["static", "", "to taste", "salt"], ["static", "", "to taste", "coriander (fresh), chopped"]]]], "tl": [["T+00:00", "Marinate chicken", "Mix chicken with yogurt, spices, ginger-garlic paste, salt", 600], ["T+00:10", "Preheat grill", "Set grill to high or oven to 220\u00b0C fan, line tray with foil", 0], ["T+00:15", "Grill chicken", "Grill marinated chicken 12-15 min until charred in spots, flip halfway", 900], ["T+00:30", "Start sauce base", "Saut\u00e9 aromatics in butter-oil, add spices, tomatoes, paste", 300], ["T+00:35", "Simmer sauce", "Add cream, kasuri methi, simmer 10 min until thickened", 600], ["T+00:45", "Combine & serve", "Add charred chicken to sauce, heat through, garnish", 300]], "steps": [["Marinate the chicken", "Cut boneless chicken thighs into bite-sized pieces. In a bowl, combine Greek yogurt, ginger-garlic paste, turmeric, chili powder, cumin, garam masala, and salt. Add chicken, mix well to coat, and marinate at room temperature for at least 20 minutes or up to 1 hour. Don't exceed 24 hours or the texture degrades.", "Yogurt tenderises and adds tang; spices penetrate; brief marination balances flavour and texture.", 1200], ["Grill for char", "Preheat your grill to high (or oven to 220\u00b0C fan). Line a baking tray with foil. Arrange marinated chicken in a single layer. Grill for 12-15 minutes, flipping halfway, until chicken is cooked through and has dark charred spots in places. The charring is essential\u2014it's where the smoky depth comes from.", "High-heat grilling mimics the tandoor, creating the char that defines restaurant butter chicken.", 900], ["Build the sauce base", "In a heavy-based saucepan or Dutch oven, heat butter and oil over medium heat. Add ginger-garlic paste and saut\u00e9 for 1 minute until fragrant. Add cumin, chili powder, garam masala, and salt; cook 30 seconds. Add crushed tomatoes and tomato paste, stir well, and bring to a simmer.", "Cooking spices in fat blooms their flavours; tomato paste adds depth and richness.", 300], ["Simmer for depth", "Reduce heat to low and simmer the tomato base for 15-20 minutes, stirring occasionally, until it thickens and deepens in colour. The oil may start to separate slightly\u2014that's fine. Stir in double cream and crushed kasuri methi. Simmer another 5 minutes until the sauce is velvety and coats the back of a spoon.", "Simmering concentrates the tomato flavour and develops sweetness; kasuri methi is the signature aromatic.", 1500], ["Combine and serve", "Add the grilled chicken to the sauce, stirring gently to coat. Simmer for 2-3 minutes just until heated through\u2014don't overcook or the chicken will dry out. Taste and adjust salt if needed. Serve hot, garnished with fresh coriander, alongside naan or basmati rice.", "Gentle heating integrates the flavours without toughening the chicken; finishing with coriander adds freshness.", 180]], "pair": [["With the curry", "Riesling or off-dry Chenin Blanc", "Germany \u00b7 South Africa", "Off-dry whites cut through richness without fighting mild spices"], ["Starter drink", "Mango Lassi", "Yogurt-mango blend", "Cool, creamy, sweet-tart refreshment that echoes the dish's flavours"]]}, {"slug": "pad-thai", "t": "Pad Thai", "tier": "global", "cui": "Thai \u00b7 Central Thai", "occ": ["solo", "date"], "time": "25 min", "method": "Stovetop \u00b7 stir-fry", "diff": "Medium", "blurb": "Rice noodles stir-fried with tamarind, fish sauce, egg, and crunchy toppings.", "prov": {popular_in:'Every street corner in Thailand — and the dish that taught the West what Thai food could be',famous_for:'The sweet-sour-salty tangle of rice noodles, tamarind and fish sauce, stir-fried hot and fast in a single wok with egg, tofu and peanuts',consists_of:'Flat rice noodles rehydrated, wok-fried with tamarind paste, fish sauce, palm sugar, lime, egg, tofu or prawns, garlic chives, bean sprouts and crushed peanuts — finished with a wedge of fresh lime',name_origin:'Pad Thai — \'Thai stir-fry\'; promoted in the 1930s-40s as a nationalist dish to unite the country around rice noodles and reduce Chinese wheat-noodle influence. A government campaign made it iconic',why_loved:'Four flavours in one mouthful — sweet, sour, salty, umami — and it cooks in minutes once the mis-en-place is set. The peanuts give crunch, the lime gives lift, the chilli gives fire',method_detail:'Wok — hot and fast; soak the noodles, fry the aromatics, push in the egg, toss everything together with the tamarind sauce'}, "brief": {"lead": "Pad Thai is Thailand's great ambassador\u2014the noodle dish that conquered the world by getting everything right: tight rice noodles wok-charred in a sauce of tamarind (sour), fish sauce (salty), and palm sugar (sweet), with egg for richness, prawns for sweet-savour, tofu for body, and a crown of peanuts, bean sprouts, and garlic chives for crunch. The secret? Cook in small batches and use tamarind, not ketchup.", "expect": [["Chewy noodles.", "Medium rice noodles, tender with bounce, not mushy."], ["Sharp balance.", "Sour-salty-sweet hits together\u2014tamarind is non-negotiable."], ["Varied textures.", "Soft egg, crisp sprouts, crunchy peanuts."], ["Custom finish.", "Lime, chilli powder, more peanuts at the table."]], "stats": [["25", "min", "Active"], ["30", "min", "Passive"], ["2", "", "Serves"], ["55", "min", "Total"]], "kit": ["Wok or large heavy skillet", "Wok spatula or large spoon", "Tongs", "Small bowls for prepped ingredients"]}, "ing": [["Noodles & Pork", [["linear", 113, "g", "dried medium rice noodles"], ["linear", 112, "g", "pork shoulder, very thinly sliced"], ["taper", 2, "tsp", "fish sauce"], ["taper", 1, "pinch", "granulated sugar"]]], ["Sauce", [["linear", 40, "g", "palm sugar"], ["linear", 35, "g", "tamarind concentrate (Thai brand)"], ["linear", 35, "ml", "fish sauce"]]], ["Stir-Fry Base", [["linear", 35, "ml", "neutral oil (canola or sunflower)"], ["linear", 70, "g", "pressed tofu, cubed"], ["linear", 25, "g", "sweet preserved radish, minced"], ["linear", 10, "g", "dried prawn"], ["countN", 1, "", "Asian shallot, diced"], ["countN", 1, "", "large egg"], ["linear", 25, "ml", "water"]]], ["Finishings", [["linear", 40, "g", "Chinese flat garlic chives, cut into pieces"], ["linear", 80, "g", "mung bean sprouts"], ["linear", 25, "g", "crushed unsalted dry-roasted peanuts"], ["static", "", "to serve", "lime wedges"], ["static", "", "to serve", "Thai chilli powder"], ["static", "", "to serve", "fish sauce"], ["static", "", "to serve", "extra peanuts"]]]], "tl": [["T+00:00", "Soak noodles", "Cover rice noodles with warm (43\u00b0C) water, soak 30 min until pliable", 0], ["T+00:00", "Marinate pork", "Mix sliced pork with fish sauce and sugar, set aside", 0], ["T+00:25", "Make sauce", "Heat palm sugar and tamarind until sugar dissolves, stir in fish sauce", 300], ["T+00:30", "Stir-fry base", "High-heat wok: sear pork, add aromatics, egg, scramble briefly", 180], ["T+00:33", "Add noodles & sauce", "Add noodles, sauce, water, stir until sauce absorbs (2 min)", 120], ["T+00:35", "Finish with toppings", "Add half chives and sprouts, wilt 30 sec, turn off heat, fold in remaining toppings", 60]], "steps": [["Rehydrate the noodles", "Place dried medium rice noodles in a bowl and cover with slightly warm water (about 43\u00b0C/43\u00b0C). Let soak for 30 minutes until pliable. Drain well. Do not pre-boil\u2014they'll cook in the sauce.", "Soaking rehydrates without making them mushy; pre-boiling leads to clumping.", 1800], ["Marinate the pork", "While noodles soak, slice pork shoulder very thinly (partially freeze if helpful). Toss with fish sauce and a pinch of sugar. Set aside.", "Brief marination seasons the pork and adds a touch of sweetness.", 60], ["Mix the sauce", "In a small saucepan over low heat, combine palm sugar and tamarind concentrate. Stir until sugar dissolves (add 1 tbsp water if needed). Remove from heat and stir in fish sauce until well combined. Set aside.", "The sauce must be ready before the wok heats up\u2014Pad Thai cooks fast.", 180], ["Stir-fry the base", "Heat a wok or heavy skillet over high heat until lightly smoking. Add oil and swirl. Sear pork 20 seconds until halfway cooked. Add tofu, sweet preserved radish, dried prawn, and shallot; stir-fry 40 seconds until aromatic. Push to one side. Crack egg into empty side, scramble briefly until mostly set, then fold everything together, breaking egg into small pieces.", "Cooking egg before noodles prevents it from becoming scrambled bits; early aromatics build depth.", 180], ["Cook noodles with sauce", "Add rehydrated noodles to wok. Pour sauce around edges, along with 1 tbsp plus 2 tsp water. Stir-fry constantly for 2 minutes until sauce is fully absorbed and noodles are tender-cooked. Add half the garlic chives and half the bean sprouts; toss 30 seconds until just wilted.", "Sauce finishes cooking the noodles; half the chives/sprouts cook down, the rest stay fresh.", 180], ["Finish and serve", "Turn off the heat. Add remaining garlic chives, bean sprouts, and crushed peanuts. Toss gently to combine. Serve immediately with extra crushed peanuts, sugar, lime wedges, Thai chilli powder, and fish sauce on the side for diners to adjust.", "Adding half the fresh toppings off heat preserves their crunch; customisation is authentic to Thai style.", 120]], "pair": [["With Pad Thai", "Riesling (off-dry) or Gew\u00fcrztraminer", "Germany \u00b7 Alsace", "Aromatic whites with slight sweetness balance the sharp-sour-salty flavours"], ["Starter drink", "Thai Iced Tea", "Thailand \u00b7 sweet-spiced creamy", "Cool, creamy, sweet\u2014mirrors the dish's flavour profile"]]}, {"slug": "tacos-al-pastor", "t": "Tacos Al Pastor", "tier": "global", "cui": "Mexican \u00b7 Central Mexican", "occ": ["solo", "date", "host"], "time": "40 min", "method": "Stovetop \u00b7 grill or skillet", "diff": "Medium", "blurb": "Marinated pork with pineapple, cooked on a vertical spit, adapted for home.", "prov": {popular_in:'Mexico City and every taquería since — the taco that proves immigration makes cuisine better',famous_for:'The pork, marinated red with achiote and chilli, stacked on a vertical trompo spit and charred at the edge — shaved thin into a warm tortilla with pineapple, onion and coriander',consists_of:'Pork shoulder marinated in achiote paste, guajillo and ancho chillies, pineapple, vinegar and spices; cooked on a vertical spit; served on small corn tortillas with onion, coriander, pineapple and lime',name_origin:'Al pastor — \'shepherd style\'; brought to Mexico by Lebanese immigrants in the 1920s-30s who adapted shawarma to pork and local chillies. The spit stands vertically like its Middle Eastern parent',why_loved:'The charred edge, the sweet pineapple, the sharp onion, the sour lime — four flavours in one folded tortilla. A perfect taco: messy, vivid, immediate, gone',method_detail:'Vertical spit or oven — marinate thin slices, stack, cook slowly with a pineapple catching the drips above; shave, fold into tortillas, top and serve hot'}, "brief": {"lead": "Tacos al pastor is Mexico's Lebanese-inspired masterpiece\u2014pork shoulder, thinly sliced and marinated in dried chillies, achiote, vinegar, and pineapple, then traditionally stacked on a vertical spit (trompo) and roasted until the edges crisp and char. At home, we adapt by marinating thinly cut pork, searing it hot, and serving with fresh pineapple, onions, and coriander on warm corn tortillas with salsa. The pineapple isn't just garnish\u2014it's in the marinade and on the taco, sweet-tart against smoky pork.", "expect": [["Smoky-sweet pork.", "chilli-marinated pork with charred edges, tender within."], ["Bright pineapple.", "Fresh pineapple balances the rich pork\u2014some tacos include grilled pineapple."], ["Small tacos.", "Two-bite corn tortillas, easy to eat multiples."], ["Custom heat.", "Serve with salsa verde, roja, or both."]], "stats": [["30", "min", "Active"], ["30", "min", "Passive"], ["4", "", "Serves"], ["60", "min", "Total"]], "kit": ["Large heavy skillet or grill", "Tongs", "Cutting board", "Small saucepan"]}, "ing": [["Pork & Marinade", [["linear", 900, "g", "pork shoulder or butt, thinly sliced"], ["countX", 3, "", "dried guajillo chillies, stemmed and seeded"], ["countX", 2, "", "dried ancho or pasilla chillies, stemmed and seeded"], ["linear", 30, "ml", "apple cider vinegar or white vinegar"], ["linear", 120, "ml", "pineapple juice"], ["linear", 15, "g", "achiotepaste or 1 tbsp achiote powder"], ["linear", 4, "", "garlic cloves"], ["linear", 1, "", "small white onion"], ["taper", 1, "tsp", "ground cumin"], ["taper", 1, "tsp", "dried oregano"], ["taper", 1, "tsp", "salt"], ["taper", 0.5, "tsp", "black pepper"]]], ["Serving", [["countX", 1, "", "small pineapple, cut into chunks"], ["countX", 1, "", "white onion, diced"], ["static", "", "125", "ml", "chopped coriander"], ["countX", 12, "", "corn tortillas"], ["static", "", "to taste", "salsa verde or roja"], ["static", "", "to serve", "lime wedges"]]]], "tl": [["T+00:00", "Rehydrate chillies", "Boil dried chillies in water 15 min until soft, drain", 0], ["T+00:15", "Blend marinade", "Blend softened chillies with vinegar, pineapple juice, garlic, onion, spices", 300], ["T+00:20", "Marinate pork", "Coat sliced pork in marinade, refrigerate 30 min (or overnight)", 0], ["T+00:50", "Warm tortillas", "Heat corn tortillas on griddle or dry skillet, keep warm", 0], ["T+00:55", "Cook pork", "Sear marinated pork over high heat 2-3 min per side until charred and cooked", 300], ["T+01:00", "Assemble & serve", "Fill tortillas with pork, pineapple, onion, coriander, serve with salsa, lime", 120]], "steps": [["Prepare the chillies", "Bring a small saucepan of water to boil. Remove from heat, add dried guajillo and ancho chillies, and soak for 15 minutes until softened. Drain, reserving a splash of soaking liquid.", "Rehydrating dried chillies softens them for blending; the soaking liquid adds depth.", 900], ["Make the marinade", "In a blender, combine the softened chillies, vinegar, pineapple juice, achiote paste (or powder), garlic, half the onion (roughly chopped), cumin, oregano, salt, and pepper. Blend until completely smooth, adding a tablespoon of the chilli soaking liquid if needed to get it moving.", "Blending creates a smooth, intensely flavoured paste that penetrates the pork.", 300], ["Marinate the pork", "Slice pork shoulder against the grain into very thin strips (partially freeze for easier slicing). Place in a bowl or dish, pour the marinade over, and toss to coat thoroughly. Cover and refrigerate for at least 30 minutes, up to overnight.", "Thin slices absorb marinade quickly; the vinegar tenderises and chillies add colour and flavour.", 1800], ["Cook the pork", "Heat a large heavy skillet or grill over high heat until very hot. Shake excess marinade from pork (discard marinade) and add pork in batches\u2014don't crowd the pan. Sear for 2-3 minutes per side until charred in spots and cooked through. Transfer to a board and rest for 5 minutes, then chop into bite-sized pieces.", "High heat creates char; resting prevents juices from running out.", 420], ["Warm the tortillas", "While pork cooks, heat corn tortillas on a dry skillet or griddle over medium-high heat for about 30 seconds per side until pliable and slightly charred. Stack and wrap in a cloth to keep warm.", "Warm tortillas fold without cracking; charring adds flavour.", 240], ["Assemble and serve", "Dice the remaining onion and cut pineapple into small chunks. For each taco, fill a warm tortilla with chopped pork, pineapple, onion, and coriander. Serve with lime wedges and salsa on the side. Diners can add salsa and squeeze lime to taste.", "The classic trio\u2014pork, pineapple, onion\u2014creates the perfect bite; fresh garnishes brighten the rich pork.", 120]], "pair": [["With tacos", "Mexican Lager or IPA", "Mexico \u00b7 crisp bitterness", "Beer cuts fat and spice, refreshes palate between bites"], ["Starter drink", "Paloma", "Tequila \u00b7 grapefruit \u00b7 lime", "Bitter-sweet, tart, refreshing\u2014matches pineapple and chillies"]]}, {"slug": "tonkotsu-ramen", "t": "Tonkotsu Ramen", "tier": "global", "cui": "Japanese \u00b7 Kyushu", "occ": ["solo", "date"], "time": "12-14 hr", "method": "Stovetop \u00b7 long simmer", "diff": "Hard", "blurb": "Rich, creamy pork bone broth served with noodles, chashu pork, and toppings.", "prov": {popular_in:'Hakata, Kyushu — and now every serious ramen shop on earth. The cult dish of the pork-bone broth',famous_for:'The milky, opaque, collagen-rich broth that comes from boiling pork bones for twelve hours or more — hearty, deeply savoury, almost creamy',consists_of:'Pork bones (trotters, neck, head) boiled until the broth turns white, thin alkaline noodles, chashu pork belly, ajitama egg, spring onion, wood-ear mushroom and a fragrant tare of soy or miso',name_origin:'Tonkotsu — \'pork bone\'; a Kyushu invention born post-war from cheap bones and patience. The broth\'s cloudiness is the collagen emulsifying — the whole point',why_loved:'The broth is the dish — rich enough to coat the lips, deep enough to taste of hours. The soft-boiled, marinated egg is the reward at the bottom of the bowl',method_detail:'Stovetop — boil bones at a hard rolling simmer (not a blanche) for 10-14 hours; assemble the bowls with tare, broth, noodles and toppings'}, "brief": {"lead": "Tonkotsu ramen is the bowl that changed how the world thinks about soup\u2014a broth so rich, opaque, and creamy you'd swear there's cream or milk, but it's all from bones. Pork trotters, chicken carcasses, and aromatics are boiled at a rolling boil for 12-plus hours, breaking down collagen until it emulsifies fat and marrow into the liquid, creating a pale, milky soup with body like light cream. Served with springy noodles, tender chashu pork, a soft-yolk egg, and garnishes, it's the ultimate comfort bowl\u2014worth the long cook.", "expect": [["Creamy broth.", "Pale, opaque, intensely porky\u2014rich but balanced, not cloying."], ["Springy noodles.", "Thin, alkaline noodles with bounce\u2014made for slurping."], ["Tender chashu.", "Melt-in-your-mouth pork belly braise."], ["Custom bowl.", "Add egg, spring onions, sesame seeds, chilli oil to taste."]], "stats": [["1", "hr", "Active"], ["12-14", "hr", "Passive"], ["2", "", "Serves"], ["13-15", "hr", "Total"]], "kit": ["Large stockpot with tight-fitting lid", "Fine-mesh strainer", "Cheesecloth (optional)", "Slotted spoon"]}, "ing": [["Broth Base", [["linear", 1.4, "kg", "pig trotters, split lengthwise"], ["linear", 900, "g", "chicken backs and carcasses"], ["linear", 450, "g", "pork fatback"], ["linear", 2, "tbsp", "vegetable oil"], ["countX", 1, "", "large onion, roughly chopped"], ["countX", 12, "", "garlic cloves"], ["linear", 7.5, "cm", "fresh ginger, roughly chopped"], ["countX", 2, "", "whole leeks, washed and chopped"], ["countX", 24, "", "spring onions, white parts only"], ["linear", 170, "g", "whole mushrooms (cremini)"]]], ["Toppings", [["static", "", "", "ramen noodles (fresh or dried)"], ["static", "", "", "chashu pork belly slices (marinated and braised)"], ["static", "", "", "soft-boiled or marinated eggs (ajitsuke tamago)"], ["static", "", "", "spring onions, finely sliced"], ["static", "", "", "norisheets, cut into strips"], ["static", "", "", "sesame seeds"], ["static", "", "", "chilli oil or sesame oil"], ["static", "", "", "light soy sauce or salt"]]]], "tl": [["T+00:00", "Blanch bones", "Cover pork and chicken bones with cold water, bring to boil, dump immediately", 300], ["T+00:05", "Char aromatics", "Pan-sear onion, garlic, ginger until deeply charred (15 min)", 0], ["T+00:20", "Clean bones", "Scrub all bones under cold water until grey/white, remove all dark bits", 900], ["T+00:35", "Start broth", "Return bones to pot with charred veg, leeks, spring onions, mushrooms, fatback, cover with cold water, bring to rolling boil", 600], ["T+04:00", "Remove fatback", "Lift out pork fatback when tender, refrigerate for later", 0], ["T+12:00", "Finish broth", "Boil until opaque and creamy (6-8 more hours), strain through cheesecloth", 0], ["T+12:30", "Season & serve", "Whisk in chopped fatback, season with soy/salt, serve with noodles and toppings", 300]], "steps": [["Blanch the bones", "Place pork trotters and chicken carcasses in a large stockpot and cover with cold water. Bring to a boil over high heat. As soon as it boils, dump the water and bones down the drain. This initial boil tightens proteins and releases blood.", "Blanching removes impurities that would cloud the broth\u2014this is the key to a clean, pale tonkotsu.", 300], ["Char the aromatics", "While bones blanch, heat vegetable oil in a cast iron skillet over high heat until smoking. Add onion (skin on), garlic cloves, and ginger chunks. Cook, tossing occasionally, until deeply charred on most sides\u2014about 15 minutes. The darker, the better. Set aside.", "Charring creates Maillard reactions that add deep umami to the broth.", 900], ["Clean the bones thoroughly", "After blanching, wash every bone under cold running water, scrubbing with your hands or a chopstick to remove every bit of dark marrow, coagulated blood, or brown discoloration. Bones should be uniformly grey or white. This takes about 15 minutes.", "Thorough cleaning prevents the broth from turning brown\u2014you want pale, pristine tonkotsu.", 900], ["Build and start the broth", "Return cleaned bones to the stockpot. Add charred aromatics, leeks, spring onion whites, mushrooms, and the slab of pork fatback. Cover with cold water. Bring to a rolling boil over high heat, skimming off any scum that rises (this stops after 20 minutes). Wipe the pot rim clean. Reduce to a bare simmer, cover with a heavy lid, and check after 15 minutes\u2014adjust heat to maintain a slow rolling boil.", "A rolling boil (not a gentle simmer) is what emulsifies collagen into creaminess.", 600], ["Cook 12-plus hours", "After 4 hours, carefully remove the pork fatback with a slotted spoon\u2014it should be tender. Refrigerate it. Continue boiling the broth, topping up with water as needed to keep bones submerged, for 8 to 12 more hours. The broth is ready when it's opaque with the texture of light cream, about 12-14 hours total.", "Long boiling breaks down collagen into gelatin and emulsifies fat, creating the signature creamy texture.", 43200], ["Strain and finish", "Once broth is opaque and rich, strain through a fine-mesh strainer (lined with cheesecloth for extra clarity). Skim and discard any floating fat. Finely chop the cooked pork fatback and whisk it into the broth. To serve, season broth with salt, soy sauce, or a splash of sesame oil. Ladle over cooked ramen noodles and top with chashu pork, soft-boiled egg, spring onions, nori, sesame seeds, and chilli oil.", "Straining removes solids; whipped-in fatback adds unctuous richness; seasoning is done at the end.", 1800]], "pair": [["With ramen", "Japanese Lager or Dry Sake", "Japan \u00b7 clean crisp", "Clean flavours cut through richness, refresh palate"], ["Starter drink", "Highball (Whisky + Soda)", "Japan \u00b7 whisky \u00b7 soda \u00b7 lemon", "Bubbly, bitter, refreshing\u2014classic izakaya pairing"]]}, {"slug": "tagliatelle-al-ragu-bolognese", "t": "Tagliatelle al Ragu Bolognese", "tier": "global", "cui": "Italian \u00b7 Emilia-Romagna", "occ": ["solo", "date"], "time": "3.5 hr", "method": "Stovetop \u00b7 slow braise", "diff": "Medium", "blurb": "Fresh egg pasta with a slow-cooked meat sauce from Bologna.", "prov": {popular_in:'Bologna, Emilia-Romagna — the dish the city is named for; the platonic ideal of meat sauce',famous_for:'The slow-simmered ragù of beef, pork and pancetta, tomato and wine, served on ribbon-wide tagliatelle — never spaghetti. The pasta shape is non-negotiable to a Bolognese',consists_of:'Soffritto of onion, carrot and celery, browned minced beef and pork, pancetta, white wine, a little tomato, milk and stock — simmered 2-4 hours until rich and silky; tossed with fresh tagliatelle',name_origin:'Ragù alla Bolognese — registered with the Bologna Chamber of Commerce in 1982; the authentic recipe specifies tagliatelle, not spaghetti, because the egg pasta holds the sauce where the smooth dried strand slides it off',why_loved:'Patience in a pan — the long simmer coaxes depth no shortcut can fake. The milk softens the acid of the tomato; the wine lifts the meat; the result is greater than the sum',method_detail:'Stovetop — sweat the soffritto slowly, brown the meats, deglaze with wine, add tomato and stock, simmer the lowest possible heat for hours; finish with milk; toss through fresh tagliatelle'}, "brief": {"lead": "Rag\u00f9 Bolognese is Italy's most iconic meat sauce\u2014a slow-cooked masterpiece from Bologna that turns humble beef and pork into something luxurious. It starts with a soffritto of finely minced onion, carrot, celery (no garlic, no herbs in the authentic version), builds with beef and pork mince, a splash of wine, a note of tomato, and a long, gentle simmer for at least three hours (some cooks go longer). The result is a rich, deeply flavoured sauce that coats fresh egg tagliatelle perfectly. This isn't tomato sauce with meat\u2014it's meat sauce with a touch of tomato.", "expect": [["Meat-forward richness.", "Primarily beef and pork flavour, tomato is secondary."], ["Tender depth.", "Slow cooking mellows and concentrates\u2014no harsh notes."], ["Saucy but not soupy.", "Thick enough to cling to fresh pasta strands."], ["Fresh pasta essential.", "Tagliatelle's rough surface holds the sauce."]], "stats": [["45", "min", "Active"], ["3", "hr", "Passive"], ["4", "", "Serves"], ["3.75", "hr", "Total"]], "kit": ["Large heavy pot or Dutch oven", "Sharp knife", "Cutting board", "Large pot for pasta water"]}, "ing": [["Rag\u00f9 Base", [["linear", 30, "g", "pancetta or unsmoked bacon, finely minced"], ["linear", 80, "g", "onion, very finely minced"], ["linear", 40, "g", "carrot, very finely minced"], ["linear", 40, "g", "celery, very finely minced"], ["linear", 30, "ml", "extra virgin olive oil"], ["linear", 30, "g", "butter"], ["linear", 400, "g", "beef mince (beef mince)"], ["linear", 100, "g", "pork mince (pork mince)"], ["linear", 120, "ml", "dry white wine"], ["linear", 120, "ml", "whole milk or cream"], ["linear", 80, "g", "tomato pur\u00e9e or passata"], ["taper", 1, "tsp", "salt"], ["taper", 0.5, "tsp", "black pepper"]]], ["Pasta & Finish", [["static", "", "", "fresh tagliatelle (or high-quality dried egg tagliatelle)"], ["static", "", "to taste", "parmesan, freshly grated"], ["static", "", "to serve", "extra virgin olive oil"]]]], "tl": [["T+00:00", "Prep soffritto", "Finely mince onion, carrot, celery; mince pancetta", 0], ["T+00:20", "Cook soffritto", "Saut\u00e9 pancetta, butter, oil, soffritto veg gently 10-15 min until soft", 900], ["T+00:35", "Brown meat", "Add beef and pork mince, brown well, breaking up clumps", 600], ["T+00:45", "Add liquids", "Add wine, reduce to dry; add milk/cream, reduce; add tomato pur\u00e9e, season", 600], ["T+01:00", "Simmer rag\u00f9", "Cover and simmer very gently 2.5-3+ hours, stirring occasionally", 10800], ["T+03:30", "Cook pasta", "Cook fresh tagliatelle 1-2 min in salted water, drain, toss with rag\u00f9", 300], ["T+03:35", "Serve", "Serve with parmesan and a splash of olive oil", 0]], "steps": [["Prepare the soffritto", "Finely mince the onion, carrot, and celery into tiny, even pieces\u2014this is the Italian soffritto, the flavour foundation. Also finely mince the pancetta. Consistency matters: everything should be very small so it melts into the sauce.", "The soffritto provides the aromatic base\u2014finely minced it disappears into the sauce.", 1200], ["Cook soffritto gently", "In a large heavy pot or Dutch oven, heat olive oil and butter over medium-low heat. Add the minced pancetta and cook for 5 minutes until it releases its fat. Add the soffritto vegetables (onion, carrot, celery) and cook gently for 10-15 minutes until soft and translucent but not browned. Season lightly with salt.", "Gentle cooking sweetens the vegetables without browning\u2014this is the foundation of Bolognese flavour.", 900], ["Brown the meats", "Increase heat to medium. Add beef and pork mince to the pot. Break up any clumps with a spoon and cook, stirring occasionally, until the meat is well-browned all over. This should take about 10-15 minutes. Don't rush this step\u2014browning adds deep flavour.", "Well-browned meat develops Maillard reactions that provide the rag\u00f9's deep savoury character.", 900], ["Add wine, milk, tomato", "Pour in the white wine and cook, stirring, until completely evaporated\u2014this concentrates the flavours. Add the milk or cream and cook again until nearly evaporated. Stir in the tomato pur\u00e9e and season with salt and pepper. The sauce should look thick and meaty, not tomato-heavy.", "Wine adds acidity and depth; milk mellows and balances; tomato is a supporting actor, not the star.", 600], ["Slow-simmer the rag\u00f9", "Reduce heat to low and cover the pot. Simmer very gently for at least 2.5 to 3 hours, stirring occasionally to prevent sticking. The rag\u00f9 is done when the meat is tender and the sauce has thickened and darkened to a rich, deep colour. Some cooks simmer up to 4 hours.", "Long, gentle simmering mellows the flavours and develops the characteristic Bolognese richness.", 10800], ["Cook and serve", "While rag\u00f9 simmers, bring a large pot of salted water to boil. Cook fresh tagliatelle for 1-2 minutes (dried egg tagliatelle may need 3-4 minutes) until al dente. Drain, reserving a splash of pasta water. Toss the pasta with the rag\u00f9, adding a splash of pasta water if needed to coat. Serve immediately with freshly grated parmesan and a drizzle of olive oil.", "Fresh egg pasta is traditional\u2014the rough surface holds the sauce; finishing with parmesan and oil is authentic Bolognese style.", 300]], "pair": [["With rag\u00f9", "Sangiovese or Barbera", "Italy \u00b7 medium-bodied red", "Italian red with acidity cuts richness, matches meat intensity"], ["Starter drink", "Negroni", "Italy \u00b7 gin \u00b7 Campari \u00b7 vermouth", "Bitter, herbal, refreshing\u2014classic Italian aperitivo"]]}, {"slug": "pizza-margherita", "t": "Pizza Margherita", "tier": "global", "cui": "Italian \u00b7 Neapolitan", "occ": ["solo", "date"], "time": "24+ hr", "method": "Oven \u00b7 very high heat", "diff": "Hard", "blurb": "Classic Neapolitan pizza with tomato, mozzarella, and basil.", "prov": {"popular_in": "Italy (Naples origin), worldwide pizzerias", "famous_for": "Simple toppings representing Italian flag colours on soft, puffy crust", "consists_of": "Soft, puffy dough with San Marzano tomatoes, fior di latte mozzarella, fresh basil", "name_origin": "Created in 1889 by Raffaele Esposito in Naples to honour Queen Margherita of Savoy", "why_loved": "Pure expression of quality ingredients, crispy-chewy crust, bright flavours", "method_detail": "Oven \u2014 very high temperature (450-500\u00b0C), fast bake (60-90 seconds)"}, "brief": {"lead": "Pizza Margherita is Naples' masterpiece and the world's most iconic pizza\u2014soft, puffy dough with a leopard-spotted char, topped with just three ingredients in the colours of the Italian flag: red San Marzano tomatoes, white fior di latte mozzarella (or buffalo mozzarella), and green fresh basil. The dough ferments for 24-plus hours for flavour and bubbles, then bakes in screaming-hot heat (450-500\u00b0C if you can get it) for 60 to 90 seconds. The result is a crisp yet chewy crust, sweet-tart tomato, creamy cheese, aromatic basil\u2014the perfect pizza expression of less-is-more.", "expect": [["Puffy, charred crust.", "Soft and airy inside with leopard-spotted char on edges."], ["Simple toppings.", "Tomato, mozzarella, basil\u2014nothing extraneous."], ["Fast bake.", "60-90 seconds at extreme heat\u2014texture is everything."], ["Eaten immediately.", "Pizza waits for no one."]], "stats": [["30", "min", "Active"], ["24+", "hr", "Passive"], ["2", "", "Serves"], ["24.5+", "hr", "Total"]], "kit": ["Pizza stone or steel", "Peel (or inverted baking sheet)", "Very hot oven (or pizza oven)", "Digital scale"]}, "ing": [["Dough (makes 2 pizzas)", [["linear", 500, "g", "Italian 00 flour (or strong bread flour)"], ["linear", 325, "g", "water (room temperature, 65% hydration)"], ["linear", 10, "g", "fine sea salt"], ["linear", 3, "g", "instant yeast (1 tsp)"], ["linear", 10, "g", "olive oil (optional)"]]], ["Toppings", [["linear", 200, "g", "San Marzano tomatoes or peeled plum tomatoes, crushed"], ["linear", 200, "g", "fior di latte mozzarella (or buffalo mozzarella), diced"], ["static", "", "", "fresh basil leaves"], ["linear", 10, "ml", "extra virgin olive oil"], ["taper", 1, "pinch", "flaky sea salt"]]]], "tl": [["T+00:00", "Mix dough", "Mix flour, salt, yeast, water, knead until smooth (8-10 min)", 600], ["T+00:15", "Bulk ferment", "Let dough rise at room temp 2 hours, then refrigerate 12-24 hours", 0], ["T+24:00", "Preheat oven", "Heat oven to max (250\u00b0C+) with pizza stone/steel for 1 hour", 0], ["T+25:00", "Shape pizzas", "Divide dough into 2, shape into discs, let relax 20 min", 0], ["T+25:20", "Top and bake", "Top with tomato, mozzarella, bake 60-90 sec in pizza oven (3-5 min home oven)", 300], ["T+25:25", "Finish and serve", "Add fresh basil, drizzle with oil, slice and eat immediately", 0]], "steps": [["Mix the dough", "Combine 500g Italian 00 flour, 10g salt, and 3g instant yeast in a large bowl. Add 325g room-temperature water and 10g olive oil (optional). Mix by hand or with a dough hook until a shaggy dough forms. Turn onto a clean surface and knead for 8-10 minutes until smooth and elastic. The dough should feel soft and slightly tacky, not sticky.", "00 flour has the right protein for Neapolitan texture; hydration (65%) creates the characteristic puff.", 600], ["Bulk fermentation", "Place dough in a lightly oiled bowl, cover, and let rise at room temperature for 2 hours. Then refrigerate for 12 to 24 hours. This long, slow fermentation develops flavour and creates the dough's extensibility for stretching.", "Long fermentation builds flavour, gluten structure, and the bubbles that char in the oven.", 1800], ["Preheat oven extreme", "One hour before baking, place a pizza stone or baking steel in your oven and heat to its maximum setting\u2014ideally 250\u00b0C (249\u00b0C) or higher. If you have a pizza oven that reaches 450-500\u00b0C, even better. The stone or steel must be fully preheated to create the blistered crust.", "Extreme heat is the secret to the leopard-spotted char and puff\u2014Neapolitan pizza bakes in seconds.", 3600], ["Shape the pizzas", "Remove dough from the fridge 1-2 hours before baking to come to room temperature. Divide into 2 equal pieces (about 200g each). Shape each into a ball and let rest on a floured surface, covered, for 20 minutes. Gently stretch each ball into a 25-30cm disc using your hands\u2014don't use a rolling pin, which would press out the gas bubbles.", "Room-temperature dough stretches easily; hand-pushing preserves the bubbles that create puff.", 1800], ["Top minimally", "Lay one stretched dough on a floured peel or inverted baking sheet. Spread with crushed San Marzano tomatoes (drained of excess liquid). Scatter diced fior di latte mozzarella over the top. Don't overload\u2014sparse toppings ensure the crust cooks through. Have fresh basil and olive oil ready.", "Minimal toppings let the dough shine\u2014too much weight prevents proper rise.", 180], ["Bake fast and serve", "Slide the pizza onto the preheated stone. In a pizza oven (450-500\u00b0C), bake for 60-90 seconds. In a home oven (250\u00b0C), bake for 3-5 minutes. The crust should be puffy and charred in spots, the cheese melted and bubbling. Remove from oven, immediately scatter fresh basil leaves over the top, drizzle with olive oil, and sprinkle with flaky salt. Slice and serve immediately.", "Fast baking at extreme heat creates the characteristic Neapolitan texture\u2014crisp-chewy with leopard char. Eat while hot.", 300]], "pair": [["With pizza", "Lambrusco or Barbera", "Italy \u00b7 frizzante red or medium red", "Italian red with acidity or slight bubbles cuts richness, matches tomato"], ["Starter drink", "Aperol Spritz", "Italy \u00b7 Aperol \u00b7 prosecco \u00b7 soda", "Bitter-sweet, bubbly, refreshing\u2014classic Italian aperitivo"]]}, {"slug": "katsu-curry", "t": "Katsu Curry", "tier": "global", "cui": "Japanese \u00b7 Yoshoku", "occ": ["solo", "date"], "time": "35 min", "method": "Stovetop \u00b7 fry then simmer", "diff": "Medium", "blurb": "Crispy panko chicken cutlet with Japanese curry sauce over rice.", "prov": {popular_in:'Japan — the yoshoku classic that married British breaded cutlets to Indian curry via the Imperial Navy. Now the comfort lunch of choice from Tokyo to Cape Town',famous_for:'The golden panko-crusted pork cutlet, shatter-crisp, laid over rice beside a thick, mild, slightly sweet curry sauce — indulgent and gentle at once',consists_of:'A pork fillet or loin, floured, egged and panko-crumbed, fried golden, sliced into strips over Japanese short-grain rice, served with a curry roux of onion, carrot, apple, garam and stock',name_origin:'Katsu — a Japanese shortening of \'cutlet\'; kare — curry, adapted from the British Navy\'s version of Indian curry. The two met in 20th-century Japan and became inseparable',why_loved:'The crunch of the cutlet against the soft curry and rice is textural genius — three layers, three comforts. The apple in the sauce gives a sweetness that makes the spice approachable',method_detail:'Stovetop — make the curry roux ahead; fry the cutlet hot and fast; slice and serve over rice with the sauce poured alongside'}, "brief": {"lead": "Katsu curry is Japan's brilliant mashup\u2014a crispy panko-crusted chicken cutlet (tonkatsu) served over rice with a rich, mildly spiced curry sauce. The chicken gets a classic three-step breading (flour, egg, panko) and fries until golden-crisp. Meanwhile, the curry sauce builds from a roux of butter and flour, curry powder, aromatics, and stock, simmered into velvet. It's comfort food that delivers: the crunch of cutlet, the warmth of curry, the sweetness of Japanese-style curry, all over fluffy rice. A Friday night favourite.", "expect": [["Crisp-crunchy cutlet.", "Panko breading fries light and airy\u2014stay-crispy under sauce."], ["Mild curry flavour.", "Japanese curry is sweeter, milder than Indian style."], ["Velvety sauce.", "Roux-thickened, glossy, clings to cutlet and rice."], ["Complete meal.", "Protein, carb, sauce in one bowl\u2014satisfying and balanced."]], "stats": [["25", "min", "Active"], ["20", "min", "Passive"], ["2", "", "Serves"], ["45", "min", "Total"]], "kit": ["Large skillet or wok", "Tongs", "Meat mallet or rolling pin", "Saucepan"]}, "ing": [["Chicken Cutlet", [["linear", 400, "g", "chicken breasts or thighs, pounded to 1.5cm thickness"], ["taper", 1, "tsp", "salt"], ["taper", 0.5, "tsp", "black pepper"], ["linear", 50, "g", "plain flour"], ["countN", 2, "", "eggs, beaten"], ["linear", 100, "g", "panko breadcrumbs"], ["linear", 60, "ml", "neutral oil for frying"]]], ["Curry Sauce", [["linear", 30, "g", "butter"], ["linear", 30, "g", "plain flour"], ["linear", 2, "tbsp", "mild curry powder"], ["linear", 1, "", "small onion, diced"], ["linear", 1, "", "small carrot, diced"], ["linear", 1, "", "small apple, grated (optional)"], ["linear", 500, "ml", "chicken stock"], ["linear", 2, "tbsp", "soy sauce"], ["linear", 1, "tbsp", "ketchup or Worcestershire sauce"], ["taper", 1, "tsp", "honey or sugar"], ["taper", 0.5, "tsp", "salt"]]], ["Serve", [["static", "", "", "cooked white rice"], ["static", "", "to taste", "fukujinzuke (pickled vegetables) or pickled red ginger"]]]], "tl": [["T+00:00", "Pound chicken", "Pound chicken to even thickness, season with salt and pepper", 300], ["T+00:05", "Bread chicken", "Dredge in flour, dip in egg, coat with panko", 0], ["T+00:15", "Make roux", "Melt butter, cook flour + curry powder 2 min, add veg, cook 3 min", 600], ["T+00:20", "Simmer sauce", "Add stock, soy, ketchup, honey, simmer 10 min until thickened", 0], ["T+00:25", "Fry chicken", "Fry chicken in oil 3-4 min per side until golden and cooked through", 480], ["T+00:33", "Slice & serve", "Slice chicken into strips, serve over rice with sauce ladled over", 0]], "steps": [["Prep the chicken", "Pound chicken breasts or thighs to an even 1.5cm thickness using a meat mallet or rolling pin. Season both sides with salt and pepper. Set up three shallow bowls: one with flour, one with beaten eggs, one with panko breadcrumbs.", "Even thickness cooks evenly; breading in the right order creates crisp coating that stays.", 300], ["Bread the chicken", "Dredge each chicken piece in flour, shaking off excess. Dip into beaten egg, letting excess drip off. Press firmly into panko breadcrumbs, coating both sides well. Place breaded chicken on a plate and let rest for 10 minutes\u2014this helps the coating adhere.", "Flour-egg-panko is the classic katsu breading; resting prevents coating from flaking.", 1800], ["Start the curry roux", "Melt butter in a saucepan over medium heat. Add flour and curry powder; cook, stirring constantly, for 2 minutes until fragrant but not browned. Add diced onion, carrot, and grated apple (if using); cook for 3 minutes until softened.", "The roux thickens the sauce; cooking curry powder blooms its flavours without bitterness.", 300], ["Simmer the sauce", "Gradually whisk in chicken stock, stirring to eliminate any lumps. Add soy sauce, ketchup, honey, and salt. Reduce heat to low and simmer for 10-15 minutes, stirring occasionally, until the sauce thickens and coats the back of a spoon. Taste and adjust seasoning if needed.", "Simmering mellows the curry powder and develops the Japanese-style sweetness.", 900], ["Fry the chicken", "While sauce simmers, heat oil in a large skillet over medium-high heat. Fry breaded chicken for 3-4 minutes per side until golden-brown and crispy, and cooked through (74\u00b0C internal). Drain on paper towels.", "Medium-high heat creates crisp exterior without burning; draining removes excess oil.", 480], ["Slice and serve", "Slice the fried chicken into strips. Serve immediately over hot white rice, ladling the curry sauce over the chicken and rice. Accompany with fukujinzuke (Japanese pickles) or pickled ginger for crunch and contrast.", "Slicing makes eating easy; sauce over both chicken and rice ties the dish together; pickles add contrast.", 120]], "pair": [["With katsu curry", "Japanese Lager or Dry Sake", "Japan \u00b7 clean crisp", "Clean flavours cut through rich curry sauce, refresh palate"], ["Starter drink", "Highball (Whisky + Soda)", "Japan \u00b7 whisky \u00b7 soda \u00b7 lemon", "Bubbly, bitter, refreshing\u2014classic izakaya pairing with fried foods"]]}, {"slug": "egg-fried-rice", "t": "Egg Fried Rice", "tier": "global", "cui": "Chinese \u00b7 Cantonese", "occ": ["solo"], "time": "20 min", "method": "Stovetop \u00b7 stir-fry", "diff": "Easy", "blurb": "Fried rice with egg, vegetables, and seasonings\u2014restaurant style at home.", "prov": {popular_in:'Every Chinese kitchen — and every kitchen that learned to use yesterday\'s rice. The universal answer to \'what\'s for dinner when there\'s nothing\'',famous_for:'The way day-old cold rice transforms in a hot wok — each grain separate, glossed with oil, flecked with scrambled egg and spring onion, ready in five minutes',consists_of:'Cold cooked rice (mandatory — fresh rice turns to mush), eggs beaten loose, oil, garlic, spring onion, soy sauce, and a pinch of white pepper. Optional peas, prawns or char siu',name_origin:'Chaofan — \'stir-fried rice\'; a Cantonese way to avoid waste, turned into a dish so good it needs no excuse. Every Chinese region has its version',why_loved:'Fast, forgiving, infinitely adaptable — the technique that proves a hot wok and cold rice are all you need. The egg sets in golden ribbons through the white grains',method_detail:'Wok — smoking hot; fry the egg first, set it aside, then rice, then combine. Never overload the wok or it steams instead of fries'}, "brief": {"lead": "Egg fried rice is the ultimate home-cook comfort dish\u2014takeout-style rice that's actually better made at home if you know a few techniques. Jasmine rice gets washed and cooked (fresh rice works if you fluff it well), then stir-fried over high heat with beaten eggs, mixed vegetables, and a Cantonese seasoning blend of light and dark soy sauce, salt, sugar, and chicken bouillon powder. The secret? Hot wok, constant motion, and proper seasoning. No mushy clumps, just fluffy, fragrant, slightly charred grains in under 20 minutes.", "expect": [["Fluffy grains.", "Rice is separate, not clumpy\u2014each grain coated but distinct."], ["Egg integrated.", "Egg is cooked into rice, not scrambled separately."], ["Balanced seasoning.", "Salty-savoury with depth from both soy sauces."], ["Quick cooking.", "High-heat stir-fry takes minutes\u2014fast weeknight dinner."]], "stats": [["15", "min", "Active"], ["15", "min", "Passive"], ["2", "", "Serves"], ["30", "min", "Total"]], "kit": ["Wok or large heavy skillet", "Wok spatula", "Rice cooker or pot", "Chopsticks"]}, "ing": [["Rice & Egg", [["linear", 200, "g", "uncooked jasmine rice"], ["linear", 200, "g", "water"], ["countN", 2, "", "large eggs"], ["taper", 0.25, "tsp", "salt"], ["linear", 15, "ml", "neutral oil"]]], ["Vegetables", [["linear", 30, "g", "spring onion (green parts only), diced"], ["linear", 30, "g", "carrot, small dice"], ["linear", 60, "g", "frozen corn and peas"]]], ["Seasoning", [["linear", 15, "ml", "light soy sauce"], ["linear", 5, "ml", "dark soy sauce"], ["taper", 0.25, "tsp", "salt"], ["taper", 0.25, "tsp", "sugar"], ["taper", 0.5, "tsp", "chicken bouillon powder"], ["linear", 15, "ml", "water"]]]], "tl": [["T+00:00", "Cook rice", "Wash rice 3 times, cook with water in rice cooker, let steam 2 min", 0], ["T+00:15", "Prep veg & egg", "Dice carrot and spring onion; beat eggs with salt", 0], ["T+00:18", "Par-cook veg", "Microwave carrot, corn, peas with splash of water 2 min, drain", 0], ["T+00:20", "Fluff rice", "Fluff cooked rice with chopsticks 1-2 min to cool and separate", 0], ["T+00:22", "Stir-fry egg", "Heat wok, add oil, cook eggs 20-30 sec, add rice on top", 600], ["T+00:24", "Stir-fry rice", "Toss rice and egg 2 min, breaking clumps, press to separate", 120], ["T+00:26", "Add veg & season", "Add vegetables, toss 2 min, lower heat, add mixed seasoning", 0], ["T+00:28", "Finish", "High heat, toss 2 min, add oil and spring onions, toss 1 min, serve", 300]], "steps": [["Cook and fluff rice", "Wash jasmine rice three times with fresh water, draining after each rinse. Add to rice cooker with 200g water and cook. Once done, let rice steam covered for 2 additional minutes. Then fluff thoroughly with chopsticks for 1-2 minutes to release steam and separate grains. Fresh rice works when properly fluffed\u2014day-old rice isn't mandatory.", "Washing removes excess starch that causes clumping; fluffing separates grains for even frying.", 1200], ["Prep ingredients", "While rice cooks, dice the green parts of spring onions and set aside (save the whites for another dish). Dice carrot into small pieces. In a bowl, combine frozen corn and peas. Add a splash of water and microwave for 2 minutes; drain well. Crack eggs into a bowl, add 1/4 teaspoon salt, and beat lightly.", "Pre-cooking vegetables ensures they're tender; microwaving is efficient; salting eggs seasons them evenly.", 180], ["Heat wok and cook egg", "Heat a wok or large skillet over high heat until very hot. Add oil and swirl to coat. Pour in beaten eggs and stir gently for 20-30 seconds until mostly set but still creamy. Immediately add the fluffed rice directly on top of the eggs\u2014don't stir yet.", "Cooking egg before rice prevents it from becoming scrambled bits; adding rice on top lets residual heat finish the egg gently.", 60], ["Stir-fry rice and egg", "Using a wok spatula, flip and stir-fry constantly for 2 minutes, breaking apart any clumps of rice and egg. Use the flat side of the spatula to press down on rice, helping separate grains. Scoop along the bottom edges of the wok, not the centre, to prevent sticking.", "Constant motion prevents sticking; pressing separates grains without mashing them.", 120], ["Add vegetables and season", "Add the cooked vegetables and increase heat to high. Stir-fry for 2-3 minutes until everything is well mixed and hot. Meanwhile, in a small bowl, combine light soy sauce, dark soy sauce, salt, sugar, chicken bouillon powder (if using), and water. Pour this seasoning mixture over the rice.", "Both soy sauces add colour and depth\u2014light for saltiness, dark for colour; sugar balances salt.", 300], ["Finish and serve", "Increase heat to high and stir-fry for 2-3 minutes until the seasoning is evenly distributed and the rice is hot and fragrant. Add the remaining oil and diced spring onions; toss for 1 minute. Turn off the heat. Taste and add more light soy sauce if needed (up to 1 teaspoon). Serve hot in a bowl or mounded on a plate.", "Final oil adds gloss and richness; spring onions add freshness at the end for bright contrast.", 300]], "pair": [["With fried rice", "Chinese lager or Tsingtao", "China \u00b7 crisp lager", "Light, crisp beer cleanses palate between bites"], ["Starter drink", "Ginger Ale", "China \u00b7 ginger \u00b7 sweet", "Sweet-spicy bubbles refresh, complement soy flavours"]]}, {"slug": "khao-soi", "t": "Khao Soi (Northern Thai Coconut Curry Noodles)", "tier": "exotic", "cui": "Thai \u00b7 Lanna (Chiang Mai)", "occ": ["solo", "date"], "time": "50 min", "method": "Stovetop \u00b7 simmer", "diff": "Medium", "blurb": "Chiang Mai's iconic curry noodle soup with tender chicken in rich coconut broth, topped with crispy noodles.", "prov": {"popular_in": "Northern Thailand (Chiang Mai, Lanna region)", "famous_for": "Signature dish of Chiang Mai; coconut curry broth with both soft and crispy egg noodles", "consists_of": "Egg noodles in coconut curry broth with chicken, topped with crispy fried noodles and condiments", "name_origin": "Thai words 'khao' (rice) and 'soi' (to cut/slice); evolved from 'Papa Soi' hand-sliced noodles introduced by Yunnanese Muslim traders", "why_loved": "Perfect balance of rich, creamy coconut curry with fresh, crunchy condiments and the irresistible contrast of soft and crispy noodles", "method_detail": "Stovetop \u2014 chicken simmered in coconut curry paste broth, served with both boiled and fried noodles"}, "brief": {"lead": "The iconic noodle soup of Northern Thailand, featuring tender chicken in a rich, aromatic coconut curry broth, served with the signature dual texture of soft boiled noodles and crispy fried noodles, finished with a vibrant array of fresh condiments.", "expect": [["Coconut Curry Broth", "Rich, creamy, and aromatic with curry paste, turmeric, and coconut milk - the soul of the dish."], ["Dual Noodle Texture", "Soft boiled egg noodles swimming in broth topped with crispy fried noodles for irresistible contrast."], ["Tender Chicken", "Falling-off-the-bone chicken thighs that absorb the curry flavours during simmering."], ["Fresh Condiments", "Crisp bean sprouts, shallots, spring onions, coriander, and pickled mustard greens to cut through the richness."]], "stats": [["20", "min", "Active"], ["30", "min", "Passive"], ["2", "", "Serves"], ["40", "min", "Total"]], "kit": ["Large pot", "Wok or deep pan (for frying noodles)", "Mortar and pestle (optional for paste)", "Sharp knife", "Cutting board", "Tongs"]}, "ing": [["For the Curry Broth", [["linear", 500, "ml", "coconut milk"], ["linear", 240, "ml", "water or chicken stock"], ["linear", 3, "tbsp", "red curry paste"], ["linear", 1, "tbsp", "curry powder"], ["linear", 1, "tsp", "ground turmeric"], ["linear", 2, "tbsp", "fish sauce"], ["linear", 1, "tbsp", "palm sugar or brown sugar"], ["countX", 2, "", "chicken leg quarters (bone-in, skin-on)"], ["countN", 4, "cloves", "garlic, minced"], ["countN", 2, "", "shallots, sliced"], ["linear", 2, "cm", "galangal, sliced"], ["countN", 2, "", "makrut lime leaves"]]], ["For the Noodles & Toppings", [["linear", 300, "g", "fresh egg noodles (or wheat noodles)"], ["linear", 100, "g", "rice vermicelli (optional, extra body)"], ["linear", 1, "litre", "oil (for frying noodles)"], ["linear", 80, "g", "bean sprouts"], ["countN", 2, "", "spring onions, chopped"], ["countN", 2, "", "shallots, fried until crisp"], ["linear", 20, "g", "pickled mustard greens, chopped"], ["linear", 15, "g", "coriander, chopped"]]], ["For the Curry Paste (if homemade)", [["linear", 2, "tbsp", "dried chillies, soaked"], ["countN", 5, "", "dried chillies, toasted"], ["countN", 2, "", "shallots"], ["countN", 4, "cloves", "garlic"], ["linear", 1, "tbsp", "coriander seeds, toasted"], ["linear", 0.5, "tsp", "cumin seeds"], ["linear", 1, "cm", "galangal"], ["linear", 1, "tbsp", "prawn paste"], ["static", "", "to taste", "salt"]]]], "tl": [["T+00:00", "Prep & Bloom Paste", "Heat coconut milk, bloom curry paste with aromatics", 0], ["T+10:00", "Simmer Chicken", "Add chicken and simmer 40 min until tender", 300], ["T+20:00", "Fry Noodles", "Fry portion of noodles until crispy (T+20)", 1], ["T+30:00", "Boil Noodles", "Cook remaining noodles; prep condiments", 1], ["T+50:00", "Assemble & Serve", "Compose bowls with broth, noodles, chicken, toppings", 0]], "steps": [["Bloom the Curry Paste", "In a large pot over medium heat, add the thick cream from the top of the coconut milk (about 3 tablespoons). Add the curry paste, curry powder, and turmeric. Fry for 2-3 minutes, stirring constantly, until the paste is fragrant and starts to separate from the oil - this releases the essential oils and intensifies the flavours.", "Blooming the spices in coconut fat unlocks their aromatic compounds, creating the rich base that defines the dish.", 120], ["Build the Broth", "Add the minced garlic, sliced shallots, galangal, and makrut lime leaves. Fry for 1 minute until fragrant. Pour in the remaining coconut milk and water or stock. Add fish sauce and palm sugar. Bring to a gentle simmer, stirring to dissolve the sugar.", "Building the broth in layers allows each aromatic to infuse properly before adding the chicken.", 60], ["Simmer the Chicken", "Add the chicken leg quarters to the simmering broth. Cover and cook gently for 40 minutes, or until the chicken is tender and falling off the bone. Skim any excess oil that rises to the surface if desired. Adjust seasoning with fish sauce or sugar to taste - it should be rich, savoury, and slightly sweet.", "Gentle simmering renders the collagen in the chicken, creating tender meat and enriching the broth without breaking the coconut milk.", 2400], ["Prepare the Noodles", "While the chicken simmers, separate the egg noodles into two portions. Boil one portion (2/3) according to package instructions until just tender - about 2-3 minutes. Drain and set aside. For the remaining portion (1/3), heat oil in a wok or deep pan to 180\u00b0C and fry the noodles until crispy and golden - about 1-2 minutes. Drain on paper towels.", "The dual texture of soft and crispy noodles is the signature of khao soi - the boiled noodles absorb the broth while the fried ones add crunch.", null], ["Assemble and Serve", "Place a portion of boiled noodles in each serving bowl. Ladle the hot broth over the noodles (about 1-1.1250 ml per bowl). Top with a piece of chicken. Garnish generously with crispy fried noodles, bean sprouts, spring onions, crispy shallots, pickled mustard greens, and coriander. Serve immediately with lime wedges and chilli oil on the side.", "Assembling table-side allows each diner to customise their bowl with fresh condiments that brighten and cut through the rich curry.", 0], ["Optional: Chilli Oil", "For an authentic touch, make a quick chilli oil by frying dried chilli flakes in oil until fragrant, then drizzle over the finished bowls. This adds both heat and visual appeal.", "Chilli oil provides an extra layer of heat and the vibrant red colour that's characteristic of street-style khao soi.", null]], "pair": [["With the Dish", "Singha Beer", "Thailand \u00b7 Light Lager", "Crisp and refreshing lager to cut through the rich coconut curry and cleanse the palate between bites."], ["Aperitif", "Tom Yum Soup Shot", "Thailand \u00b7 Sour Spicy Broth", "A small bowl of hot and sour tom yum to awaken the palate before the rich and creamy khao soi."]]}, {"slug": "massaman-curry", "t": "Massaman Curry (Thai-Muslim Curry)", "tier": "exotic", "cui": "Thai \u00b7 Southern/Muslim", "occ": ["date", "host"], "time": "80 min", "method": "Stovetop \u00b7 simmer", "diff": "Medium", "blurb": "Rich and aromatic Thai-Muslim curry with tender beef, potatoes, and peanuts in a creamy coconut sauce with warm spices.", "prov": {"popular_in": "Southern Thailand; also popular in Central Thailand and internationally", "famous_for": "Incorporating Persian/Indian spices like cardamom, cinnamon, and cloves; one of the mildest Thai curries with complex aromatic layers", "consists_of": "Beef or chicken simmered in coconut milk with potatoes, onions, and roasted peanuts, flavoured with Massaman curry paste and warm spices", "name_origin": "From 'Muslim', referring to the dish's origins among Thai Muslim traders with Persian influences; evolved from Malay-Indian curry traditions brought to Southern Thailand", "why_loved": "Gentle, approachable heat with deep, complex spices - cardamom's floral notes, cinnamon's warmth, and peanuts' nuttiness create sophisticated comfort food that appeals to all palates", "method_detail": "Stovetop \u2014 meat and vegetables slowly simmered in spiced coconut broth until tender and infused"}, "brief": {"lead": "A rich and aromatic curry that bridges Thai and Muslim culinary traditions, featuring tender beef chuck slowly simmered with potatoes in a luxurious coconut broth infused with warm Persian spices - cardamom, cinnamon, and cloves - and finished with roasted peanuts for a nutty, sophisticated finish.", "expect": [["Complex Spice Profile", "Cardamom's floral notes, cinnamon's warmth, and cloves' depth create layers of aromatic sophistication beyond typical Thai curries."], ["Tender Beef", "Chuck beef slowly melts into succulence during the 2-hour simmer, absorbing the spiced coconut broth."], ["Creamy Coconut Base", "Rich coconut milk tempered with spices creates a luxurious, velvety sauce that coats every ingredient."], ["Nutty Finish", "Roasted peanuts add a delightful crunch and nutty depth that balances the sweet and savoury elements."]], "stats": [["20", "min", "Active"], ["60", "min", "Passive"], ["4", "", "Serves"], ["80", "min", "Total"]], "kit": ["Large heavy-bottomed pot", "Sharp knife", "Cutting board", "Wooden spoon", "Measuring cups", "Can opener"]}, "ing": [["For the Curry", [["linear", 1, "kg", "beef chuck, cut into 4 cm chunks"], ["linear", 400, "ml", "coconut milk"], ["linear", 250, "ml", "beef stock or water"], ["linear", 5, "tbsp", "Massaman curry paste"], ["countX", 2, "", "large potatoes, cubed (4 cm)"], ["countX", 1, "", "large onion, quartered"], ["countN", 3, "tbsp", "fish sauce"], ["countN", 3, "tbsp", "palm sugar or brown sugar"], ["countN", 3, "tbsp", "tamarind paste or juice"], ["linear", 50, "g", "roasted peanuts"], ["static", "", "to taste", "flaky sea salt"]]], ["For the Spice Infusion (optional but authentic)", [["countN", 3, "", "cardamom pods, cracked"], ["countN", 2, "", "cinnamon sticks (5 cm each)"], ["countN", 4, "", "cloves"], ["countN", 2, "", "star anise (optional)"], ["linear", 1, "tsp", "cumin seeds"]]], ["For Serving", [["linear", 15, "g", "coriander, chopped"], ["countN", 2, "", "spring onions, sliced"], ["countN", 4, "", "red chillies, sliced"], ["static", "", "to serve", "steamed jasmine rice"]]]], "tl": [["T+00:00", "Prep & Bloom Paste", "Prep ingredients; bloom curry paste in coconut cream", 0], ["T+10:00", "Sear Beef", "Brown beef chunks in batches; add spices", 300], ["T+20:00", "Simmer Beef", "Add liquids; simmer beef 90 min until tender", 5400], ["T+60:00", "Add Vegetables", "Add potatoes and onions; cook 30 min more", 1800], ["T+80:00", "Finish & Serve", "Add peanuts, adjust seasoning, garnish, serve", 0]], "steps": [["Bloom the Curry Paste", "In a large heavy-bottomed pot over medium heat, scoop out the thick cream from the top of the coconut milk (about 3 tablespoons). Add the Massaman curry paste and fry for 2-3 minutes, stirring constantly, until the paste is fragrant and the oil starts to separate - this 'blooming' releases the paste's aromatic compounds.", "Cooking the paste in coconut fat intensifies the flavours and creates a rich base for the curry.", 120], ["Sear the Beef", "Increase the heat to medium-high. Add the beef chunks in batches (do not overcrowd the pot) and sear for 2-3 minutes per batch until browned on all sides. Remove the beef and set aside. If using whole spices, add them now and toast for 30 seconds until fragrant.", "Searing creates a flavourful crust (Maillard reaction) that adds depth to the broth; toasting spices releases their essential oils.", 180], ["Build the Curry Base", "Reduce heat to medium. Add the onion quarters to the pot and cook for 2-3 minutes until lightly coloured. Return the beef to the pot. Pour in the remaining coconut milk and stock. Add fish sauce, palm sugar, and tamarind paste. Stir to dissolve the sugar and bring to a gentle simmer.", "Onions provide sweetness and body; the liquid ratio creates a rich but not overly thick sauce.", 120], ["Slow Simmer the Beef", "Cover the pot with a lid slightly ajar. Maintain a gentle simmer for 90 minutes, or until the beef is tender and yielding. Check occasionally and skim any excess fat from the surface. The sauce should slowly thicken and deepen in colour.", "Long, slow cooking breaks down the connective tissue in the chuck, creating meltingly tender beef and a rich, collagen-infused sauce.", 5400], ["Add Potatoes and Finish", "Add the cubed potatoes to the pot. Simmer uncovered for 30 minutes, or until the potatoes are tender and the sauce has thickened nicely. Stir in the roasted peanuts (reserve some for garnish). Taste and adjust seasoning with fish sauce, sugar, or salt - it should be rich, slightly sweet, and savoury with gentle warmth.", "Potatoes absorb the spiced broth and add body; peanuts provide texture and nuttiness characteristic of Massaman.", 1800], ["Rest and Serve", "Remove from heat and let the curry rest for 5 minutes - this allows the flavours to meld and the sauce to settle. Serve over steamed jasmine rice, garnished with coriander, spring onions, sliced chillies, and reserved roasted peanuts.", "Resting time allows the flavours to harmonise and the sauce to reach the perfect consistency.", 0], ["Chef's Note", "For the most authentic flavour, make your own Massaman paste by blending dried chillies, lemongrass, galangal, garlic, shallots, coriander seeds, cumin, cardamom, cinnamon, cloves, and prawn paste. Store-bought paste works well for convenience.", "Homemade paste provides the freshest, most vibrant spice profile, but quality store-bought paste delivers excellent results.", null]], "pair": [["With the Dish", "Riesling (Off-Dry)", "Germany \u00b7 Aromatic White", "Off-dry Riesling's acidity and slight sweetness balance the rich, spiced coconut sauce without overpowering the delicate aromatics."], ["Aperitif", "Thai Iced Tea", "Thailand \u00b7 Sweet Creamy Tea", "Cool, creamy, and sweet - the perfect foil to Massaman's warm spices and rich coconut base."]]}, {"slug": "pho-bo", "t": "Ph\u1edf B\u00f2 (Vietnamese Beef Noodle Soup)", "tier": "exotic", "cui": "Vietnamese", "occ": ["solo", "date"], "time": "180 min", "method": "Stovetop \u00b7 long simmer", "diff": "Medium", "blurb": "Vietnam's iconic fragrant beef noodle soup with crystal-clear broth, rice noodles, and tender beef slices.", "prov": {"popular_in": "Vietnam (northern and southern regions); globally popular Vietnamese diaspora dish", "famous_for": "Crystal-clear, deeply aromatic beef broth infused with charred aromatics and warm spices; Vietnam's national dish", "consists_of": "Rice noodles in clear beef broth topped with various beef cuts, fresh herbs, bean sprouts, and condiments", "name_origin": "From the French 'pot-au-feu' (beef stew), adopted during French colonial period; adapted to Vietnamese tastes with local aromatics and noodles", "why_loved": "The depth of flavour from hours of simmering with charred aromatics, the comfort of hot noodles, and the ritual of customising each bowl with fresh herbs and condiments", "method_detail": "Stovetop \u2014 beef bones simmered 6+ hours with charred aromatics and spices; noodles cooked separately and assembled table-side"}, "brief": {"lead": "Vietnam's most iconic dish - a soulful, crystal-clear beef broth simmered for hours with charred onion and ginger, cinnamon, star anise, and cardamom, served over flat rice noodles with tender beef slices, and crowned with a vibrant garden of fresh herbs, bean sprouts, and chillies that each diner adds to taste.", "expect": [["Crystal-Clear Broth", "Deeply beefy yet pristine, infused with the sweet warmth of charred aromatics and the fragrant spice blend of star anise, cinnamon, and cardamom."], ["Multiple Beef Textures", "Rare brisket slices, well-done flank, and tender beef balls offer a range of textures and flavour concentrations."], ["Fresh Herb Garden", "Mint, coriander, Thai basil, and bean sprouts add bright, fresh contrasts to the rich, aromatic broth."], ["Custom Condiment Ritual", "Each diner customises their bowl with hoisin, chilli sauce, lime, and fresh herbs - part of the ph\u1edf experience."]], "stats": [["40", "min", "Active"], ["180", "min", "Passive"], ["4", "", "Serves"], ["220", "min", "Total"]], "kit": ["Very large stock pot (8+ litres)", "Cheesecloth or spice bag", "Sharp knife", "Cutting board", "Tongs", "Spider strainer", "Blowtorch or gas stove"]}, "ing": [["For the Broth", [["linear", 2, "kg", "beef bones (knuckle, femur, marrow-rich cuts)"], ["linear", 500, "g", "beef brisket (for broth and serving)"], ["linear", 300, "g", "beef flank or sirloin (for slicing)"], ["linear", 6, "litres", "water"], ["countX", 2, "", "large yellow onions, unpeeled"], ["countX", 2, "", "large pieces of ginger (10 cm each), unpeeled"], ["countN", 3, "", "star anise"], ["countN", 2, "", "cinnamon sticks (5 cm each)"], ["countN", 4, "", "cardamom pods, cracked"], ["countN", 1, "tsp", "coriander seeds, toasted"], ["countN", 1, "tsp", "fennel seeds, toasted"], ["countN", 1, "", "clove"], ["linear", 3, "tbsp", "fish sauce"], ["linear", 2, "tbsp", "rock sugar or palm sugar"], ["static", "", "to taste", "flaky sea salt"]]], ["For the Bowls", [["linear", 400, "g", "flat rice noodles (b\u00e1nh ph\u1edf)"], ["linear", 200, "g", "beef balls or beef tendon (optional)"], ["linear", 100, "g", "bean sprouts"], ["linear", 50, "g", "Thai basil"], ["linear", 30, "g", "coriander"], ["linear", 20, "g", "mint leaves"], ["countN", 4, "", "spring onions, white and green parts separated"], ["countN", 2, "", "yellow onions, thinly sliced"], ["countX", 2, "", "limes, cut into wedges"], ["static", "", "to serve", "chilli oil or fresh chillies"]]], ["For the Condiments", [["static", "", "to serve", "hoisin sauce"], ["static", "", "to serve", "sriracha or chilli garlic sauce"], ["static", "", "to taste", "black pepper"], ["static", "", "to taste", "vinegar (optional)"]]]], "tl": [["T+00:00", "Prep Bones & Vegetables", "Blanch bones; char aromatics over open flame", 0], ["T+20:00", "Start Broth", "Simmer bones with charred aromatics and spices", 0], ["T+40:00", "Long Simmer", "Maintain gentle simmer for 4-6 hours", 21600], ["T+180:00", "Strain & Season", "Strain broth; season with fish sauce and sugar", 0], ["T+200:00", "Prep Beef & Noodles", "Slice beef; cook noodles; prep herbs", 0], ["T+220:00", "Assemble & Serve", "Compose bowls; pour broth; add toppings", 0]], "steps": [["Prepare and Blanch Bones", "Rinse the beef bones thoroughly under cold water. In a large pot, bring water to a boil. Add the bones and blanch for 5 minutes - this removes impurities and blood. Drain and rinse the bones under cold water until the water runs clear. Clean the pot.", "Blanching removes blood and impurities that would cloud the broth, resulting in the crystal-clear ph\u1edf broth that defines the dish.", 300], ["Char the Aromatics", "Using a blowtorch, gas stove, or oven grill, char the unpeeled onions and ginger until blackened on the outside - about 10-15 minutes. This creates a sweet, smoky depth. Peel away the blackened layers (don't remove all the char).", "Charring caramelises the natural sugars in the aromatics, adding the distinctive sweet-smoky depth that defines authentic ph\u1edf broth.", 600], ["Start the Broth", "Place the blanched bones in a very large stock pot (minimum 8 litres). Add 6 litres of cold water. Bring to a boil, then reduce to a very gentle simmer. Skim any scum that rises to the surface for the first 30 minutes.", "Starting with cold water allows for maximum flavour extraction; constant skimming ensures a clear broth.", 1800], ["Add Aromatics and Spices", "Add the charred onions and ginger to the pot. Create a spice bundle with the star anise, cinnamon, cardamom, clove, coriander seeds, and fennel seeds (use cheesecloth or a spice bag). Add the spice bundle to the pot. Simmer gently, uncovered, for 4-6 hours. The broth should reduce by about one-third and develop a rich, amber colour.", "The spice bundle infuses the broth with warm aromatics without leaving gritty residue; long simmering extracts maximum flavour from the bones.", 21600], ["Season and Strain", "Remove the spice bundle. Add fish sauce and rock sugar. Simmer for another 30 minutes. Taste and adjust with salt if needed. Strain the broth through a fine-mesh sieve or cheesecloth into a clean container. Discard the solids. The broth can be refrigerated overnight and the fat skimmed from the surface for a lighter result.", "Fish sauce adds umami depth; sugar balances the saltiness; straining removes all solids for the pristine clear broth.", 1800], ["Prepare the Components", "Soak the rice noodles in hot water for 30 minutes, then drain. Slice the beef flank or sirloin as thinly as possible against the grain - partially freezing the beef for 20 minutes makes this easier. Slice the brisket into thin pieces. Prepare all herbs and condiments.", "Thin slices of beef cook quickly in the hot broth; presoaking noodles ensures they cook evenly in the broth.", 0], ["Assemble and Serve", "Bring the strained broth to a rolling boil. Blanch the noodles for 30 seconds in boiling water, then divide among serving bowls. Arrange the sliced beef, brisket, and onions on top of the noodles. Pour the boiling broth over the beef (it should cook to medium-rare from the heat). Garnish generously with herbs, bean sprouts, spring onion greens, and white pepper. Serve immediately with lime wedges, hoisin sauce, and chilli sauce on the side.", "Assembling table-side allows each diner to customise with fresh herbs and condiments - an essential part of the ph\u1edf experience.", 0], ["Chef's Note", "For the most authentic experience, serve the broth in a small pot at the table so diners can add more hot broth to their bowl as they eat. This keeps the noodles from getting soggy and ensures every bite is piping hot.", "This is how ph\u1edf is traditionally enjoyed in Vietnam, keeping the broth hot and the noodles perfectly textured throughout the meal.", null]], "pair": [["With the Dish", "Vietnamese Lager (333, Bia Saigon)", "Vietnam \u00b7 Light Lager", "Crisp, cold lager cuts through the rich broth and refreshes the palate between the aromatic, spicy sips."], ["Aperitif", "Vietnamese Iced Coffee (C\u00e0 Ph\u00ea S\u1eefa \u0110\u00e1)", "Vietnam \u00b7 Sweet Strong Coffee", "The perfect start - strong, sweet coffee contrasts beautifully with ph\u1edf's savoury warmth, bridging to the main course."]]}, {"slug": "moussaka", "t": "Moussaka (Greek Aubergine and Beef Casserole)", "tier": "exotic", "cui": "Greek \u00b7 Mediterranean", "occ": ["host", "date"], "time": "120 min", "method": "Oven \u00b7 layered casserole", "diff": "Medium", "blurb": "Iconic Greek casserole with layers of aubergine, rich beef mince, and creamy b\u00e9chamel topping.", "prov": {"popular_in": "Greece; throughout the Mediterranean and Greek diaspora communities", "famous_for": "Layers of fried aubergine and beef mince topped with a creamy b\u00e9chamel sauce; Greece's most beloved comfort food", "consists_of": "Layered casserole with fried aubergine, tomatoey beef mince sauce, and a creamy b\u00e9chamel custard topping, baked until golden", "name_origin": "From Arabic 'musaqqa'a' meaning 'chilled' or 'to moisten'; the modern Greek version was created in the 1920s by chef Nikolaos Tselementes", "why_loved": "The ultimate comfort food - rich, savoury, and satisfying with layers of contrasting textures from silky aubergine to hearty meat sauce to creamy topping", "method_detail": "Oven \u2014 aubergine fried, layered with meat sauce, topped with b\u00e9chamel, and baked until golden and bubbling"}, "brief": {"lead": "Greece's iconic layered casserole featuring silky fried aubergine, a rich tomatoey beef mince sauce fragrant with cinnamon and allspice, all crowned with a luxurious b\u00e9chamel custard topping that bakes to golden perfection - a dish of hearty comfort and sophisticated flavours that defines Greek home cooking.", "expect": [["Silky Fried Aubergine", "Fried until meltingly tender, the aubergine layers provide richness and a silky texture that contrasts beautifully with the meat sauce."], ["Fragrant Meat Sauce", "Beef mince simmered with tomatoes, onions, and warm spices like cinnamon and allspice - the savoury heart of the dish."], ["Creamy B\u00e9chamel Topping", "The luxurious crown - a creamy white sauce enriched with egg and cheese that bakes to a golden, velvety perfection."], ["Hearty Comfort", "Substantial, satisfying, and deeply savoury - the ultimate comfort food that's perfect for feeding a crowd."]], "stats": [["40", "min", "Active"], ["60", "min", "Passive"], ["4", "", "Serves"], ["100", "min", "Total"]], "kit": ["Large baking dish (30 x 20 cm)", "Large frying pan", "Medium saucepan", "Sharp knife", "Cutting board", "Whisk"]}, "ing": [["For the Aubergine", [["countX", 2, "", "large aubergines (about 1 kg total)"], ["linear", 200, "ml", "sunflower or canola oil (for frying)"], ["static", "", "to taste", "flaky sea salt"]]], ["For the Meat Sauce", [["linear", 600, "g", "beef mince"], ["countX", 2, "", "large onions, finely chopped"], ["countN", 4, "cloves", "garlic, minced"], ["linear", 400, "g", "tinned tomatoes, chopped"], ["linear", 2, "tbsp", "tomato pur\u00e9e"], ["linear", 100, "ml", "red wine (optional)"], ["countN", 1, "tsp", "ground cinnamon"], ["countN", 0.5, "tsp", "ground allspice"], ["linear", 2, "tbsp", "dried oregano"], ["static", "", "to taste", "flaky sea salt and black pepper"], ["linear", 60, "ml", "olive oil"]]], ["For the B\u00e9chamel Topping", [["linear", 80, "g", "butter"], ["linear", 80, "g", "cake flour"], ["linear", 1, "litre", "warm milk"], ["countN", 2, "", "eggs, beaten"], ["countN", 150, "g", "graviera or kefalotyri cheese, grated"], ["static", "", "to taste", "flaky sea salt", "white pepper"]]], ["For Assembly", [["linear", 50, "g", "parmesan cheese, grated"], ["linear", 1, "tsp", "dried oregano"]]]], "tl": [["T+00:00", "Prep Aubergine", "Slice and salt aubergine; fry until golden", 0], ["T+20:00", "Make Meat Sauce", "Saut\u00e9 vegetables and beef; add tomatoes and spices", 0], ["T+35:00", "Simmer Sauce", "Simmer meat sauce 30 min until thick", 1800], ["T+50:00", "Make B\u00e9chamel", "Prepare white sauce; enrich with eggs and cheese", 0], ["T+60:00", "Assemble Layers", "Layer aubergine, meat sauce, b\u00e9chamel", 0], ["T+70:00", "Bake", "Bake 45-60 min until golden and bubbling", 3600]], "steps": [["Prepare the Aubergine", "Slice the aubergines lengthwise into 1 cm thick slices. Sprinkle generously with salt and set aside for 30 minutes - this draws out bitterness and excess moisture. Pat the slices thoroughly dry with paper towels.", "Salting aubergine removes bitter compounds and prevents the slices from absorbing too much oil during frying.", 1800], ["Fry the Aubergine", "Heat oil in a large frying pan over medium-high heat (180\u00b0C). Fry the aubergine slices in batches until golden on both sides - about 2-3 minutes per side. Drain on paper towels and season lightly with salt.", "Frying creates a tender, silky texture and prevents the aubergine from becoming mushy during baking.", 600], ["Start the Meat Sauce", "In the same pan, heat 2 tablespoons of olive oil over medium heat. Add the chopped onions and cook for 8-10 minutes until softened and translucent. Add the minced garlic and cook for 1 minute until fragrant. Add the beef mince and cook, breaking it up, until browned all over.", "Building the sauce base properly creates depth of flavour; browning the beef adds savoury complexity.", 600], ["Simmer the Sauce", "Add the chopped tomatoes, tomato pur\u00e9e, red wine (if using), cinnamon, allspice, oregano, salt, and pepper. Stir well and simmer gently for 30 minutes, or until the sauce has thickened nicely. Taste and adjust seasoning - it should be rich and savoury with gentle warmth from the spices.", "Simmering develops the flavours and allows the sauce to thicken for better layering.", 1800], ["Make the B\u00e9chamel", "In a medium saucepan, melt the butter over medium heat. Add the flour and whisk for 1-2 minutes to cook out the raw flour taste. Gradually whisk in the warm milk, stirring constantly to prevent lumps. Simmer gently for 5-10 minutes until thickened. Remove from heat and whisk in the beaten eggs and grated cheese. Season with salt and white pepper.", "Cooking the flour (roux) prevents a raw taste; adding eggs off-heat prevents scrambling; cheese adds savoury depth.", 600], ["Assemble the Moussaka", "Preheat the oven to 180\u00b0C (160\u00b0C fan-assisted). Arrange a layer of aubergine slices in the bottom of a greased baking dish (30 x 20 cm). Spread half the meat sauce over the aubergine. Repeat with another layer of aubergine and the remaining meat sauce. Finish with a final layer of aubergine. Pour the b\u00e9chamel evenly over the top. Sprinkle with parmesan and oregano.", "Proper layering ensures every serving gets all components; the b\u00e9chamel topping creates the signature golden crown.", 0], ["Bake and Rest", "Bake for 45-60 minutes, or until the b\u00e9chamel is golden and bubbling, and the sides are pulling away from the dish. Remove from oven and let rest for 15-20 minutes before serving - this is crucial for clean slices.", "Resting allows the layers to set so the moussaka holds its shape when sliced.", 1200], ["Chef's Note", "For the most authentic flavour, don't omit the cinnamon and allspice - these warm spices are what distinguish Greek moussaka from other layered casseroles. Some versions also include a layer of sliced potatoes; par-boil them first before layering.", "The warm spices echo the dish's Ottoman past and create the distinctive Greek flavour profile.", null]], "pair": [["With the Dish", "Assyrtiko", "Greece \u00b7 Santorini \u00b7 Dry White", "Crisp, mineral-driven Greek white with high acidity cuts through the rich b\u00e9chamel and aubergine while complementing the spiced meat sauce."], ["Aperitif", "Greek Salad (Horiatiki)", "Greece \u00b7 Tomato Cucumber Salad", "Cool, crisp, and refreshing - the perfect balance to moussaka's richness with tangy feta, fresh vegetables, and olive oil."]]}, {"slug": "jollof-rice", "t": "Jollof Rice (West African Party Rice)", "tier": "exotic", "cui": "West African \u00b7 Senegambian", "occ": ["solo", "date", "host"], "time": "75 min", "method": "Stovetop \u00b7 one-pot", "diff": "Easy", "blurb": "West Africa's iconic party rice - smoky, savoury, and infused with tomatoes, peppers, and aromatic spices.", "prov": {"popular_in": "Nigeria, Ghana, Senegal, Gambia, and throughout West Africa; the subject of friendly 'Jollof Wars' between countries", "famous_for": "The beloved 'party rice' of West Africa; smoky, flavourful one-pot rice dish that's the centerpiece of celebrations and gatherings", "consists_of": "Long-grain rice cooked in a rich tomato, pepper, and onion stew with aromatic spices, creating distinctively flavourful grains", "name_origin": "From the Wolof people and Jolof Empire (14th-16th centuries) in present-day Senegal/Gambia; the dish spread from Saint Louis, Senegal across West Africa", "why_loved": "The perfect party dish - smoky, savoury, and deeply flavourful rice that feeds a crowd and brings people together; each region claims their version is best", "method_detail": "Stovetop one-pot \u2014 rice cooked in tomato-pepper base with 'party jollof' smoky flavour from burnt tomato residue"}, "brief": {"lead": "West Africa's most celebrated dish - a fragrant, smoky one-pot rice where long-grain grains are cooked to perfection in a rich tomato, pepper, and onion stew infused with curry, thyme, and bay leaves, creating the signature 'party jollof' flavour that's the centerpiece of celebrations across Nigeria, Ghana, and beyond.", "expect": [["Smoky Party Jollof Flavour", "The coveted smoky depth that comes from the 'burnt tomato' technique - the essence of authentic party jollof."], ["Flavourful Grains", "Each grain absorbs the tomato-pepper base and spices, creating rice that's fragrant and savoury in every bite."], ["Versatile Crowd-Pleaser", "Perfect for feeding a crowd - equally beloved for solo dinners, date nights, and large celebrations."], ["Regional Variations", "Nigerian (smokier, more intense), Ghanaian (more tomato-forward), Senegalese (includes fish) - each region proudly claims superiority."]], "stats": [["25", "min", "Active"], ["50", "min", "Passive"], ["4", "", "Serves"], ["75", "min", "Total"]], "kit": ["Large heavy-bottomed pot", "Blender or food processor", "Sharp knife", "Cutting board", "Wooden spoon", "Measuring cups"]}, "ing": [["For the Jollof Base", [["linear", 500, "g", "long-grain rice (parboiled or basmati)"], ["countX", 6, "", "Roma/plum tomatoes"], ["countX", 2, "", "red capsicums (or mixed peppers)"], ["countX", 2, "", "red onions (1 for base, 1 for garnish)"], ["countX", 2, "", "Scotch bonnet or habanero peppers (adjust to heat preference)"], ["linear", 100, "ml", "tomato pur\u00e9e"], ["linear", 80, "ml", "sunflower or canola oil"], ["linear", 500, "ml", "beef or chicken stock"], ["countN", 2, "tbsp", "curry powder"], ["countN", 1, "tbsp", "dried thyme"], ["countN", 2, "", "bay leaves"], ["countN", 1, "tsp", "ginger, grated"], ["countN", 2, "cloves", "garlic, minced"], ["static", "", "to taste", "flaky sea salt"], ["static", "", "to taste", "stock cube or bouillon (optional)"]]], ["For Garnish", [["linear", 30, "g", "spring onions, chopped"], ["linear", 20, "g", "coriander or parsley, chopped"], ["countX", 2, "", "fresh tomatoes, sliced"], ["static", "", "to serve", "grilled chicken, beef, or fried plantains (optional)"]]]], "tl": [["T+00:00", "Blend Base", "Blend tomatoes, peppers, onions for smooth base", 0], ["T+10:00", "Create Party Jollof Smoky Base", "Fry blended base until oil separates and slightly burns", 0], ["T+20:00", "Add Spices & Rice", "Add spices, stock, rice; stir to combine", 0], ["T+25:00", "Steam Rice", "Cover and steam rice 25 min on low heat", 1500], ["T+50:00", "Rest & Fluff", "Rest 10 min; fluff rice; garnish and serve", 0]], "steps": [["Prepare the Jollof Base", "Blend the tomatoes, peppers (remove seeds for less heat), and 1 onion until smooth. Set aside. Rinse the rice thoroughly until the water runs clear - this removes excess starch for separate grains. Soak the rice in hot water for 10 minutes, then drain.", "A smooth blended base creates the silky texture that coats each grain evenly; rinsing rice prevents gummy results.", 600], ["Create the Party Jollof Smoky Base", "In a large heavy-bottomed pot, heat the oil over medium heat. Add the blended tomato-pepper base and tomato pur\u00e9e. Fry for 15-20 minutes, stirring frequently, until the mixture has reduced significantly, the oil has separated, and you see slight browning/caramelisation at the edges - this 'burnt' effect creates the signature smoky party jollof flavour.", "This reduction and caramelisation is the secret to the coveted smoky depth that distinguishes authentic jollof from plain rice.", 1200], ["Add Spices and Build Flavour", "Add the curry powder, thyme, bay leaves, grated ginger, garlic, and crumbled stock cube (if using). Stir for 1 minute until fragrant. Add the remaining chopped onion and cook for 2 minutes until softened.", "Blooming the spices in the hot base releases their aromatic compounds and creates the complex flavour profile.", 180], ["Add Rice and Liquid", "Add the drained rice to the pot. Stir gently to coat every grain with the flavoured base - this is crucial for even colouring. Pour in the stock. Taste and add salt as needed. The liquid should be about 2 cm above the rice level.", "Coating the rice ensures every grain absorbs the flavours; proper liquid ratio prevents mushy or undercooked rice.", 60], ["Steam the Rice", "Increase the heat to high and bring to a boil. Once boiling, reduce heat to the lowest setting, cover tightly with a lid, and steam for 25 minutes. Do not lift the lid - trapping the steam ensures even cooking.", "The steaming method allows the rice to absorb the flavoured liquid gradually, creating separate, flavourful grains.", 1500], ["Rest and Fluff", "Remove from heat and let rest, covered, for 10 minutes. This allows the moisture to redistribute evenly. Uncover and fluff gently with a fork. Taste and adjust salt if needed. Garnish with spring onions, coriander/parsley, and fresh tomato slices.", "Resting time ensures even moisture distribution; gentle fluffing separates the grains without breaking them.", 600], ["Serve and Celebrate", "Jollof rice is traditionally served as the centerpiece at parties and celebrations. Accompany with grilled chicken, beef, fried plantains, or a simple salad. The 'Jollof Wars' between Nigeria and Ghana are legendary - each country claims their version is superior. Try both and decide your favourite!", "Jollof is more than a dish - it's a cultural icon that brings people together and sparks friendly rivalries across West Africa.", 0], ["Chef's Note", "For the most authentic party jollof flavour, some cooks deliberately let the tomato base catch slightly at the bottom of the pot (being careful not to burn it). This 'burnt tomato' technique is what creates the distinctive smoky flavour. Another trick: add a piece of smoked fish or beef to the pot for extra depth.", "These techniques are the secrets that distinguish home-cooked jollof from restaurant versions and create the beloved party flavour.", null]], "pair": [["With the Dish", "Star Lager or Gulder", "Nigeria \u00b7 Lager", "Cold, crisp Nigerian lager perfectly balances jollof's rich, smoky flavours and refreshes the palate at celebrations."], ["Aperitif", "Suya (Spicy Beef Skewers)", "Nigeria \u00b7 Spicy Grilled Beef", "The classic starter - spicy, smoky beef skewers with groundnut spice coating that pairs perfectly with jollof rice."]]}, {"slug": "mapo-tofu", "t": "Mapo Tofu (Sichuan Numbing Spicy Tofu)", "tier": "exotic", "cui": "Chinese \u00b7 Sichuan", "occ": ["solo", "date"], "time": "30 min", "method": "Stovetop \u00b7 stir-fry and braise", "diff": "Easy", "blurb": "Sichuan's iconic numbing-spicy tofu dish with silky tofu in a fiery, aromatic chilli bean sauce.", "prov": {"popular_in": "Sichuan Province, China; globally popular as a symbol of Sichuan cuisine", "famous_for": "The 'mala' (numbing-spicy) flavour profile from Sichuan peppercorns and chillies; China's fiery global ambassador", "consists_of": "Silken tofu and minced pork/beef in a rich sauce flavoured with doubanjiang (broad bean chilli paste) and Sichuan peppercorns", "name_origin": "Named after 'Mapo' ('pockmarked old woman'), Chen Senfu, who created the dish at her Chengdu restaurant in the 1860s-1870s Qing Dynasty", "why_loved": "The addictive interplay of silky tofu, fiery heat, and numbing Sichuan peppercorns creates an unforgettable flavour experience", "method_detail": "Stovetop \u2014 doubanjiang and aromatics bloomed in oil, then tofu braised in chilli-bean sauce until infused"}, "brief": {"lead": "Sichuan's most famous export - a fiery, numbing bowl of silken tofu swimming in a rich, aromatic sauce flavoured with the holy trinity of Sichuan cooking: doubanjiang (fermented broad bean chilli paste) for depth, Sichuan peppercorns for signature numbing heat, and fresh chillies for fire - a dish that perfectly embodies the 'mala' (numbing-spicy) sensation that defines Sichuan cuisine.", "expect": [["Signature 'Mala' Sensation", "The addictive combination of Sichuan peppercorn's numbing buzz and chilli's fiery heat - the essence of Sichuan cuisine."], ["Silky Tofu Texture", "Tender silken tofu that absorbs the rich sauce while maintaining its delicate, custard-like texture."], ["Complex Umami Depth", "Doubanjiang (fermented broad bean paste) provides deep, fermented umami that can't be replicated with fresh ingredients alone."], ["Comforting Heat", "A warming, comforting dish that's both fiery and soothing - perfect for cold weather or when you need a flavour wake-up."]], "stats": [["15", "min", "Active"], ["15", "min", "Passive"], ["2", "", "Serves"], ["30", "min", "Total"]], "kit": ["Wok or deep frying pan", "Sharp knife", "Cutting board", "Spatula", "Small bowls for prep", "Ladle"]}, "ing": [["For the Mapo Tofu", [["linear", 400, "g", "soft/silken tofu"], ["linear", 150, "g", "beef or pork mince"], ["linear", 3, "tbsp", "doubanjiang (fermented broad bean chilli paste)"], ["countN", 2, "tsp", "Sichuan peppercorns, toasted and ground"], ["countN", 2, "", "dried chillies, whole (optional)"], ["countN", 2, "cloves", "garlic, minced"], ["countN", 1, "cm", "ginger, minced"], ["countX", 1, "", "spring onion, white and green parts separated"], ["linear", 250, "ml", "chicken stock or water"], ["countN", 1, "tsp", "cornflour mixed with 2 tbsp water"], ["countN", 2, "tsp", "light soy sauce"], ["linear", 1, "tsp", "Shaoxing rice wine (optional)"], ["static", "", "to taste", "flaky sea salt"], ["linear", 2, "tbsp", "vegetable oil"]]], ["For Serving", [["linear", 15, "g", "coriander, chopped"], ["linear", 1, "tbsp", "Sichuan peppercorn powder (for finishing)"], ["static", "", "to taste", "chilli oil"], ["static", "", "to serve", "steamed jasmine rice"]]]], "tl": [["T+00:00", "Prep Tofu", "Cut tofu into cubes; set aside", 0], ["T+05:00", "Bloom Aromatics", "Fry doubanjiang, garlic, ginger until fragrant", 0], ["T+08:00", "Brown Meat", "Add mince; brown and break up", 0], ["T+12:00", "Add Stock & Tofu", "Add liquid and tofu; simmer gently", 0], ["T+20:00", "Thicken & Season", "Add cornflour slurry; season with soy sauce", 0], ["T+25:00", "Finish & Serve", "Garnish with spring onions, coriander, peppercorns", 0]], "steps": [["Prepare the Tofu", "Cut the silken tofu into 2 cm cubes. Gently place the cubes in a bowl of warm, salted water for 5 minutes - this firms the tofu slightly and removes excess moisture. Drain carefully and set aside.", "Salting water firms the tofu so it holds its shape during cooking while remaining silky inside.", 300], ["Toast Sichuan Peppercorns", "In a dry pan over medium heat, toast the Sichuan peppercorns for 1-2 minutes until fragrant (be careful not to burn). Grind to a fine powder. Set aside.", "Toasting releases the citrusy, numbing aromatic compounds in the peppercorns, intensifying the flavour.", 120], ["Bloom the Aromatics", "Heat the oil in a wok or deep frying pan over medium heat. Add the doubanjiang and fry for 1-2 minutes, stirring constantly, until the oil turns red and the paste is fragrant - this 'blooming' releases the paste's flavours. Add the garlic, ginger, and spring onion whites. Fry for 30 seconds until fragrant.", "Blooming the doubanjiang is crucial - it transforms the paste into a rich, aromatic base for the dish.", 90], ["Brown the Meat", "Add the minced meat to the wok. Break it up and fry for 3-4 minutes until browned and cooked through. If using dried whole chillies, add them now.", "Browning the meat adds flavour and texture; the rendered fat carries the aromatic flavours through the dish.", 240], ["Add Stock and Simmer", "Pour in the chicken stock or water. Add the Shaoxing wine if using. Bring to a gentle simmer. Gently slide the tofu cubes into the sauce - try not to break them. Simmer for 5 minutes, very gently stirring once or twice to coat the tofu in the sauce.", "Gentle simmering allows the tofu to absorb the flavours while maintaining its delicate texture.", 300], ["Thicken and Season", "Give the cornflour slurry a stir and add it to the wok. Gently stir for 30 seconds until the sauce thickens slightly and coats the back of a spoon. Add the soy sauce and half the ground Sichuan peppercorns. Taste and adjust with salt if needed.", "The slight thickening creates a velvety sauce that clings to the tofu; soy sauce adds umami depth.", 60], ["Finish and Serve", "Remove from heat. Transfer to a serving bowl. Garnish generously with spring onion greens, coriander, and the remaining ground Sichuan peppercorns. Drizzle with chilli oil if desired. Serve immediately with steamed jasmine rice.", "Garnishing at the end preserves the fresh aromatics and vibrant colour; the finishing Sichuan pepper kick intensifies the numbing sensation.", 0], ["Chef's Note", "For the most authentic flavour, use Pixian doubanjiang from Sichuan - it has a depth of flavour that can't be matched by other brands. The ratio of tofu to meat in authentic mapo tofu is about 10:1 - the meat is there for flavour, not bulk. This dish should be fiery and numbing - adjust the doubanjiang and Sichuan pepper to your heat tolerance.", "Quality doubanjiang and proper ratios are what distinguish restaurant-quality mapo tofu from home versions.", null]], "pair": [["With the Dish", "Tsingtao Beer", "China \u00b7 Lager", "Cold, crisp lager provides refreshing relief from mapo tofu's fiery heat while complementing the savoury flavours."], ["Aperitif", "Hot and Sour Soup", "China \u00b7 Sichuan Sour Soup", "A bowl of hot and sour soup awakens the palate with its contrasting tangy heat, preparing it for mapo's numbing fire."]]}, {"slug": "som-tum", "t": "S\u00f6m T\u00fcm (Thai Green Papaya Salad)", "tier": "exotic", "cui": "Thai \u00b7 Isan (Northeastern)", "occ": ["solo"], "time": "15 min", "method": "Pounding \u00b7 mortar and pestle", "diff": "Easy", "blurb": "Thailand's beloved spicy-sour-sweet salad of shredded green papaya pounded with chillies, garlic, lime, and fish sauce.", "prov": {"popular_in": "Thailand (especially Isan/Northeastern region); also Laos where it's called 'tam mak hoong'", "famous_for": "Thailand's national salad - the perfect balance of sour, sweet, salty, and spicy flavours; beloved street food and everyday staple", "consists_of": "Shredded unripe green papaya pounded with garlic, chillies, fish sauce, lime juice, palm sugar, and topped with peanuts, dried prawn, and tomatoes", "name_origin": "From 'som' (sour) and 'tum' (pounded) in Thai/Isan; the dish originated in Laos/Isan and spread throughout Thailand", "why_loved": "The addictive interplay of textures and flavours - crunchy papaya, salty-sour-sweet-savoury dressing, and the heat of fresh chillies creates a perfectly balanced, refreshing dish", "method_detail": "Mortar and pestle pounding \u2014 aromatics and dressing ingredients pounded together, then papaya added and gently pounded to absorb flavours"}, "brief": {"lead": "The quintessential taste of Isan - a vibrant, refreshing salad where shredded unripe green papaya is gently pounded in a mortar with garlic, bird's eye chillies, fish sauce, lime juice, and palm sugar until it absorbs the perfect balance of sour, sweet, salty, and spicy, then topped with roasted peanuts, dried prawn, crisp beans, and juicy tomatoes for a dish that's at once fiery, refreshing, and impossible to stop eating.", "expect": [["Perfect Four-Balance", "The harmonious interplay of sour (lime), sweet (palm sugar), salty (fish sauce), and spicy (fresh chillies) - the essence of Thai cuisine."], ["Crunchy Papaya Texture", "Shredded green papaya provides a crisp, fresh crunch that's the perfect canvas for the bold dressing."], ["Pounded Infusion", "The mortar and pestle technique forces the flavours into the papaya, creating deeper flavour integration than tossing alone."], ["Customisable Heat", "Adjust the chillies to your preference - from gentle warmth to fiery Isan-style heat that makes you sweat."]], "stats": [["15", "min", "Active"], ["0", "min", "Passive"], ["2", "", "Serves"], ["15", "min", "Total"]], "kit": ["Large granite mortar and pestle (essential)", "Sharp knife", "Cutting board", "Vegetable peeler", "Julienne peeler or sharp knife"]}, "ing": [["For the Som Tum", [["linear", 300, "g", "green unripe papaya, shredded"], ["countN", 4, "", "garlic cloves, peeled"], ["countX", 4, "", "bird's eye chillies (adjust to heat preference)"], ["countN", 3, "tbsp", "fish sauce"], ["countN", 2, "tbsp", "lime juice (about 2 limes)"], ["countN", 1, "tbsp", "palm sugar or tamarind paste"], ["linear", 50, "g", "roasted peanuts"], ["linear", 30, "g", "dried prawn (optional)"], ["countN", 4, "", "long beans or green beans, cut into 5 cm pieces"], ["countX", 2, "", "tomatoes, quartered or cherry tomatoes"], ["countX", 1, "", "small lime, wedged (for serving)"], ["static", "", "to taste", "flaky sea salt"]]], ["Optional Add-ins (Regional Variations)", [["linear", 50, "g", "pickled garlic or shallots"], ["linear", 30, "g", "salted egg (Thai-style)"], ["linear", 2, "tbsp", "fermented fish sauce (pla ra) - for authentic Isan flavour"], ["linear", 50, "g", "crab or dried prawn"]]]], "tl": [["T+00:00", "Prep Papaya", "Peel and shred papaya; set aside", 0], ["T+05:00", "Pound Dressing", "Pound garlic, chillies, sugar, fish sauce, lime", 0], ["T+08:00", "Add Papaya", "Add papaya and beans; pound gently", 0], ["T+12:00", "Fold In Toppings", "Gently fold in tomatoes, peanuts, dried prawn", 0], ["T+15:00", "Taste & Serve", "Adjust seasoning; serve with sticky rice", 0]], "steps": [["Prepare the Green Papaya", "Peel the green papaya. Using a julienne peeler, sharp knife, or traditional Thai shredder, shred the papaya into long, thin strips. Place in a large bowl of cold water with a pinch of salt for 5 minutes - this crisps the papaya. Drain thoroughly.", "Soaking in salted water firms and crisps the papaya, creating the signature crunch.", 300], ["Pound the Aromatics", "In a large granite mortar, add the garlic and bird's eye chillies. Pound firmly with the pestle for 30 seconds until you have a coarse paste - you want some chilli pieces remaining for texture, not a smooth pur\u00e9e.", "Pounding releases the aromatic oils and creates a paste that distributes flavour evenly.", 30], ["Build the Dressing", "Add the palm sugar (or tamarind paste), fish sauce, and lime juice to the mortar. Pound for another 30 seconds until the sugar dissolves and the ingredients are well combined. Taste - adjust with more fish sauce, lime, or sugar to achieve the perfect balance of salty, sour, sweet, and spicy.", "Building the dressing in the mortar allows the flavours to meld and the sugar to dissolve properly.", 30], ["Add the Papaya and Beans", "Add the shredded papaya and long beans to the mortar. Using a large spoon or the pestle, gently pound and toss for 1-2 minutes. You're not trying to mash the papaya - you're gently bruising it to help it absorb the dressing while maintaining its crunch.", "Gentle pounding forces the flavours into the papaya without destroying the texture - this is the secret to authentic som tum.", 120], ["Fold in the Toppings", "Add the tomatoes and peanuts (and dried prawn if using). Gently fold everything together with a large spoon - do not pound at this stage. Taste and adjust seasoning if needed. The salad should be bright, balanced, and punchy.", "Folding preserves the texture of tomatoes and peanuts while evenly distributing them.", 30], ["Serve Immediately", "Transfer to a serving plate or bowl. Serve immediately with sticky rice and lime wedges on the side. Som tum is best enjoyed fresh - the flavours are brightest and the crunch is at its peak.", "Som tum doesn't keep well - the papaya loses crunch and the dressing dilutes. It's meant to be eaten immediately.", 0], ["Chef's Note", "For the most authentic Isan flavour, add a small amount of fermented fish sauce (pla ra) - it adds a funky depth that's characteristic of the region's cuisine. The traditional way to eat som tum is with sticky rice (khao neeo) - use your hands to form small balls of sticky rice and dip them into the dressing as you eat the salad.", "Pla ra is the secret ingredient that distinguishes Isan-style som tum from Central Thai versions; sticky rice is the traditional accompaniment.", null]], "pair": [["With the Dish", "Sticky Rice (Khao Neeo)", "Thailand \u00b7 Glutinous Rice", "The essential accompaniment - clumps of sticky rice are dipped into the dressing, balancing the heat and providing a satisfying, neutral canvas."], ["Aperitif", "Singha Beer", "Thailand \u00b7 Lager", "Cold, crisp lager provides refreshing relief from som tum's fiery chillies while complementing the salty-sour flavours."]]}, {"slug": "beef-bulgogi", "t": "Beef Bulgogi (Korean Marinated BBQ Beef)", "tier": "exotic", "cui": "Korean", "occ": ["date"], "time": "40 min plus marinating", "method": "Grill or pan-fry", "diff": "Easy", "blurb": "Korea's most famous export - tender, sweet-savoury marinated beef grilled to smoky perfection.", "prov": {"popular_in": "Korea; globally popular as Korea's representative dish", "famous_for": "Korea's most celebrated dish - thinly sliced beef marinated in sweet-savoury sauce and grilled to tender perfection", "consists_of": "Thinly sliced beef (typically ribeye or sirloin) marinated in soy sauce, sugar, Asian pear, garlic, sesame oil, then grilled", "name_origin": "From 'bul' (fire) and 'gogi' (meat) in Korean; evolved from 'maekjeok' (skewered meat) from the Goguryeo Dynasty (37 BCE-668 CE)", "why_loved": "The perfect balance of sweet, savoury, and smoky flavours with impossibly tender meat that melts in your mouth", "method_detail": "Grill or pan-fry \u2014 marinated beef quickly grilled over high heat or pan-seared until caramelised and slightly charred"}, "brief": {"lead": "Korea's beloved barbecue dish - paper-thin slices of premium beef, traditionally ribeye, marinated for hours in a sweet-savoury blend of soy sauce, Asian pear (the secret tenderiser), garlic, sesame oil, and aromatics, then grilled over high heat until caramelised with gorgeous char-grilled edges, resulting in meat that's impossibly tender, juicy, and packed with the flavours that have made Korean BBQ famous worldwide.", "expect": [["Melt-in-Your-Mouth Tenderness", "Thinly sliced beef and the enzymatic tenderising from Asian pear create meat that's impossibly tender and juicy."], ["Sweet-Savoury Marinade", "The perfect balance of soy sauce's savouriness, fruit's sweetness, garlic's pungency, and sesame oil's nuttiness."], ["Caramelised Char", "High-heat grilling creates gorgeous char-grilled edges with caramelised flavour - the essence of Korean BBQ."], ["Interactive Dining", "Grill table-side (if possible) and wrap in lettuce with ssamjang, garlic, and kimchi - the full Korean BBQ experience."]], "stats": [["20", "min", "Active"], ["120", "min", "Marinating"], ["2", "", "Serves"], ["140", "min", "Total (plus marinating)"]], "kit": ["Grill (gas or charcoal) or heavy frying pan", "Sharp knife", "Cutting board", "Tongs", "Marinating dish or zip-lock bag"]}, "ing": [["For the Bulgogi", [["linear", 500, "g", "beef ribeye or sirloin, sliced paper-thin (partially freeze for easier slicing)"], ["linear", 0.5, "", "Asian pear (about 150g), grated or pur\u00e9ed"], ["countN", 4, "cloves", "garlic, minced"], ["countX", 1, "", "small onion, grated or pur\u00e9ed"], ["linear", 4, "tbsp", "soy sauce"], ["countN", 2, "tbsp", "sugar or honey"], ["countN", 2, "tbsp", " sesame oil"], ["countN", 1, "tbsp", "rice vinegar (optional)"], ["countN", 1, "tsp", "ground black pepper"], ["countX", 1, "", "spring onion, chopped"], ["linear", 1, "tsp", " toasted sesame seeds (for garnish)"], ["static", "", "to taste", "flaky sea salt"]]], ["For Serving (Korean BBQ Style)", [["static", "", "to serve", "red leaf lettuce or perilla leaves"], ["static", "", "to serve", "ssamjang (chilli bean paste)"], ["static", "", "to serve", "kimchi"], ["static", "", "to serve", "garlic cloves, grilled"], ["static", "", "to serve", "green chilli peppers, sliced"]]]], "tl": [["T-120:00", "Marinate Beef", "Combine beef with marinade; refrigerate 2 hours minimum", 0], ["T+00:00", "Prep Grill", "Heat grill or pan to high; oil grates", 0], ["T+05:00", "Grill Bulgogi", "Cook beef 1-2 min per side until charred", 0], ["T+15:00", "Rest & Serve", "Rest 5 min; serve with lettuce wraps", 0]], "steps": [["Prepare the Beef", "Partially freeze the beef for 20-30 minutes - this makes it easier to slice thinly. Slice the beef against the grain into paper-thin slices (2-3 mm). If you can't slice thinly enough, ask your butcher to slice it for you.", "Thin slices cook quickly and evenly, creating the tender texture that defines bulgogi.", 1200], ["Make the Marinade", "In a bowl or zip-lock bag, combine the grated Asian pear, minced garlic, grated onion, soy sauce, sugar or honey, sesame oil, rice vinegar (if using), and black pepper. Mix well until the sugar dissolves.", "The Asian pear contains enzymes that tenderise the meat while adding natural sweetness - it's the secret to authentic bulgogi.", 60], ["Marinate the Beef", "Add the beef slices to the marinade. Massage gently to coat every piece. Cover and refrigerate for at least 2 hours, preferably overnight - the longer the marinating time, the more tender and flavourful the beef. For best results, turn the meat halfway through.", "Long marinating allows the flavours to penetrate deeply and the pear enzymes to work their magic on the meat.", 7200], ["Prepare the Grill", "Heat a grill (gas or charcoal) or a heavy cast-iron frying pan to high heat. Lightly oil the grates or pan. The cooking surface should be very hot - this creates the signature char-grilled flavour and caramelisation.", "High heat is essential for quick cooking that develops char-grilled flavour without overcooking the meat.", 60], ["Grill the Bulgogi", "Remove the beef from the marinade, letting excess drip off (don't pat dry - the marinade creates caramelisation). Grill the beef in batches for 1-2 minutes per side, or until nicely charred and cooked through. Don't overcrowd the grill - this causes steaming instead of grilling.", "Quick high-heat cooking creates the char-grilled edges while keeping the interior juicy and tender.", 120], ["Rest and Serve", "Let the beef rest for 5 minutes on a platter. This allows the juices to redistribute. Sprinkle with sesame seeds and spring onion. Serve immediately with lettuce leaves, ssamjang, kimchi, grilled garlic, and green chillies for wrapping.", "Resting ensures juicy meat; wrapping in lettuce with condiments is the traditional Korean way to enjoy bulgogi.", 300], ["Korean BBQ Style Serving", "To eat, take a lettuce leaf, add a piece of bulgogi, a small amount of ssamjang, a slice of garlic, some kimchi, and a piece of green chilli. Wrap it up and enjoy in one bite. This combination of textures and flavours is the authentic Korean BBQ experience.", "The lettuce wrap provides freshness and crunch that balances the rich, savoury meat - this is how bulgogi is traditionally enjoyed.", 0], ["Chef's Note", "For the most authentic flavour, don't omit the Asian pear - it's the key tenderiser and flavour enhancer. If you can't find Asian pear, a very firm Bosc pear or a Granny Smith apple works as a substitute. The traditional way to slice the beef is to use a sharp knife while the meat is partially frozen - this creates the paper-thin slices that are essential for proper bulgogi.", "Proper slicing technique and the right fruit are what distinguish restaurant-quality bulgogi from home versions.", null]], "pair": [["With the Dish", "Soju", "Korea \u00b7 Distilled Spirit", "The traditional accompaniment to Korean BBQ - clean, neutral spirits that cleanse the palate between rich, savoury bites of bulgogi."], ["Aperitif", "Kimchi Pancakes (Kimchi Jeon)", "Korea \u00b7 Savoury Pancakes", "Crispy, savoury kimchi pancakes with their tangy heat make the perfect starter to whet the appetite for bulgogi's sweet-savoury richness."]]}];